INSERT INTO `accreditation_instrument` (`instrument_id`, `instrument_reference_code`, `instrument_order_id`, `instrument_name`, `instrument_objective`, `instrument_material`, `instrument_document`, `instrument_maximum_score`, `instrument_standard_id`, `instrument_chapter_id`, `instrument_class_id`, `instrument_version`, `instrument_institution_group_id`, `instrument_r`, `instrument_d`, `instrument_o`, `instrument_w`, `instrument_s`, `instrument_update`, `instrument_user_id`, `instrument_record_status`) VALUES
(4952, 'TKRS 1 EP.1', 1, 'Representasi pemilik/Dewan Pengawas dipilih dan ditetapkan oleh Pemilik.', '1', '', '', 10, 1263, 73, 0, 2025, 1, 'Regulasi tentang penetapan  representasi pemilik/Dewan Pengawas oleh Pemilik', NULL, NULL, NULL, NULL, '2025-06-30 13:38:47', 0, 'A'),
(4953, 'TKRS 1 EP.2', 2, 'Tanggung jawab dan wewenang representasi pemilik meliputi poin a) sampai h) dengan yang tertera di  dalam maksud dan tujuan serta dijelaskan di dalam peraturan internal rumah sakit.', '1', '', '', 10, 1263, 73, 0, 2025, 1, 'Regulasi tentang tanggung jawab dan wewenang representasi pemilik meliputi poin a) sampai dengan h)', NULL, NULL, NULL, NULL, '2025-06-30 14:30:48', 0, 'A'),
(4954, 'TKRS 1 EP.3', 3, 'Representasi pemilik/Dewan Pengawas di evaluasi oleh pemilik setiap tahun dan hasil evaluasinya didokumentasikan.', '1', '', '', 10, 1263, 73, 0, 2025, 1, NULL, 'Representasi pemilik/Dewan Pengawas dievaluasi oleh pemilik setiap tahun dan hasil evaluasinya didokumentasikan', NULL, 'Representasi pemilik', NULL, '0000-00-00 00:00:00', 0, 'A'),
(4955, 'TKRS 1 EP.4', 4, 'Representasi pemilik/Dewan Pengawas  menetapkan visi misi rumah sakit yang diarahkan oleh pemilik.', '1', '', '', 10, 1263, 73, 0, 2025, 1, 'Regulasi tentang penetapan visi misi rumah sakit', NULL, NULL, NULL, NULL, '0000-00-00 00:00:00', 0, 'A'),
(4956, 'TKRS 2 EP.1', 1, 'Telah menetapkan regulasi tentang  kualifikasi  Direktur, uraian tugas, tanggung jawab dan wewenang sesuai dengan persyaratan dan peraturan perundang- undangan yang berlaku.', '2', '', '', 10, 1264, 73, 0, 2025, 1, 'Regulasi tentang kualifikasi Direktur,  uraian tugas, tanggung jawab dan wewenang sesuai dengan persyaratan dan peraturan perundang-undangan yang berlaku.', NULL, NULL, NULL, NULL, '2025-06-30 14:34:03', 0, 'A'),
(4957, 'TKRS 2 EP.2', 2, 'Direktur menjalankan operasional rumah sakit sesuai tanggung jawabnya yang meliputi namun  tidak  terbatas pada poin a) sampai i) dengan dalam maksud dan tujuan yang dituangkan dalam uraian tugasnya.', '2', '', '', 10, 1264, 73, 0, 2025, 1, NULL, 'Bukti Direktur menjalankan operasional rumah sakit sesuai tanggung jawabnya yang meliputi namun tidak terbatas pada poin a) sampai dengan i) dalam maksud dan tujuan yang dituangkan dalam uraian tugasnya', NULL, 'Direktur RS', NULL, '2025-06-30 14:08:03', 0, 'A'),
(4958, 'TKRS 2 EP.3', 3, 'Memiliki bukti tertulis tanggung jawab Direktur telah dilaksanakan dan dievaluasi oleh pemilik/representasi pemilik setiap tahun dan hasil evaluasinya didokumentasikan.', '2', '', '', 10, 1264, 73, 0, 2025, 1, NULL, 'Bukti  penilaian kinerja Direktur oleh  pemilik/representasi pemilik setiap tahun', NULL, '•	Representasi pemilik\r\n•	Direktur', NULL, '0000-00-00 00:00:00', 0, 'A'),
(4959, 'TKRS 3 EP.1', 1, 'Direktur menunjuk pimpinan rumah sakit dan kepala unit sesuai kualifikasi dalam persyaratan jabatan yang telah ditetapkan beserta uraian tugasnya.', '3', '', '', 10, 1265, 73, 0, 2025, 1, 'Regulasi  penetapan pimpinan rumah sakit dan kepala unit sesuai kualifikasi dalam persyaratan jabatan yang telah ditetapkan beserta uraian tugasnya', NULL, NULL, NULL, NULL, '2025-06-30 14:25:40', 0, 'A'),
(4960, 'TKRS 3 EP.2', 2, 'Pimpinan rumah sakit bertanggung jawab untuk melaksanakan misi yang telah ditetapkan dan memastikan kebijakan serta prosedur dilaksanakan.', '3', '', '', 10, 1265, 73, 0, 2025, 1, NULL, 'Bukti pimpinan rumah sakit bertanggung jawab untuk melaksanakan misi yang telah ditetapkan dan memastikan regulasi RS dilaksanakan, berupa:\r\na)	Laporan bulanan dan tahunan\r\nb)	Supervisi kepatuhan staf terhadap regulasi RS', NULL, 'Para manajer RS', NULL, '2025-06-30 14:35:15', 0, 'A'),
(4961, 'TKRS 3 EP.3', 3, 'Pimpinan rumah sakit bersama dengan pimpinan unit merencanakan dan menentukan jenis pelayanan klinis untuk memenuhi kebutuhan pasien yang dilayani rumah sakit.', '3', '', '', 10, 1265, 73, 0, 2025, 1, NULL, 'Bukti rapat pimpinan    rumah    sakit    bersama    dengan    pimpinan    unit merencanakan jenis pelayanan dan menetapkan jenis pelayanan klinis  untuk memenuhi kebutuhan pasien yang dilayani rumah sakit  meliputi: undangan, materi rapat, absensi dan notulen', NULL, '•	Para manajer RS\r\n•	Kepala unit pelayanan', NULL, '2025-06-30 14:36:23', 0, 'A'),
(4962, 'TKRS 3 EP.4', 4, 'Rumah sakit memberikan informasi tentang pelayanan yang disediakan kepada tokoh masyarakat, para pemangku kepentingan, fasilitas pelayanan  kesehatan di sekitar rumah sakit, dan terdapat proses untuk menerima masukan bagi peningkatan pelayanannya.', '3', '', '', 10, 1265, 73, 0, 2025, 1, NULL, 'Bukti penyampaian   informasi   tentang  pelayanan  yang disediakan kepada  tokoh masyarakat, para pemangku kepentingan, fasilitas pelayanan kesehatan di sekitar rumah sakit, tentang pelayanan yang disediakan dan proses menerima masukan', NULL, 'Unit PKRS', NULL, '0000-00-00 00:00:00', 0, 'A'),
(4963, 'TKRS 3.1 EP.1', 1, 'Pimpinan rumah sakit memastikan bahwa terdapat proses untuk menyampaikan informasi dalam lingkungan rumah sakit secara akurat dan tepat waktu. ', '3.1', '', '', 10, 1266, 73, 0, 2025, 1, NULL, 'Bukti tentang proses untuk menyampaikan  informasi  dalam  lingkungan rumah  sakit  secara akurat dan tepat waktu sudah dilaksanakan  (dapat berupa buletin, media sosial, intra net, surat edaran, pengumuman, paging system, code system, dan lainnya)', NULL, 'Kepala unit kerja terkait', NULL, '2025-06-30 15:05:12', 0, 'A'),
(4964, 'TKRS 3.1 EP.2', 2, 'Pimpinan rumah sakit memastikan bahwa komunikasi yang efektif antara unit klinis dan nonklinis,  antara  PPA dengan manajemen, antar PPA dengan pasien dan keluarga serta antar staf telah dilaksanakan.', '3.1', '', '', 10, 1266, 73, 0, 2025, 1, NULL, 'Bukti telah terlaksana  komunikasi yang efektif antara unit klinis dan nonklinis, antara PPA dengan manajemen, antar PPA dengan pasien  dan  keluarga  serta  antar  staf, antara lain berupa:\r\n1)	Bukti  rapat di setiap unit klinis dan non klinis dan antar unit\r\n2)	Bukti rapat pertemuan PPA  beserta manajemen \r\n3)	Bukti pemberian informasi dan edukasi ke pasien dan keluarga \r\n4)	CPPT \r\n5)	Form serah terima \r\nBukti rapat  meliputi : undangan, materi rapat, absensi  dan notulen', NULL, '•	Para manajer RS\r\n•	Kepala unit kerja', NULL, '2025-07-01 08:19:13', 0, 'A'),
(4965, 'TKRS 3.1 EP.3', 3, 'Pimpinan rumah sakit telah mengkomunikasikan visi, misi, tujuan, rencana strategis dan kebijakan, rumah sakit kepada semua staf.', '3.1', '', '', 10, 1266, 73, 0, 2025, 1, NULL, 'Bukti rumah sakit telah mengkomunikasikan visi, misi, tujuan, rencana strategis dan kebijakan, rumah sakit kepada semua staf', NULL, 'Staf RS', NULL, '0000-00-00 00:00:00', 0, 'A'),
(4966, 'TKRS 4 EP.1', 1, 'Direktur dan Pimpinan rumah sakit berpartisipasi dalam merencanakan mengembangkan dan menerapkan program peningkatan mutu dan keselamatan pasien di lingkungan rumah sakit.', '4', '', '', 10, 1267, 73, 0, 2025, 1, NULL, 'Bukti  Direktur    dan    Pimpinan    rumah    sakit berpartisipasi dalam merencanakan   mengembangkan   dan   menerapkan   program peningkatan mutu dan keselamatan pasien di lingkungan rumah sakit, berupa:\r\n1)	Program PMKP yang telah ditetapkan oleh Direktur RS\r\n2)	Bukti laporan pelaksanaan  Program PMKP kepada pemilik/representasi pemilik', NULL, '•	Representasi pemilik\r\n•	Direktur RS', NULL, '2025-07-01 08:20:38', 0, 'A'),
(4967, 'TKRS 4 EP.2', 2, 'Pimpinan rumah sakit memilih dan  menetapkan  proses pengukuran, pengkajian data, rencana      perbaikan dan mempertahankan peningkatan  mutu dan keselamatan pasien di lingkungan rumah sakit', '4', '', '', 10, 1267, 73, 0, 2025, 1, NULL, 'Bukti rapat untuk memilih    dan    menetapkan    proses pengukuran, pengkajian data, rencana perbaikan dan mempertahankan peningkatan mutu dan keselamatan pasien meliputi: undangan, materi rapat, absensi dan notulen', NULL, '•	Direktur RS\r\n•	Para manajer', NULL, '2025-07-01 08:21:25', 0, 'A'),
(4968, 'TKRS 4 EP.3', 3, 'Pimpinan rumah sakit memastikan terlaksananya program PMKP termasuk memberikan dukungan teknologi dan sumber daya yang adekuat serta menyediakan pendidikan staf tentang peningkatan mutu dan keselamatan pasien di rumah sakit agar dapat berjalan secara efektif.', '4', '', '', 10, 1267, 73, 0, 2025, 1, NULL, '1)	Bukti pelaksanaan  program PMKP berupa Laporan Program PMKP\r\n2)	Bukti daftar inventaris hardware dan software/aplikasi  sistem manajemen data elektronik di RS, misalnya SIDOKAR\r\n3)	Bukti  pelatihan staf tentang peningkatan mutu dan keselamatan pasien (TOR, Materi, Presensi, Pre dan post test serta sertifikat)', NULL, 'Direktur RS', NULL, '2025-07-01 08:22:25', 0, 'A'),
(4969, 'TKRS 4 EP.4', 4, 'Pimpinan rumah sakit menetapkan mekanisme pemantauan dan koordinasi program peningkatan  mutu dan keselamatan pasien.', '4', '', '', 10, 1267, 73, 0, 2025, 1, 'Regulasi tentang mekanisme pemantauan dan koordinasi program peningkatan mutu dan keselamatan pasien.', NULL, NULL, NULL, NULL, '2025-07-01 08:22:46', 0, 'A'),
(4970, 'TKRS 5 EP.1', 1, 'Direktur dan pimpinan rumah sakit menggunakan data yang tersedia (data basedalam menetapkan indikator prioritas rumah sakit yang perbaikannya  akan  berdampak luas/menyeluruh meliputi poin a) sampai dengan f) dalam maksud dan tujuan.', '5', '', '', 10, 1268, 73, 0, 2025, 1, NULL, 'Bukti ada dokumen kajian  dalam menetapkan indikator prioritas rumah sakit yang meliputi a)- f)  yang dilengkapi dengan daftar peserta yang melakukan kajian dan data yang digunakan untuk melakukan kajian', NULL, '•	Direktur RS\r\n•	Para manajer RS', NULL, '2025-07-01 08:23:27', 0, 'A'),
(4971, 'TKRS 5 EP.2', 2, 'Dalam memilih prioritas perbaikan di  tingkat  rumah sakit maka Direktur dan pimpinan  mengggunakan kriteria prioritas meliputi poin  a) sampai dengan h) dalam  maksud dan tujuan.', '5', '', '', 10, 1268, 73, 0, 2025, 1, NULL, 'Bukti ada dokumen kajian dalam memilih prioritas perbaikan di tingkat rumah sakit dengan mengggunakan kriteria prioritas meliputi poin a)–h) yang dilengkapi dengan daftar peserta yang terlibat', NULL, '•	Direktur RS\r\n•	Para manajer RS', NULL, '0000-00-00 00:00:00', 0, 'A'),
(4972, 'TKRS 5 EP.3', 3, 'Direktur dan pimpinan rumah sakit mengkaji dampak perbaikan primer dan dampak perbaikan  sekunder pada indikator prioritas rumah sakit  yang  ditetapkan di tingkat rumah sakit maupun tingkat unit.', '5', '', '', 10, 1268, 73, 0, 2025, 1, NULL, 'Bukti ada dokumen kajian dampak perbaikan primer dan dampak perbaikan sekunder pada:\r\n•	indikator mutu prioritas rumah sakit\r\n•	indikator mutu prioritas unit', NULL, '•	Direktur RS\r\n•	Para manajer RS', NULL, '2025-07-01 08:24:40', 0, 'A'),
(4973, 'TKRS 6 EP.1', 1, 'Pimpinan rumah sakit bertanggung jawab terhadap kontrak untuk memenuhi kebutuhan pasien dan manajemen termasuk ruang  lingkup  pelayanan tersebut yang dicantumkan  dalam  persetujuan kontrak.', '6', '', '', 10, 1269, 73, 0, 2025, 1, 'Regulasi tentang kontrak klinis dan kontrak manajemen.', NULL, NULL, NULL, NULL, '2025-07-01 08:29:18', 0, 'A'),
(4974, 'TKRS 6 EP.2', 2, 'Tenaga kesehatan yang dikontrak perlu dilakukan kredensial sesuai ketentuan di rumah sakit.', '6', '', '', 10, 1269, 73, 0, 2025, 1, NULL, 'Bukti  kredensial tenaga kesehatan yang dikontrak, berupa:\r\n•	Proses kredensial\r\n•	Penetapan SPK dan RKK', NULL, 'Manajer SDM', NULL, '2025-07-01 08:30:09', 0, 'A'),
(4975, 'TKRS 6 EP.3', 3, 'Pimpinan rumah sakit menginspeksi kepatuhan  layanan kontrak sesuai kebutuhan', '6', '', '', 10, 1269, 73, 0, 2025, 1, NULL, 'Bukti pimpinan RS melakukan inspeksi/supervisi kepatuhan layanan kontrak', NULL, 'Para manajer RS', NULL, '0000-00-00 00:00:00', 0, 'A'),
(4976, 'TKRS 6 EP.4', 4, 'Apabila kontrak dinegosiasikan ulang atau dihentikan, rumah sakit tetap mempertahankan kelanjutan dari pelayanan pasien', '6', '', '', 10, 1269, 73, 0, 2025, 1, 'Regulasi kontrak pada EP 1 juga mengatur batas waktu pengajuan penghentian sepihak sebelum kontrak berakhir (misalnya  satu bulan sudah diajukan untuk penghentian sepihak)', NULL, NULL, NULL, NULL, '2025-07-01 08:31:17', 0, 'A'),
(4977, 'TKRS 6 EP.5', 5, 'Semua kontrak menetapkan data mutu yang harus dilaporkan kepada rumah sakit, disertai frekuensi dan mekanisme pelaporan, serta bagaimana rumah sakit akan merespons jika  persyaratan  atau  ekspektasi  mutu tidak terpenuhi.', '6', '', '', 10, 1269, 73, 0, 2025, 1, 'Penetapan dalam kontrak tentang:\r\n1)	Data mutu yang harus dilaporkan  disertai frekuensi dan mekanisme pelaporan\r\n2)	Respons RS jika persyaratan atau ekspektasi mutu tidak terpenuhi', NULL, NULL, NULL, NULL, '2025-07-01 08:32:06', 0, 'A'),
(4978, 'TKRS 6 EP.6', 6, 'Pimpinan klinis dan non klinis yang terkait layanan yang dikontrak melakukan analisis dan memantau informasi mutu yang dilaporkan pihak yang dikontrak yang merupakan bagian dalam program penigkatan mutu dan keselamatan pasien rumah sakit.', '6', '', '', 10, 1269, 73, 0, 2025, 1, NULL, 'Bukti pelaksanaan analisis  informasi mutu  layanan yang dikontrak oleh  Pimpinan klinis dan non klinis', NULL, 'Kepala unit kerja', NULL, '2025-07-01 08:40:33', 0, 'A'),
(4979, 'TKRS 7 EP.1', 1, 'Pimpinan rumah sakit menggunakan data dan  informasi mutu serta dampak terhadap keselamatan untuk membuat keputusan pembelian  dan  penggunaan peralatan baru.', '7', '', '', 10, 1270, 73, 0, 2025, 1, NULL, 'Bukti berupa dokumen kajian dari pimpinan rumah sakit dalam membuat keputusan pembelian dan penggunaan alat baru yang dilengkapi dengan data dan informasi mutu dan dampak terhadap keselamatan', NULL, '•	Direktur RS\r\n•	Para manajer RS', NULL, '2025-07-01 08:41:11', 0, 'A'),
(4980, 'TKRS 7 EP.2', 2, 'Pimpinan rumah sakit menggunakan data dan  informasi mutu serta dampak terhadap keselamatan dalam pemilihan, penambahan, pengurangan dan melakukan rotasi staf.', '7', '', '', 10, 1270, 73, 0, 2025, 1, NULL, 'Bukti berupa dokumen kajian dari Pimpinan rumah sakit  dalam pemilihan, penambahan, pengurangan dan melakukan rotasi staf yang dilengkapi dengan  data dan informasi mutu dan dampak terhadap keselamatan', NULL, '•	Direktur RS\r\n•	Para manajer RS', NULL, '2025-07-01 08:42:35', 0, 'A'),
(4981, 'TKRS 7 EP.3', 3, 'Pimpinan rumah sakit menggunakan rekomendasi dari organisasi profesional dan sumber berwenang lainnya dalam mengambil keputusan mengenai pengadaan sumber daya.', '7', '', '', 10, 1270, 73, 0, 2025, 1, NULL, 'Bukti ada rekomendasi dari organisasi profesional dan sumber berwenang lainnya dalam mengambil keputusan mengenai pengadaan sumber daya.', NULL, '•	Direktur RS\r\n•	Para manajer', NULL, '2025-07-01 08:43:20', 0, 'A'),
(4982, 'TKRS 7 EP.4', 4, 'Pimpinan rumah sakit memberikan arahan, dukungan, dan pengawasan terhadap penggunaan sumber daya Teknologi informasi Kesehatan (TIK)', '7', '', '', 10, 1270, 73, 0, 2025, 1, NULL, 'Bukti Pimpinan   rumah   sakit   memberikan:\r\na)	Arahan (dokumen dapat berbentuk rapat/pertemuan)\r\nb)	Dukungan (dokumen dapat berbentuk anggaran dan atau SDM)\r\nc)	Pengawasan terhadap penggunaan sumber daya Teknologi informasi Kesehatan (TIK) \r\n(Dokumen dapat berbentuk hasil supervisi atau rapat evaluasi)', NULL, '•	Direktur RS\r\n•	Para manajer RS', NULL, '0000-00-00 00:00:00', 0, 'A'),
(4983, 'TKRS 7 EP.5', 5, 'Pimpinan rumah sakit memberikan arahan, dukungan, dan pengawasan terhadap pelaksanaan program penanggulangan kedaruratan dan bencana.', '7', '', '', 10, 1270, 73, 0, 2025, 1, NULL, 'Bukti Pimpinan   rumah   sakit   memberikan:\r\na)	Arahan (dokumen dapat berbentuk rapat/pertemuan)\r\nb)	Dukungan (dokumen dapat berbentuk anggaran untuk penambahan SDM, pelatihan-pelatihan, simulasi dan perbaikan fasilitas)\r\nc)	Pengawasan terhadap pelaksanaan program penanggulangan kedaruratan dan bencana. (Dokumen dapat berbentuk hasil supervisi atau rapat evaluasi)', NULL, '•	Direktur RS\r\n•	Para manajer RS', NULL, '2025-07-01 08:45:26', 0, 'A'),
(4984, 'TKRS 7 EP.6', 6, 'Pimpinan rumah sakit memantau hasil keputusannya dan menggunakan data tersebut untuk mengevaluasi dan memperbaiki mutu keputusan pembelian dan pengalokasian sumber daya.', '7', '', '', 10, 1270, 73, 0, 2025, 1, NULL, 'Bukti ada dokumen pemantauan dan evaluasi oleh Pimpinan   rumah   sakit   terhadap pelaksanaan keputusan pada EP 1, 2, 3, 4, 5 dan melakukan perbaikan mutu.', NULL, '•	Direktur RS\r\n•	Para manajer RS', NULL, '2025-07-01 08:46:04', 0, 'A'),
(4985, 'TKRS 7.1 EP.1', 1, 'Pimpinan rumah sakit menentukan obat-obatan, perbekalan medis, serta peralatan medis yang paling berisiko dan membuat bagan alur rantai  perbekalannya.', '7.1', '', '', 10, 1271, 73, 0, 2025, 1, 'Regulasi tentang penentuan tingkat risiko obat-obatan, perbekalan medis, serta peralatan medis disertai bagan alur rantai perbekalannya.', NULL, NULL, NULL, NULL, '0000-00-00 00:00:00', 0, 'A'),
(4986, 'TKRS 7.1 EP.2', 2, 'Pimpinan rumah sakit menentukan titik  paling  berisiko dalam bagan alur rantai perbekalan dan membuat keputusan berdasarkan risiko dalam rantai perbekalan tersebut.', '7.1', '', '', 10, 1271, 73, 0, 2025, 1, 'Regulasi pada EP 1 disertai dengan:\r\n1)	penetapan titik paling berisiko dalam bagan alur rantai perbekalan dan \r\n2)	penetapan upaya mitigasi risiko dalam rantai perbekalan tersebut', NULL, NULL, NULL, NULL, '0000-00-00 00:00:00', 0, 'A'),
(4987, 'TKRS 7.1 EP.3', 3, 'Rumah sakit memiliki proses untuk melakukan pelacakan retrospektif terhadap perbekalan yang  diduga tidak stabil, terkontaminasi, rusak, atau palsu.', '7.1', '', '', 10, 1271, 73, 0, 2025, 1, NULL, 'Bukti dokumen proses pelacakan retrospektif terhadap perbekalan yang diduga tidak stabil, terkontaminasi, rusak, atau palsu', NULL, 'Kepala unit farmasi', NULL, '0000-00-00 00:00:00', 0, 'A'),
(4988, 'TKRS 7.1 EP.4', 4, 'Rumah sakit memberitahu produsen dan/atau distributor bila menemukan perbekalan yang tidak stabil, terkontaminasi, rusak, atau palsu.', '7.1', '', '', 10, 1271, 73, 0, 2025, 1, NULL, 'Bukti pemberitahuan kepada  produsen  dan /atau  distributor  bila menemukan perbekalan yang tidak stabil, terkontaminasi, rusak, atau palsu.', NULL, 'Kepala unit farmasi', NULL, '2025-07-01 09:09:38', 0, 'A'),
(4989, 'TKRS 8 EP.1', 1, 'Terdapat struktur organisasi Komite Medik, Komite Keperawatan, dan Komite Tenaga Kesehatan Lain yang ditetapkan Direktur sesuai peraturan perundang- undangan yang berlaku.', '8', '', '', 10, 1272, 73, 0, 2025, 1, '1)	Penetapan Komite Medik\r\n2)	Penetapan Komite Keperawatan \r\n3)	Penetapan Komite/Tim Tenaga Kesehatan Lainnya', NULL, NULL, NULL, NULL, '0000-00-00 00:00:00', 0, 'A'),
(4990, 'TKRS 8 EP.2', 2, 'Komite Medik, Komite Keperawatan dan Komite Tenaga Kesehatan Lain melaksanakan tanggung jawabnya mencakup (a-d) dalam maksud dan tujuan.', '8', '', '', 10, 1272, 73, 0, 2025, 1, NULL, 'Bukti Komite medik, komite keperawatan dan komite tenaga kesehatan lain melaksanakan tanggung jawabnya mencakup: \r\na)	komunikasi yang efektif\r\nb)	kebijakan;  Pedoman,  prosedur  serta  protokol,  tata hubungan kerja, alur klinis, dan dokumen lain yang mengatur layanan klinis\r\nc)	kode etik profesi\r\nd)	Mutu pelayanan pasien', NULL, NULL, NULL, '2025-07-01 09:10:16', 0, 'A'),
(4991, 'TKRS 8 EP.3', 3, 'Untuk melaksanakan tanggung jawabnya Komite  Medik, Komite Keperawatan, dan Komite Tenaga Kesehatan Lain menyusun Program kerja setiap tahun dan ditetapkan oleh Direktur.', '8', '', '', 10, 1272, 73, 0, 2025, 1, '1)	Program Kerja Komite Medik\r\n2)	Program Kerja Komite Keperawatan \r\n3)	Program Kerja Komite / Tim Tenaga Kesehatan Lain', NULL, NULL, NULL, NULL, '2025-07-01 09:10:34', 0, 'A'),
(4992, 'TKRS 9 EP.1', 1, 'Kepala unit kerja diangkat sesuai kualifikasi dalam persyaratan jabatan yang ditetapkan.', '9', '', '', 10, 1273, 73, 0, 2025, 1, 'Regulasi tentang  penetapan kepala unit kerja sesuai dengan kualifikasi dalam persyaratan jabatan', NULL, NULL, NULL, NULL, '2025-07-01 09:11:05', 0, 'A'),
(4993, 'TKRS 9 EP.2', 2, 'Kepala unit kerja menyusun pedoman pengorganisasian, pedoman pelayanan dan prosedur sesuai proses bisnis di unit kerja.', '9', '', '', 10, 1273, 73, 0, 2025, 1, '1)	Pedoman Pengorganisasian unit\r\n2)	Pedoman Pelayanan Unit disertai prosedur di unit', NULL, NULL, NULL, NULL, '2025-07-01 09:11:22', 0, 'A'),
(4994, 'TKRS 9 EP.3', 3, 'Kepala unit kerja menyusun program kerja yang termasuk di dalamnya kegiatan peningkatan mutu dan keselamatan pasien serta manajemen risiko setiap tahun.', '9', '', '', 10, 1273, 73, 0, 2025, 1, 'Regulasi tentang program kerja unit yang di dalamnya termasuk kegiatan peningkatan mutu dan keselamatan pasien serta manajemen risiko setiap tahun', NULL, NULL, NULL, NULL, '2025-07-01 09:11:47', 0, 'A'),
(4995, 'TKRS 9 EP.4', 4, 'Kepala unit kerja mengusulkan  kebutuhan  sumber daya mencakup ruangan, peralatan medis, teknologi informasi dan sumber daya lain yang diperlukan unit layanan serta terdapat mekanisme untuk menanggapi kondisi jika terjadi kekurangan tenaga.', '9', '', '', 10, 1273, 73, 0, 2025, 1, NULL, 'Bukti kepala unit kerja mengusulkan kebutuhan sumber daya mencakup:\r\na)	Ruangan, peralatan medis, teknologi informasi dan sumber daya lain, dan\r\nb)	Mekanisme untuk menanggapi kondisi jika terjadi kekurangan tenaga', NULL, 'Kepala unit kerja', NULL, '2025-07-01 09:12:12', 0, 'A'),
(4996, 'TKRS 9 EP.5', 5, 'Kepala unit kerja telah melakukan koordinasi dan integrasi baik dalam unitnya maupun antar unit layanan.', '9', '', '', 10, 1273, 73, 0, 2025, 1, NULL, '1)	Bukti rapat dalam unit\r\n2)	Bukti rapat antar unit\r\nmeliputi : undangan, materi rapat, absensi dan notulen', NULL, 'Kepala unit kerja', NULL, '0000-00-00 00:00:00', 0, 'A'),
(4997, 'TKRS 10 EP.1', 1, 'Kepala unit klinis/non klinis melakukan pengukuran INM yang sesuai dengan pelayanan yang diberikan oleh unitnya', '10', '', '', 10, 1274, 73, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan pengukuran INM di unit klinis/non klinis', NULL, '•	Komite Mutu RS\r\n•	Kepala unit kerja', NULL, '2025-07-01 09:13:28', 0, 'A'),
(4998, 'TKRS 10 EP.2', 2, 'Kepala unit klinis/non klinis melakukan pengukuran IMP-RS yang sesuai dengan pelayanan yang diberikan oleh unitnya, termasuk semua layanan kontrak yang menjadi tanggung jawabnya.', '10', '', '', 10, 1274, 73, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan pengukuran IMP–RS di unit klinis/non klinis termasuk semua layanan kontrak', NULL, '•	Komite Mutu RS\r\n•	Kepala unit kerja', NULL, '2025-07-01 09:14:08', 0, 'A'),
(4999, 'TKRS 10 EP.3', 3, 'Kepala unit klinis/non klinis menerapkan pengukuran IMP-Unit untuk mengurangi variasi dan memperbaiki proses dalam unitnya,', '10', '', '', 10, 1274, 73, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan pengukuran IMP-Unit di unit klinis/non klinis', NULL, '•	Komite Mutu RS\r\n•	Kepala unit kerja', NULL, '2025-07-01 09:14:35', 0, 'A'),
(5000, 'TKRS 10 EP.4', 4, 'Kepala unit klinis/non klinis memilih prioritas perbaikan yang baru bila perbaikan sebelumnya sudah dapat dipertahankan dalam waktu 1 (satu) tahun.', '10', '', '', 10, 1274, 73, 0, 2025, 1, NULL, 'Bukti tentang pemilihan prioritas perbaikan baru bila sudah dapat  dipertahankan dalam waktu 1 (satu) tahun.', NULL, '•	Komite Mutu RS\r\n•	Kepala unit kerja', NULL, '2025-07-01 09:15:11', 0, 'A'),
(5001, 'TKRS 11 EP.1', 1, 'Penilaian praktik profesional berkelanjutan (On going Professional Practice Evaluation) para dokter dalam memberikan pelayanan untuk  meningkatkan  mutu  dan keselamatan pasien menggunakan indikator mutu yang diukur di unit tersebut.', '11', '', '', 10, 1275, 73, 0, 2025, 1, NULL, 'Bukti indikator mutu yang digunakan untuk penilaian praktik profesional berkelanjutan (On going Professional Practice Evaluation/OPPE) para dokter,   diukur unit tersebut.', NULL, '•	Manajer SDM\r\n•	Kepala unit pelayanan\r\n\r\n(Lihat juga KPS 12 EP 3)', NULL, '2025-07-01 09:16:10', 0, 'A'),
(5002, 'TKRS 11 EP.2', 2, 'Penilaian kinerja para perawat dalam memberikan pelayanan untuk meningkatkan mutu  dan  keselamatan pasien menggunakan indikator  mutu  yang diukur di unit tersebut.', '11', '', '', 10, 1275, 73, 0, 2025, 1, NULL, 'Bukti   indikator mutu yang digunakan untuk penilaian kinerja para perawat, diukur di unit tersebut.', NULL, '•	Manajer SDM\r\n•	Kepala unit pelayanan\r\n\r\n(Lihat juga KPS 16 EP 2)', NULL, '2025-07-01 09:16:40', 0, 'A'),
(5003, 'TKRS 11 EP.3', 3, 'Penilaian kinerja tenaga kesehatan lainnya memberikan pelayanan untuk  meningkatkan  mutu  dan keselamatan pasien menggunakan indikator mutu yang diukur di unit tersebut.', '11', '', '', 10, 1275, 73, 0, 2025, 1, NULL, 'Bukti   Indikator mutu yang digunakan untuk penilaian kinerja tenaga kesehatan lainnya (staf klinis), diukur di unit tersebut.', NULL, '•	Manajer SDM\r\n•	Kepala unit pelayanan\r\n\r\n(Lihat juga KPS 19 EP 2)', NULL, '2025-07-01 09:17:12', 0, 'A'),
(5004, 'TKRS 12 EP.1', 1, 'Direktur rumah sakit menetapkan Komite Etik rumah sakit.', '12', '', '', 10, 1276, 73, 0, 2025, 1, 'Regulasi tentang penetapan Komite Etik RS', NULL, NULL, NULL, NULL, '2025-07-01 09:17:38', 0, 'A'),
(5005, 'TKRS 12 EP.2', 2, 'Komite Etik telah menyusun kode etik rumah sakit  yang mengacu pada Kode Etik Rumah Sakit Indonesia (KODERSI) dan ditetapkan Direktur.', '12', '', '', 10, 1276, 73, 0, 2025, 1, 'Regulasi tentang penetapan Kode etik rumah sakit', NULL, NULL, NULL, NULL, '0000-00-00 00:00:00', 0, 'A'),
(5006, 'TKRS 12 EP.3', 3, 'Komite Etik telah menyusun kerangka kerja pelaporan dan pengelolaan etik rumah sakit serta pedoman pengelolaan kode etik rumah sakit meliputi poin 1) sampai dengan 12) dalam maksud dan tujuan sesuai dengan visi, misi, dan nilai-nilai yang dianut rumah sakit.', '12', '', '', 10, 1276, 73, 0, 2025, 1, 'Regulasi tentang Pedoman Pengelolaan Etik RS meliputi poin 1) sampai dengan 12)', NULL, NULL, NULL, NULL, '2025-07-01 09:18:20', 0, 'A'),
(5007, 'TKRS 12 EP.4', 4, 'Rumah sakit menyediakan sumber  daya  serta pelatihan kerangka pengelolaan etik rumah sakit bagi praktisi kesehatan dan staf lainnya dan memberikan solusi yang efektif dan tepat waktu  untuk  masalah  etik.', '12', '', '', 10, 1276, 73, 0, 2025, 1, NULL, 'Bukti pelaksanaan pelatihan pengelolaan etik rumah sakit bagi praktisi kesehatan dan staf lainnya meliputi TOR, undangan, daftar hadir, materi, laporan, evaluasi, dan sertifikat', NULL, 'Manajer diklat', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5008, 'TKRS 13 EP.1', 1, 'Pimpinan rumah sakit menetapkan Program Budaya Keselamatan yang mencakup poin sampai dengan dalam maksud dan tujuan serta mendukung penerapannya secara akuntabel dan transparan.', '13', '', '', 10, 1277, 73, 0, 2025, 1, 'Regulasi berupa Program Budaya Keselamatan meliputi a) sampai dengan h)', NULL, NULL, NULL, NULL, '2025-07-01 09:19:16', 0, 'A'),
(5009, 'TKRS 13 EP.2', 2, 'Pimpinan rumah sakit menyelenggarakan pendidikan dan menyediakan informasi (kepustakaan dan laporan) terkait budaya keselamatan bagi semua staf yang bekerja di rumah sakit.', '13', '', '', 10, 1277, 73, 0, 2025, 1, NULL, 'Bukti  tentang:\r\na)	Edukasi semua staf di rumah sakit tentang budaya keselamatan\r\nb)	Penyediaan informasi (kepustakaan) terkait budaya keselamatan\r\nc)	Penyediaan sistem pelaporan bila ada insiden terkait budaya keselamatan/perilaku yang tidak diinginkan', NULL, 'Manajer terkait', NULL, '2025-07-01 09:20:10', 0, 'A'),
(5010, 'TKRS 13 EP.3', 3, 'Pimpinan rumah sakit menyediakan sumber daya  untuk mendukung dan mendorong  budaya keselamatan di rumah sakit.', '13', '', '', 10, 1277, 73, 0, 2025, 1, NULL, NULL, 'Tersedia sumber daya untuk mendukung dan mendorong budaya keselamatan (misal: IT untuk sistem pelaporan, perpustakaan budaya keselamatan) \r\nCatatan: perpustakaan dapat online/onsite/hybrid', 'Komite Mutu RS', NULL, '2025-07-01 09:20:46', 0, 'A'),
(5011, 'TKRS 13 EP.4', 4, 'Pimpinan rumah sakit mengembangkan sistem yang rahasia, sederhana dan mudah diakses bagi staf untuk mengidentifikasi dan melaporkan perilaku yang tidak diinginkan dan menindaklanjutinya.', '13', '', '', 10, 1277, 73, 0, 2025, 1, NULL, NULL, 'Lihat  sistem pelaporan insiden perilaku yang tidak diinginkan memenuhi ketentuan sebagai berikut:\r\na)	Kerahasiaan\r\nb)	Sederhana (user friendly)\r\nc)	Mudah diakses oleh staf rumah sakit.', 'Manajer terkait', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5012, 'TKRS 13 EP.5', 5, 'Pimpinan rumah sakit melakukan pengukuran untuk mengevaluasi dan memantau budaya keselamatan di rumah sakit serta hasil yang diperoleh dipergunakan untuk perbaikan penerapannya di rumah sakit.', '13', '', '', 10, 1277, 73, 0, 2025, 1, NULL, 'Bukti hasil survei budaya keselamatan dan bukti penerapan perbaikan berdasarkan hasil survei', NULL, 'Komite Mutu RS', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5013, 'TKRS 13 EP.6', 6, 'Pimpinan rumah sakit menerapkan budaya adil (just culturterhadap staf yang terkait laporan budaya keselamatan tersebut.', '13', '', '', 10, 1277, 73, 0, 2025, 1, NULL, 'Bukti RS menerapkan  budaya  adil  (just  culture) terhadap staf yang terkait laporan budaya keselamatan tersebut', NULL, '•	Direktur RS\r\n•	Manajer terkait', NULL, '2025-07-01 09:25:15', 0, 'A'),
(5014, 'TKRS 14 EP.1', 1, 'Direktur dan pimpinan rumah sakit berpartisipasi dan menetapkan program manajemen risiko tingkat rumah sakit meliputi poin a) sampai dengan d) dalam maksud dan tujuan.', '14', '', '', 10, 1278, 73, 0, 2025, 1, 'Regulasi tentang program manajemen risiko  tingkat rumah sakit meliputi poin a) sampai dengan d)', NULL, NULL, NULL, NULL, '0000-00-00 00:00:00', 0, 'A'),
(5015, 'TKRS 14 EP.2', 2, 'Direktur memantau penyusunan daftar risiko yang diprioritaskan menjadi profil risiko di tingkat rumah sakit.', '14', '', '', 10, 1278, 73, 0, 2025, 1, NULL, 'Bukti dokumen rapat Direktur RS yang membahas penetapan profil risiko tingkat rumah sakit yang dilengkapi dengan:\r\na)	Dokumen daftar risiko yang di prioritaskan\r\nb)	Dokumen profil risiko di tingkat rumah sakit', NULL, 'Direktur RS', NULL, '2025-07-01 09:26:12', 0, 'A'),
(5016, 'TKRS 15 EP.1', 1, 'Pimpinan rumah sakit menetapkan penanggung jawab program penelitian di dalam rumah sakit yang memastikan semua proses telah sesuai dengan kode  etik penelitian dan persyaratan lainnya sesuai  peraturan perundang-undangan.', '15', '', '', 10, 1279, 73, 0, 2025, 1, 'Regulasi tentang penetapan Penanggung jawab program penelitian (Komite Etik Penelitian) yang dilengkapi dengan uraian tugasnya', NULL, NULL, NULL, NULL, '2025-07-01 09:27:17', 0, 'A'),
(5017, 'TKRS 15 EP.2', 2, 'Terdapat proses untuk menyelesaian konflik kepentingan (finansial dan non finansial) yang terjadi akibat penelitian di rumah sakit.', '15', '', '', 10, 1279, 73, 0, 2025, 1, 'Regulasi tentang proses penyelesaian konflik kepentingan (finansial dan non finansial) yang terjadi akibat penelitian di rumah sakit.', NULL, NULL, NULL, NULL, '2025-07-01 09:28:29', 0, 'A'),
(5018, 'TKRS 15 EP.3', 3, 'Pimpinan rumah sakit telah mengidentifikasi fasilitas dan sumber daya yang diperlukan untuk melakukan penelitian, termasuk di dalam nya kompetensi sumber daya yang akan berpartisipasi di dalam penelitian sebagai pimpinan dan anggota tim peneliti.', '15', '', '', 10, 1279, 73, 0, 2025, 1, 'Regulasi tentang penetapan:\r\n1)	Fasilitas dan sumber daya  yang  diperlukan untuk  melakukan  penelitian, \r\n2)	Kompetensi sumber daya yang akan berpartisipasi di dalam penelitian sebagai pimpinan dan anggota tim peneliti', NULL, NULL, NULL, NULL, '0000-00-00 00:00:00', 0, 'A'),
(5019, 'TKRS 15 EP.4', 4, ' Terdapat proses yang memastikan bahwa seluruh pasien yang ikut di dalam penelitian telah melalui proses persetujuan tertulis (informed consent) untuk melakukan penelitian, tanpa adanya paksaan untuk mengikuti penelitian dan telah mendapatkan informasi mengenai lamanya penelitian, prosedur yang harus dilalui, siapa yang dapat dikontak selama penelitian berlangsung, manfaat, potensial risiko serta alternatif pengobatan lainnya.', '15', '', '', 10, 1279, 73, 0, 2025, 1, NULL, 'Bukti bahwa seluruh pasien yang ikut di dalam penelitian telah melalui proses:\r\n1)	Persetujuan tertulis (informed consent) untuk melakukan penelitian\r\n2)	Mendapatkan informasi mengenai lamanya  penelitian,  prosedur  yang  harus dilalui, siapa yang dapat dikontak selama penelitian berlangsung, manfaat, potensial risiko serta alternatif pengobatan lainnya.', NULL, 'Komite Etik Penelitian RS', NULL, '2025-07-01 09:29:34', 0, 'A'),
(5020, 'TKRS 15 EP.5', 5, 'Apabila penelitian dilakukan oleh pihak ketiga (kontrak), maka pimpinan rumah sakit memastikan bahwa pihak ketiga tersebut bertanggung jawab dalam      pemantauan dan evaluasi dari mutu, keamanan dan etika dalam penelitian.', '15', '', '', 10, 1279, 73, 0, 2025, 1, NULL, 'Bukti Dokumen hasil pemantauan dan evaluasi  pihak ketiga  tentang mutu, keamanan dan etika dalam penelitian', NULL, '•	Direktur RS\r\n•	Komite Etik Penelitian RS', NULL, '2025-07-01 09:30:19', 0, 'A'),
(5021, 'TKRS 15 EP.6', 6, 'Penanggung jawab penelitian melakukan kajian dan evaluasi terhadap seluruh penelitian yang dilakukan di rumah sakit setidaknya 1 (satu) tahun sekali.', '15', '', '', 10, 1279, 73, 0, 2025, 1, NULL, 'Bukti Dokumen kajian   dan  evaluasi dari penanggung jawab penelitian terhadap seluruh penelitian di rumah sakit setahun sekali', NULL, 'Komite Etik Penelitian RS', NULL, '2025-07-01 09:30:45', 0, 'A'),
(5022, 'TKRS 15 EP.7', 7, 'Seluruh kegiatan penelitian merupakan bagian dari program mutu rumah sakit  dan  dilakukan  pemantauan serta evaluasinya secara berkala sesuai ketetapan rumah sakit.', '15', '', '', 10, 1279, 73, 0, 2025, 1, NULL, '1)	Bukti program mutu RS ada kegiatan monitoring, evaluasi terhadap kegiatan penelitian \r\n2)	Bukti hasil pemantauan dan evaluasi berkala', NULL, '•	Komite Etik Penelitian RS\r\n•	Komite Mutu RS', NULL, '2025-07-01 09:31:15', 0, 'A'),
(5023, 'KPS 1 EP.1', 1, 'Direktur telah menetapkan regulasi terkait Kualifikasi Pendidikan dan staf meliputi poin a - f pada gambaran umum.', '1', '', '', 10, 1280, 74, 0, 2025, 1, 'Regulasi tentang manajemen sumber daya manusia meliputi:\r\na)	Perencanaan dan pengelolaan staf; \r\nb)	Pendidikan dan pelatihan; \r\nc)	Kesehatan dan keselamatan kerja staf; \r\nd)	Tenaga medis; \r\ne)	Tenaga keperawatan; dan\r\nf)	Tenaga kesehatan lain.', NULL, NULL, NULL, NULL, '2025-07-01 09:33:20', 0, 'A'),
(5024, 'KPS 1 EP.2', 2, 'Kepala unit telah merencanakan dan menetapkan persyaratan pendidikan, kompetensi dan pengalaman staf di unitnya sesuai peraturan dan perundang- undangan.', '1', '', '', 10, 1280, 74, 0, 2025, 1, NULL, 'Bukti perencanaan SDM di unit kerja yang dilengkapi dengan persyaratan meliputi pendidikan, kompetensi dan pengalaman staf', NULL, '•	Kepala unit kerja\r\n•	Manajer SDM', NULL, '2025-07-01 09:34:15', 0, 'A'),
(5025, 'KPS 1 EP.3', 3, 'Kebutuhan staf telah direncanakan sesuai poin a)-e) dalam maksud dan tujuan.', '1', '', '', 10, 1280, 74, 0, 2025, 1, 'Regulasi tentang penetapan perencanaan SDM sesuai dengan:\r\na)	Misi rumah sakit.\r\nb)	Populasi pasien yang dilayani dan kompleksitas serta kebutuhan pasien. \r\nc)	Layanan diagnostik dan klinis yang disediakan rumah sakit. \r\nd)	Jumlah pasien rawat inap dan rawat jalan. \r\ne)	Peralatan medis yang digunakan untuk pelayanan pasien.', NULL, NULL, NULL, NULL, '2025-07-01 09:34:36', 0, 'A'),
(5026, 'KPS 1 EP.4', 4, 'Perencanaan staf meliputi penghitungan jumlah, jenis, dan kualifikasi staf menggunakan metode yang diakui sesuai peraturan perundang-undangan.', '1', '', '', 10, 1280, 74, 0, 2025, 1, NULL, 'Bukti perencanaan SDM yang meliputi jumlah, jenis dan kualifikasi staf menggunakan metode yang sesuai dengan peraturan perundang-undangan', NULL, 'Manajer SDM', NULL, '2025-07-01 09:35:45', 0, 'A'),
(5027, 'KPS 1 EP.5', 5, 'Perencanaan staf termasuk membahas penugasan dan rotasi/alih fungsi staf.', '1', '', '', 10, 1280, 74, 0, 2025, 1, NULL, 'Bukti perencanaan SDM termasuk meliputi penugasan dan rotasi/alih fungsi staf', NULL, 'Manajer SDM', NULL, '2025-07-01 09:36:08', 0, 'A'),
(5028, 'KPS 1 EP.6', 6, 'Efektivitas perencanaan staf dipantau secara berkelanjutan dan diperbarui sesuai kebutuhan.', '1', '', '', 10, 1280, 74, 0, 2025, 1, NULL, 'Bukti proses pemantauan efektivitas perencanaan staf dan pembaruannya', NULL, 'Manajer SDM', NULL, '2025-07-01 09:36:34', 0, 'A'),
(5029, 'KPS 2 EP.1', 1, 'Setiap staf telah memiliki uraian tugas sesuai dengan tugas yang diberikan.', '2', '', '', 10, 1281, 74, 0, 2025, 1, 'Regulasi tentang uraian tugas staf RS', NULL, NULL, NULL, NULL, '2025-07-01 09:36:47', 0, 'A'),
(5030, 'KPS 2 EP.2', 2, 'Tenaga kesehatan yang diidentifikasi dalam a) hingga d) dalam maksud dan tujuan, memiliki uraian tugas yang sesuai dengan tugas dan tanggung jawabnya.', '2', '', '', 10, 1281, 74, 0, 2025, 1, 'Regulasi tentang penetapan uraian tugas untuk:\r\na)	Tenaga kesehatan ditugaskan di bidang manajerial. \r\nb)	Tenaga kesehatan melakukan dua tugas yaitu di bidang manajerial dan di bidang klinis.\r\nc)	Tenaga kesehatan yang sedang mengikuti pendidikan dan bekerja dibawah supervisi, maka program pendidikan.\r\nd)	Tenaga kesehatan yang diizinkan untuk memberikan pelayanan sementara dirumah sakit.', NULL, NULL, NULL, NULL, '2025-07-01 09:37:01', 0, 'A'),
(5031, 'KPS 3 EP.1', 1, 'Rumah sakit telah menetapkan regulasi terkait proses rekrutmen, evaluasi kompetensi kandidat calon staf  dan mekanisme pengangkatan staf di rumah sakit.', '3', '', '', 10, 1282, 74, 0, 2025, 1, 'Regulasi tentang proses rekrutmen, evaluasi kompetensi kandidat calon staf dan mekanisme pengangkatan staf di rumah sakit', NULL, NULL, NULL, NULL, '2025-07-01 09:37:27', 0, 'A'),
(5032, 'KPS 3 EP.2', 2, 'Rumah sakit telah menerapkan proses meliputi poin  a) hingga c) dimaksud dan tujuan secara seragam.', '3', '', '', 10, 1282, 74, 0, 2025, 1, NULL, 'Bukti pelaksanaan:\r\na)	Rekrutmen staf sesuai kebutuhan rumah sakit. \r\nb)	Evaluasi kompetensi kandidat calon staf. \r\nc)	Pengangkatan staf baru.', NULL, 'Manajer SDM', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5033, 'KPS 4 EP.1', 1, 'Rumah sakit telah menetapkan dan  menerapkan  proses untuk menyesuaikan kompetensi PPA dengan kebutuhan pasien.', '4', '', '', 10, 1283, 74, 0, 2025, 1, 'Regulasi tentang kompetensi dan kewenangan PPA dalam SPK dan RKK', NULL, NULL, NULL, NULL, '2025-07-01 09:38:30', 0, 'A'),
(5034, 'KPS 4 EP.2', 2, 'Para PPA baru dievaluasi pada saat mulai bekerja oleh kepala unit di mana PPA tersebut ditugaskan', '4', '', '', 10, 1283, 74, 0, 2025, 1, NULL, 'Bukti pelaksaan evaluasi PPA yang baru direkrut oleh kepala unit tempatnya bekerja', NULL, '•	Kepala unit\r\n•	Manajer SDM', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5035, 'KPS 4 EP.3', 3, 'Terdapat setidaknya satu atau lebih evaluasi yang didokumentasikan untuk tiap PPA sesuai uraian tugas setiap tahunnya atau sesuai ketentuan rumah sakit.', '4', '', '', 10, 1283, 74, 0, 2025, 1, NULL, 'Bukti dokumentasi evaluasi PPA setiap tahunnya atau sesuai ketentuan rumah sakit', NULL, '•	Kepala unit\r\n•	Manajer SDM', NULL, '2025-07-01 09:39:17', 0, 'A'),
(5036, 'KPS 5 EP.1', 1, 'Rumah sakit telah menetapkan dan  menerapkan  proses untuk menyesuaikan kompetensi staf non klinis dengan persyaratan jabatan/posisi.', '5', '', '', 10, 1284, 74, 0, 2025, 1, 'Regulasi tentang penetapan kompetensi staf non klinis', NULL, NULL, NULL, NULL, '2025-07-01 09:39:40', 0, 'A'),
(5037, 'KPS 5 EP.2', 2, 'Staf non klinis yang baru dinilai kinerjanya pada saat akan memulai pekerjaannya oleh kepala unit di mana staf tersebut ditugaskan.', '5', '', '', 10, 1284, 74, 0, 2025, 1, NULL, 'Bukti pelaksaan evaluasi staf non klinis yang baru direkrut oleh kepala unit tempatnya bekerja', NULL, '•	Kepala unit\r\n•	Manajer SDM', NULL, '2025-07-01 09:40:09', 0, 'A'),
(5038, 'KPS 5 EP.3', 3, 'Terdapat setidaknya satu atau lebih evaluasi yang didokumentasikan untuk tiap staf non klinis sesuai uraian tugas setiap tahunnya atau sesuai ketentuan rumah sakit.', '5', '', '', 10, 1284, 74, 0, 2025, 1, NULL, 'Bukti dokumentasi evaluasi staf non klinis setiap tahunnya atau sesuai ketentuan rumah sakit', NULL, '•	Kepala unit\r\n•	Manajer SDM', NULL, '2025-07-01 09:40:40', 0, 'A'),
(5039, 'KPS 6 EP.1', 1, 'File kepegawaian staf distandardisasi dan dipelihara serta dijaga kerahasiaannya sesuai dengan kebijakan rumah sakit.', '6', '', '', 10, 1285, 74, 0, 2025, 1, NULL, NULL, 'File pegawai disusun seragam dan dipelihara serta dijaga kerahasiaannya', 'Manajer SDM', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5040, 'KPS 6 EP.2', 2, 'File kepegawaian mencakup poin a) hingga g) sesuai maksud dan tujuan.', '6', '', '', 10, 1285, 74, 0, 2025, 1, NULL, NULL, 'File kepegawaian memuat:\r\na)	Pendidikan, kualifikasi, keterampilan, kompetensi, staf\r\nb)	Bukti orientasi\r\nc)	Uraian tugas staf\r\nd)	Riwayat pekerjaan staf\r\ne)	Penilaian kinerja staf\r\nf)	Salinan sertifikat pelatihan di dalam maupun di luar rumah sakit yang telah diikuti\r\ng)	Informasi kesehatan yang dipersyaratkan, seperti vaksinasi/imunisasi, hasil medical check up.', NULL, NULL, '0000-00-00 00:00:00', 0, 'A'),
(5041, 'KPS 7 EP.1', 1, 'Rumah sakit telah menetapkan regulasi tentang orientasi bagi staf baru di rumah sakit.', '7', '', '', 10, 1286, 74, 0, 2025, 1, 'Regulasi tentang orientasi umum dan khusus bagi staf baru di rumah sakit', NULL, NULL, NULL, NULL, '0000-00-00 00:00:00', 0, 'A'),
(5042, 'KPS 7 EP.2', 2, 'Tenaga kesehatan baru  telah  diberikan  orientasi umum dan orientasi khusus sesuai.', '7', '', '', 10, 1286, 74, 0, 2025, 1, NULL, 'Bukti pelaksanaan orientasi umum dan orientasi khusus tenaga kesehatan baru', NULL, 'Manajer SDM', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5043, 'KPS 7 EP.3', 3, 'Staf nonklinis baru telah diberikan orientasi  umum  dan orientasi khusus.', '7', '', '', 10, 1286, 74, 0, 2025, 1, NULL, 'Bukti pelaksanaan orientasi umum dan orientasi khusus staf non klinis baru', NULL, 'Manajer SDM', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5044, 'KPS 7 EP.4', 4, 'Tenaga kontrak, paruh waktu, mahasiswa atau trainee dan sukarelawan telah diberikan orientasi umum dan orientasi khusus (jika ada).', '7', '', '', 10, 1286, 74, 0, 2025, 1, NULL, 'Bukti pelaksanaan orientasi umum dan orientasi khusus tenaga kontrak, paruh waktu, mahasiswa atau trainee dan sukarelawan', NULL, 'Manajer SDM', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5045, 'KPS 8 EP.1', 1, 'Rumah sakit telah mengidentifikasi kebutuhan pendidikan staf berdasarkan sumber berbagai      informasi, mencakup a) hingga h) dalam  maksud  dan  tujuan.', '8', '', '', 10, 1287, 74, 0, 2025, 1, NULL, 'Bukti kebutuhan pendidikan staf berdasarkan:\r\na)	Hasil kegiatan pengukuran data mutu dan keselamatan pasien\r\nb)	Hasil analisa laporan insiden keselamatan pasien\r\nc)	Hasil survei budaya keselamatan pasien\r\nd)	Hasil pemantauan program manajemen fasilitas dan keselamatan\r\ne)	Pengenalan teknologi termasuk penambahan peralatan medis baru, keterampilan dan pengetahuan baru yang diperoleh dari penilaian kinerja\r\nf)	Prosedur klinis baru\r\ng)	Rencana untuk menyediakan layanan baru di masa yang akan datang\r\nh)	Kebutuhan dan usulan dari setiap unit', NULL, 'Manajer SDM', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5046, 'KPS 8 EP.2', 2, 'Program pendidikan dan pelatihan telah disusun berdasarkan hasil identifikasi sumber informasi pada EP 1.', '8', '', '', 10, 1287, 74, 0, 2025, 1, 'Regulasi tentang program pelatihan', NULL, NULL, NULL, NULL, '0000-00-00 00:00:00', 0, 'A'),
(5047, 'KPS 8 EP.3', 3, 'Pendidikan dan pelatihan berkelanjutan diberikan kepada staf rumah sakit baik internal maupun eksternal.', '8', '', '', 10, 1287, 74, 0, 2025, 1, NULL, 'Bukti pelakanaan pelatihan berkelanjutan kepada staf rumah sakit baik internal maupun eksternal meliputi TOR, undangan, daftar hadir, materi, laporan, evaluasi, sertifikat', NULL, 'Manajer SDM', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5048, 'KPS 8 EP.4', 4, 'Rumah sakit telah menyediakan waktu, anggaran, sarana dan prasarana yang memadai bagi semua staf untuk mendapat kesempatan mengikuti  pendidikan dan pelatihan yang dibutuhkan.', '8', '', '', 10, 1287, 74, 0, 2025, 1, NULL, 'Bukti tersedia anggaran dengan sarana dan prasarana yang memadai bagi semua staf untuk mendapat kesempatan mengikuti pendidikan dan pelatihan yang dibutuhkan', NULL, 'Manajer SDM', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5049, 'KPS 8.1 EP.1', 1, 'Rumah sakit telah menetapkan pelatihan teknik resusitasi jantung paru tingkat dasar (BHD) pada seluruh staf dan bantuan hidup tingkat lanjut bagi staf yang ditentukan oleh rumah sakit.', '8.1', '', '', 10, 1288, 74, 0, 2025, 1, 'Regulasi tentang materi pelatihan teknik resusitasi jantung paru tingkat dasar (BHD) dan bantuan hidup tingkat lanjut', NULL, NULL, NULL, NULL, '0000-00-00 00:00:00', 0, 'A'),
(5050, 'KPS 8.1 EP.2', 2, 'Terdapat bukti yang menunjukkan bahwa staf yang mengikuti pelatihan BHD atau bantuan hidup tingkat lanjut telah lulus pelatihan tersebut.', '8.1', '', '', 10, 1288, 74, 0, 2025, 1, NULL, 'Bukti pelaksanaan pelatihan BHD atau bantuan hidup tingkat lanjut meliputi TOR, undangan, daftar hadir, materi, laporan, evaluasi, sertifikat', NULL, 'Manajer SDM', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5051, 'KPS 8.1 EP.3', 3, 'Tingkat pelatihan yang ditentukan untuk  tiap  staf harus diulang berdasarkan persyaratan  dan/atau jangka waktu yang ditetapkan oleh program pelatihan yang diakui, atau setiap 2 (dua) tahun jika tidak menggunakan program pelatihan yang diakui.', '8.1', '', '', 10, 1288, 74, 0, 2025, 1, NULL, 'Bukti pelaksanaan pelatihan ulang BHD atau bantuan hidup tingkat lanjut sesuai jangka waktu sertifikat atau setiap 2 (dua) tahun jika tidak menggunakan program pelatihan yang diakui, meliputi TOR, undangan, daftar hadir, materi, laporan, evaluasi, sertifikat', NULL, NULL, NULL, '0000-00-00 00:00:00', 0, 'A'),
(5052, 'KPS 9 EP.1', 1, 'Rumah sakit telah menetapkan  program  kesehatan  dan keselamatan staf.', '9', '', '', 10, 1289, 74, 0, 2025, 1, 'Regulasi tentang program kesehatan dan keselamatan staf', NULL, NULL, NULL, NULL, '0000-00-00 00:00:00', 0, 'A'),
(5053, 'KPS 9 EP.2', 2, 'Program kesehatan dan keselamatan staf mencakup setidaknya a) hingga h) yang tercantum dalam maksud dan tujuan.', '9', '', '', 10, 1289, 74, 0, 2025, 1, NULL, 'Bukti pelaksanaan\r\na)	Skrining kesehatan awal\r\nb)	Tindakan-tindakan untuk mengendalikan pajanan kerja yang berbahaya, seperti pajanan terhadap obat-obatan beracun dan tingkat kebisingan yang berbahaya\r\nc)	Pendidikan, pelatihan, dan intervensi terkait cara pemberian asuhan pasien yang aman\r\nd)	Pendidikan, pelatihan, dan intervensi terkait pengelolaan kekerasan di tempat kerja\r\ne)	Pendidikan, pelatihan, dan intervensi terhadap staf yang berpotensi melakukan kejadian tidak diharapkan (KTD) atau kejadian sentinel\r\nf)	Tata laksana kondisi terkait pekerjaan yang umum dijumpai seperti cedera punggung atau cedera lain yang lebih darurat\r\ng)	Vaksinasi/imunisasi pencegahan, dan pemeriksaan kesehatan berkala\r\nh)	Pengelolaan kesehatan mental staf, seperti pada saat kondisi kedaruratan penyakit infeksi/pandemi', NULL, '•	Komite K3RS\r\n•	Manajer SDM', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5054, 'KPS 9 EP.3', 3, 'Rumah sakit mengidentifikasi penularan penyakit infeksi atau paparan yang dapat terjadi pada staf serta melakukan upaya pencegahan dengan vaksinasi.', '9', '', '', 10, 1289, 74, 0, 2025, 1, NULL, '1)	Bukti pencatatan staf yang terpapar penyakit infeksi atau lainnya\r\n2)	Bukti upaya pencegahan dengan vaksinasi', NULL, 'Manajer SDM', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5055, 'KPS 9 EP.4', 4, 'Berdasar atas epidemologi penyakit infeksi maka  rumah sakit mengidentifikasi risiko staf terpapar atau tertular serta melaksanakan pemeriksaan kesehatan  dan vaksinasi.', '9', '', '', 10, 1289, 74, 0, 2025, 1, NULL, '1)	Bukti identifikasi staf berisiko terpapar atau tertular (bisa dalam bentuk risk register)\r\n2)	Bukti pelaksanaan pemeriksaan kesehatan dan vaksinasi', NULL, '•	Komite K3RS\r\n•	Manajer SDM', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5056, 'KPS 9 EP.5', 5, 'Rumah sakit telah melaksanakan evaluasi, konseling, dan tata laksana lebih lanjut untuk staf yang terpapar penyakit infeksi serta dikoordinasikan dengan program pencegahan dan pengendalian infeksi.', '9', '', '', 10, 1289, 74, 0, 2025, 1, NULL, '1)	Bukti pelaksanaan evaluasi, konseling, dan tata laksana lebih lanjut untuk staf yang terpapar penyakit infeksi, serta \r\n2)	Bukti telah dikoordinasikan dengan program pencegahan dan pengendalian infeksi', NULL, '•	Komite K3RS\r\n•	Komite PPI\r\n•	Manajer SDM', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5057, 'KPS 9 EP.6', 6, 'Rumah sakit telah mengidentifikasi area yang berpotensi untuk terjadi tindakan kekerasan di tempat kerja (workplace violence) dan menerapkan upaya untuk mengurangi risiko tersebut.', '9', '', '', 10, 1289, 74, 0, 2025, 1, NULL, '1)	Bukti identifikasi area yang berpotensi untuk terjadi tindakan kekerasan di tempat kerja (bisa dalam bentuk risk register)\r\n2)	Bukti pelaksanaan upaya untuk mengurangi risiko tersebut', NULL, '•	Komite K3RS\r\n•	Manajer SDM', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5058, 'KPS 9 EP.7', 7, 'Rumah sakit telah melaksanakan evaluasi, konseling, dan tata laksana lebih lanjut untuk staf  yang  mengalami cedera akibat tindakan kekerasan di tempat kerja.', '9', '', '', 10, 1289, 74, 0, 2025, 1, NULL, 'Bukti pelaksanaan evaluasi, konseling, dan tata laksana lebih lanjut untuk staf yang mengalami cedera akibat tindakan kekerasan di tempat kerja', NULL, '•	Komite K3RS\r\n•	Manajer SDM', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5059, 'KPS 10 EP.1', 1, 'Rumah sakit telah menetapkan peraturan internal tenaga medis (medical staf bylaws) yang mengatur proses penerimaan, kredensial, penilaian kinerja, dan rekredensial tenaga medis', '10', '', '', 10, 1290, 74, 0, 2025, 1, 'Regulasi tentang peraturan internal tenaga medis (medical staf bylaws)', NULL, NULL, NULL, NULL, '2025-07-01 10:00:04', 0, 'A');
INSERT INTO `accreditation_instrument` (`instrument_id`, `instrument_reference_code`, `instrument_order_id`, `instrument_name`, `instrument_objective`, `instrument_material`, `instrument_document`, `instrument_maximum_score`, `instrument_standard_id`, `instrument_chapter_id`, `instrument_class_id`, `instrument_version`, `instrument_institution_group_id`, `instrument_r`, `instrument_d`, `instrument_o`, `instrument_w`, `instrument_s`, `instrument_update`, `instrument_user_id`, `instrument_record_status`) VALUES
(5060, 'KPS 10 EP.2', 2, 'Rumah sakit telah melaksanakan proses  kredensial  dan pemberian kewenangan klinis untuk pelayanan diagnostik, konsultasi, dan tata laksana yang diberikan oleh dokter praktik mandiri di rumah sakit secara seragam', '10', '', '', 10, 1290, 74, 0, 2025, 1, NULL, 'Bukti pelaksanaan kredensial dan pemberian kewenangan klinis untuk pelayanan diagnostik, konsultasi, dan tata laksana yang diberikan oleh dokter praktik mandiri di rumah sakit secara seragam', NULL, '•	Komite Medik\r\n•	Manajer SDM', NULL, '2025-07-01 10:00:24', 0, 'A'),
(5061, 'KPS 10 EP.3', 3, 'Rumah sakit telah melaksanakan proses  kredensial  dan pemberian kewenangan klinis kepada dokter praktik mandiri dari luar rumah  sakit  seperti konsultasi kedokteran jarak jauh (telemedicine), radiologi jarak jauh (teleradiology), dan interpretasi untuk pemeriksaan diagnostik lain: elektrokardiogram (EKG), elektroensefalogram (EEG), elektromiogram (EMG), serta pemeriksaan lain yang serupa.', '10', '', '', 10, 1290, 74, 0, 2025, 1, NULL, 'Bukti pelaksanaan kredensial dan pemberian kewenangan klinis kepada dokter praktik mandiri dari luar rumah sakit seperti konsultasi kedokteran jarak jauh (telemedicine), radiologi jarak jauh (teleradiology), dan interpretasi untuk pemeriksaan diagnostik lain', NULL, '•	Komite Medik\r\n•	Manajer SDM', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5062, 'KPS 10 EP.4', 4, 'Setiap tenaga medis yang memberikan pelayanan di rumah sakit wajib menandatangani perjanjian sesuai dengan regulasi rumah sakit.', '10', '', '', 10, 1290, 74, 0, 2025, 1, NULL, 'Bukti setiap tenaga medis yang memberikan pelayanan di rumah sakit telah menandatangani perjanjian', NULL, 'Manajer SDM', NULL, '2025-07-01 10:03:00', 0, 'A'),
(5063, 'KPS 10 EP.5', 5, 'Rumah sakit telah melaksanakan verifikasi ke Lembaga/Badan/Instansi pendidikan atau organisasi profesional yang diakui yang mengeluarkan izin/sertifikat, dan kredensial lain dalam proses kredensial sesuai dengan peraturan perundang- undangan atau yang', '10', '', '', 10, 1290, 74, 0, 2025, 1, NULL, 'Bukti pelaksanaan verifikasi ke Lembaga/Badan/Instansi pendidikan atau organisasi profesional yang diakui yang mengeluarkan izin/sertifikat, dan kredensial lain', NULL, 'Manajer SDM', NULL, '2025-07-01 10:03:21', 0, 'A'),
(5064, 'KPS 10 EP.6', 6, 'Ada bukti dilaksanakan kredensial tambahan  ke sumber yang mengeluarkan apabila tenaga medis yang meminta kewenangan klinis tambahan yang canggih atau subspesialisasi.', '10', '', '', 10, 1290, 74, 0, 2025, 1, NULL, 'Bukti pelaksaan kredensial untuk kewenangan tambahan', NULL, 'Manajer SDM', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5065, 'KPS 10.1 EP.1', 1, 'Pengangkatan tenaga medis dibuat berdasar atas kebijakan rumah sakit dan konsisten dengan populasi pasien rumah sakit, misi, dan pelayanan  yang  diberikan untuk memenuhi kebutuhan pasien', '10.1', '', '', 10, 1291, 74, 0, 2025, 1, 'Regulasi tentang penetapan kebutuhan tenaga medis\r\n\r\n(Lihat KPS 1 EP 3)', NULL, NULL, NULL, NULL, '2025-07-01 10:04:05', 0, 'A'),
(5066, 'KPS 10.1 EP.2', 2, 'Pengangkatan tidak dilakukan sampai setidaknya izin/surat tanda registrasi sudah diverifikasi dari sumber utama yang mengeluarkan surat tersebut dan tenaga medis dapat memberikan pelayanan kepada pasien di bawah supervisi sampai semua kredensial yang disyaratkan undang-undang  dan  peraturan  sudah diverifikasi dari sumbernya.', '10.1', '', '', 10, 1291, 74, 0, 2025, 1, NULL, NULL, 'Memastikan bahwa kepada tenaga medis tidak diberikan kewenangan memberikan pelayanan kepada pasien sampai setidaknya izin/surat tanda registrasi sudah diverifikasi dari sumber utama yang mengeluarkan surat tersebut', 'Manajer SDM', NULL, '2025-07-01 10:04:37', 0, 'A'),
(5067, 'KPS 10.1 EP.3', 3, 'Untuk tenaga medis yang belum mendapatkan kewenangan mandiri, dilakukan supervisi dengan mengatur frekuensi supervisi dan supervisor yang ditunjuk serta didokumentasikan di file kredensial staf tersebut.', '10.1', '', '', 10, 1291, 74, 0, 2025, 1, NULL, 'Bukti pelaksanaan supervisi kepada tenaga medis yang belum mendapatkan kewenangan mandiri', NULL, '•	Manajer SDM\r\n•	Kepala unit pelayanan', NULL, '2025-07-01 10:05:05', 0, 'A'),
(5068, 'KPS 11 EP.1', 1, 'Direktur menetapkan kewenangan klinis setelah mendapat rekomendasi dari Komite Medik termasuk kewenangan tambahan dengan mempertimbangan poin a) hingga j) dalam maksud dan tujuan.', '11', '', '', 10, 1292, 74, 0, 2025, 1, 'Regulasi tentang penetapan kewenangan klinis berupa SPK dan RKK, serta pemberian kewenangan tambahan', NULL, NULL, NULL, NULL, '2025-07-01 10:05:26', 0, 'A'),
(5069, 'KPS 11 EP.2', 2, 'Ada bukti pemberian kewenangan klinis berdasar atas rekomendasi kewenangan klinis dari Komite Medik.', '11', '', '', 10, 1292, 74, 0, 2025, 1, NULL, 'Bukti rekomendasi kewenangan klinis dari Komite Medik', NULL, 'Manajer SDM', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5070, 'KPS 11 EP.3', 3, 'Ada bukti pelaksanaan pemberian kewenangan tambahan setelah melakukan verifikasi dari sumber utama yang mengeluarkan ijazah/sertifikat.', '11', '', '', 10, 1292, 74, 0, 2025, 1, NULL, NULL, 'Memastikan pemberian kewenangan tambahan setelah melakukan verifikasi dari sumber utama yang mengeluarkan ijazah/sertifikat', 'Manajer SDM', NULL, '2025-07-01 10:06:23', 0, 'A'),
(5071, 'KPS 11 EP.4', 4, 'Surat penugasan klinis dan rincian kewenangan klinis anggota    tenaga    medis    dalam    bentuk    cetak   atau      elektronik (softcopy) atau media lain tersedia di semua unit pelayanan.', '11', '', '', 10, 1292, 74, 0, 2025, 1, NULL, 'Bukti dokumen SPK dan RKK tersedia di semua unit pelayanan', NULL, 'Kepala ruang unit pelayanan', NULL, '2025-07-01 10:08:38', 0, 'A'),
(5072, 'KPS 11 EP.5', 5, 'Setiap tenaga medis hanya memberikan pelayanan klinis sesuai kewenangan klinis yang diberikan kepadanya.', '11', '', '', 10, 1292, 74, 0, 2025, 1, NULL, NULL, 'Memastikan setiap tenaga medis hanya memberikan pelayanan klinis sesuai kewenangan klinis yang diberikan kepadanya', 'Kepala ruang unit pelayanan', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5073, 'KPS 12 EP.1', 1, 'Rumah sakit telah menetapkan dan  menerapkan  proses penilaian kinerja untuk evaluasi mutu praktik profesional berkelanjutan, etik, dan disiplin (OPPE) tenaga medis', '12', '', '', 10, 1293, 74, 0, 2025, 1, NULL, 'Bukti pelaksanaan penilaian kinerja untuk evaluasi mutu praktik profesional berkelanjutan, etik, dan disiplin (OPPE) tenaga medis sesuai regulasi RS', NULL, 'Manajer SDM', NULL, '2025-07-01 10:10:27', 0, 'A'),
(5074, 'KPS 12 EP.2', 2, 'Penilaian OPPE tenaga medis memuat 3 (tiga) area umum 1) hingga 3) dalam maksud dan tujuan.', '12', '', '', 10, 1293, 74, 0, 2025, 1, NULL, 'Bukti dalam dokumen OPPE memuat:\r\n1)	Perilaku;\r\n2)	Pengembangan professional; dan \r\n3)	Kinerja klinis', NULL, 'Manajer SDM', NULL, '2025-07-01 10:10:48', 0, 'A'),
(5075, 'KPS 12 EP.3', 3, 'Penilaian OPPE juga meliputi peran tenaga medis dalam pencapaian target indikator mutu  yang  diukur di unit tempatnya bekerja.', '12', '', '', 10, 1293, 74, 0, 2025, 1, NULL, 'Bukti dalam OPPE juga meliputi peran tenaga medis dalam pencapaian target indikator mutu yang diukur di unit tempatnya bekerja', NULL, 'Manajer SDM', NULL, '2025-07-01 10:11:11', 0, 'A'),
(5076, 'KPS 12 EP.4', 4, 'Data dan informasi hasil pelayanan klinis dari tenaga medis dikaji secara objektif dan berdasar atas  bukti, jika memungkinkan dilakukan benchmarking dengan pihak eksternal rumah sakit.', '12', '', '', 10, 1293, 74, 0, 2025, 1, NULL, 'Bukti pelaksanaan pengkajian secara obyektif terhadap data dan informasi hasil pelayanan klinis dari tenaga medis, termasuk dilakukan benchmarking', NULL, 'Manajer SDM', NULL, '2025-07-01 10:12:13', 0, 'A'),
(5077, 'KPS 12 EP.5', 5, 'Data dan informasi hasil pemantauan kinerja tenaga medis sekurang-kurangnya setiap 12 (dua belas) bulan dilakukan oleh kepala unit, kepala kelompok tenaga medis, Subkomite Mutu Profesi Komite Medik dan pimpinan pelayanan medis. Hasil, simpulan, dan tindakan didokumentasikan di dalam file kredensial tenaga medis tersebut', '12', '', '', 10, 1293, 74, 0, 2025, 1, NULL, 'Bukti data dan informasi hasil pemantauan kinerja tenaga medis yang dilakukan oleh:\r\n1)	Kepala unit,\r\n2)	Kepala kelompok tenaga medis, \r\n3)	Subkomite Mutu Profesi Komite Medik dan \r\n4)	Pimpinan pelayanan medis', NULL, 'Manajer SDM', NULL, '2025-07-01 10:12:37', 0, 'A'),
(5078, 'KPS 12 EP.6', 6, 'Jika terjadi kejadian insiden keselamatan pasien atau pelanggaran perilaku etik maka dilakukan tindakan terhadap tenaga medis tersebut secara adil (just culture) berdasarkan hasil analisis terkait kejadian tersebut.', '12', '', '', 10, 1293, 74, 0, 2025, 1, NULL, 'Bukti pelaksanaan tindakan terhadap tenaga medis jika terjadi kejadian insiden keselamatan pasien atau pelanggaran perilaku etik', NULL, 'Manajer SDM', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5079, 'KPS 12 EP.7', 7, 'Bila ada temuan yang berdampak pada pemberian kewenangan tenaga medis, temuan tersebut didokumentasi ke dalam file tenaga medis dan diinformasikan serta disimpan di unit tempat tenaga medis memberikan pelayanan', '12', '', '', 10, 1293, 74, 0, 2025, 1, NULL, 'Bukti perubahan pemberian kewenangan tenaga medis dan tersedia di unit tempat tenaga medis memberikan pelayanan', NULL, '•	Manajer SDM\r\n•	Kepala ruang unit pelayanan', NULL, '2025-07-01 10:13:18', 0, 'A'),
(5080, 'KPS 13 EP.1', 1, 'Berdasarkan penilaian praktik profesional berkelanjutan tenaga medis, rumah sakit menentukan sedikitnya setiap 3 (tiga) tahun, apakah kewenangan klinis tenaga medis dapat dilanjutkan dengan atau tanpa modifikasi (berkurang atau bertambah).', '13', '', '', 10, 1294, 74, 0, 2025, 1, NULL, 'Bukti pelaksanaan rekredensial tenaga medis setiap 3 (tiga) tahun yang didasarkan pada OPPE', NULL, '•	Komite Medik\r\n•	Manajer SDM', NULL, '2025-07-01 10:14:13', 0, 'A'),
(5081, 'KPS 13 EP.2', 2, 'Terdapat bukti terkini dalam berkas setiap  tenaga medis untuk semua kredensial yang perlu diperbarui secara periodik.', '13', '', '', 10, 1294, 74, 0, 2025, 1, NULL, 'Bukti dalam file kepegawaian tersimpan berkas setiap tenaga medis untuk semua kredensial yang perlu diperbarui secara periodik', NULL, 'Manajer SDM', NULL, '2025-07-01 10:14:33', 0, 'A'),
(5082, 'KPS 13 EP.3', 3, 'Ada bukti pemberian kewenangan klinis tambahan didasarkan atas kredensial yang telah diverifikasi dari sumber Badan/Lembaga/Institusi penyelenggara pendidikan atau pelatihan. sesuai dengan peraturan perundang-undangan.', '13', '', '', 10, 1294, 74, 0, 2025, 1, NULL, 'Bukti pemberian kewenangan klinis tambahan', NULL, 'Manajer SDM\r\n\r\n(Lihat juga KPS 10 EP 6, KPS 11 EP 3)', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5083, 'KPS 14 EP.1', 1, 'Rumah sakit  telah  menetapkan  dan  menerapkan   proses kredensial yang efektif terhadap tenaga perawat meliputi poin a) hingga c) dalam maksud dan tujuan.', '14', '', '', 10, 1295, 74, 0, 2025, 1, NULL, 'Bukti pelaksanaan proses kredensial yang efektif terhadap tenaga perawat meliputi:\r\n1)	Sesuai peraturan dan perundang-undangan\r\n2)	Melakukan kredensial terhadap semua bukti pendidikan, pelatihan, pengalaman, informasi yang ada pada setiap perawat\r\n3)	memverifikasi informasi penting dari berbagai sumber utama', NULL, '•	Komite Keperawatan\r\n•	Manajer SDM', NULL, '2025-07-01 10:16:47', 0, 'A'),
(5084, 'KPS 14 EP.2', 2, 'Tersedia bukti dokumentasi pendidikan, registrasi, sertifikasi, izin, pelatihan, dan pengalaman yang terbaharui di file tenaga perawat.', '14', '', '', 10, 1295, 74, 0, 2025, 1, NULL, 'Bukti dokumentasi pendidikan, registrasi, sertifikasi, izin, pelatihan, dan pengalaman yang terbaharui di dalam file tenaga perawat', NULL, 'Manajer SDM', NULL, '2025-07-01 10:17:07', 0, 'A'),
(5085, 'KPS 14 EP.3', 3, 'Terdapat pelaksanaan verifikasi ke sumber Badan/Lembaga/institusi penyelenggara pendidikan/ pelatihan yang seragam.', '14', '', '', 10, 1295, 74, 0, 2025, 1, NULL, 'Bukti pelaksanaan verifikasi ke sumber Badan/Lembaga/institusi penyelenggara pendidikan/ pelatihan yang seragam', NULL, 'Manajer SDM', NULL, '2025-07-01 10:17:26', 0, 'A'),
(5086, 'KPS 14 EP.4', 4, 'Terdapat bukti dokumen kredensial yang dipelihara pada setiap tenaga perawat.', '14', '', '', 10, 1295, 74, 0, 2025, 1, NULL, 'Bukti dokumen kredensial yang selalu diperbarui', NULL, 'Manajer SDM', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5087, 'KPS 14 EP.5', 5, 'Rumah sakit menerapkan proses untuk memastikan bahwa kredensial perawat kontrak lengkap sebelum penugasan.', '14', '', '', 10, 1295, 74, 0, 2025, 1, NULL, 'Bukti dokumen kredensial perawat kontrak sudah lengkap sebelum diberikan penugasan (perhatikan tanggalnya)', NULL, 'Manajer SDM', NULL, '2025-07-01 10:18:16', 0, 'A'),
(5088, 'KPS 15 EP.1', 1, 'Rumah sakit telah menetapkan rincian kewenangan klinis perawat berdasar hasil kredensial terhadap perawat.', '15', '', '', 10, 1296, 74, 0, 2025, 1, 'Regulasi tentang penetapan rincian kewenangan klinis (RKK) perawat berdasar hasil kredensial', NULL, NULL, NULL, NULL, '2025-07-01 10:18:28', 0, 'A'),
