(5091, 'KPS 16 EP.2', 2, 'Penilaian kinerja tenaga perawat meliputi pemenuhan uraian tugasnya dan perannya dalam  pencapaian  target indikator mutu yang diukur di unit tempatnya bekerja.', '16', '', '', 10, 1297, 74, 0, 2025, 1, NULL, 'Bukti pelaksanaan penilaian kinerja tenaga perawat meliputi:\r\n1)	pemenuhan uraian tugasnya dan \r\n2)	perannya dalam pencapaian target indikator mutu yang diukur di unit tempatnya bekerja', NULL, '•	Manajer SDM\r\n•	Kepala unit pelayanan', NULL, '2025-07-01 10:19:26', 0, 'A'),
(5092, 'KPS 16 EP.3', 3, 'Pimpinan rumah sakit dan kepala unit telah  berlaku adil (just culture) ketika ada temuan dalam kegiatan peningkatan mutu, laporan  insiden  keselamatan  pasien atau manajemen risiko.', '16', '', '', 10, 1297, 74, 0, 2025, 1, NULL, 'Bukti dokumentasi proses tindak lanjut ketika ada temuan dalam kegiatan peningkatan mutu, laporan insiden keselamatan pasien atau manajemen risiko', NULL, 'Manajer SDM', NULL, '2025-07-01 10:20:00', 0, 'A'),
(5093, 'KPS 16 EP.4', 4, 'Rumah sakit telah mendokumentasikan hasil kajian, tindakan yang diambil, dan setiap dampak atas      tanggung jawab pekerjaan perawat dalam file kredensial perawat.', '16', '', '', 10, 1297, 74, 0, 2025, 1, NULL, 'Bukti dalam file kepegawaian telah didokumentasikan hasil kajian, tindakan yang diambil, dan setiap dampak atas tanggung jawab pekerjaan perawat', NULL, 'Manajer SDM', NULL, '2025-07-01 10:20:27', 0, 'A'),
