(5095, 'KPS 17 EP.2', 2, 'Tersedia bukti dokumentasi pendidikan, registrasi, sertifikasi, izin, pelatihan, dan pengalaman yang terbaharui di file tenaga Kesehatan lainnya.', '17', '', '', 10, 1298, 74, 0, 2025, 1, NULL, 'Bukti dokumentasi pendidikan, registrasi, sertifikasi, izin, pelatihan, dan pengalaman yang terbaharui di dalam file tenaga kesehatan lainnya (staf klinis)', NULL, 'Manajer SDM', NULL, '2025-07-01 10:21:13', 0, 'A'),
