(5100, 'KPS 19 EP.1', 1, 'Rumah sakit telah melakukan penilaian kinerja tenaga Kesehatan lainnya secara periodik menggunakan  format dan metode sesuai ketentuan yang ditetapkan rumah sakit.', '19', '', '', 10, 1300, 74, 0, 2025, 1, NULL, 'Bukti pelaksanaan penilaian kinerja tenaga kesehatan lainnya (staf klinis) secara periodik menggunakan format dan metode sesuai regulasi RS', NULL, '•	Manajer SDM\r\n•	Kepala unit pelayanan', NULL, '2025-07-01 10:23:02', 0, 'A'),
(5101, 'KPS 19 EP.2', 2, 'Penilain kinerja tenaga Kesehatan lainnya meliputi pemenuhan uraian tugasnya dan perannya dalam pencapaian target indikator mutu yang diukur di unit tempatnya bekerja.', '19', '', '', 10, 1300, 74, 0, 2025, 1, NULL, 'Bukti pelaksanaan penilaian kinerja tenaga kesehatan lainnya (staf klinis) meliputi:\r\n1)	pemenuhan uraian tugasnya dan \r\n2)	perannya dalam pencapaian target indikator mutu yang diukur di unit tempatnya bekerja', NULL, '•	Manajer SDM\r\n•	Kepala unit pelayanan', NULL, '2025-07-01 10:23:33', 0, 'A'),
(5102, 'KPS 19 EP.3', 3, 'Pimpinan rumah sakit dan kepala unit telah  berlaku adil (just culture) ketika ada temuan dalam kegiatan peningkatan mutu, laporan  insiden  keselamatan  pasien atau manajemen risiko.', '19', '', '', 10, 1300, 74, 0, 2025, 1, NULL, 'Bukti dokumentasi proses tindak lanjut ketika ada temuan dalam kegiatan peningkatan mutu, laporan insiden keselamatan pasien atau manajemen risiko', NULL, 'Manajer SDM', NULL, '2025-07-01 10:26:45', 0, 'A'),
(5103, 'KPS 19 EP.4', 4, 'Rumah sakit telah mendokumentasikan hasil kajian, tindakan yang diambil, dan setiap dampak atas tanggung jawab pekerjaan tenaga kesehatan dalam file kredensial tenaga kesehatan lainnya.', '19', '', '', 10, 1300, 74, 0, 2025, 1, NULL, 'Bukti dalam file kepegawaian telah didokumentasikan hasil kajian, tindakan yang diambil, dan setiap dampak atas tanggung jawab pekerjaan tenaga kesehatan lainnya (staf klinis)', NULL, 'Manajer SDM', NULL, '2025-07-01 10:27:09', 0, 'A'),
(5104, 'MFK 1 EP.1', 1, 'Rumah sakit menetapkan regulasi terkait Manajemen Fasilitas dan Keselamatan (MFK) yang meliputi poin a) hingga j) pada gambaran umum.', '1', '', '', 10, 1301, 75, 0, 2025, 1, 'Regulasi tentang : \r\na)	Kepemimpinan dan perencanaan;\r\nb)	Keselamatan fasilitas;\r\nc)	Keamanan fasilitas;\r\nd)	Pengelolaan bahan dan limbah berbahaya dan beracun (B3);\r\ne)	Proteksi kebakaran;\r\nf)	Peralatan medis;\r\ng)	Sistim utilitas;\r\nh)	Penanganan kedaruratan dan bencana;\r\ni)	Konstruksi dan renovasi; dan\r\nj)	Pelatihan.', NULL, NULL, NULL, NULL, '2025-07-01 10:28:05', 0, 'A'),
(5105, 'MFK 1 EP.2', 2, 'Rumah sakit telah melengkapi izin-izin dan sertifikasi yang masih berlaku sesuai persyaratan peraturan perundang-undangan.', '1', '', '', 10, 1301, 75, 0, 2025, 1, NULL, '1)	Memiliki perizinan berusaha yang masih berlaku dan teregistrasi di Kementerian Kesehatan\r\n2)	Memiliki Izin Pengelolaan Limbah Cair (IPLC) yang masih berlaku. \r\n3)	Memiliki Kerja sama dengan pihak ketiga yang mempunyai izin sebagai pengolah dan/atau sebagai transporter limbah B3 yang masih berlaku atau izin alat pengolah limbah B3 (Insenerator, Autoclave, Microwave).', NULL, '•	Komite/tim K3\r\n•	Bagian Umum/ Kepala IPSRS', NULL, '2025-07-01 10:28:43', 0, 'A'),
(5106, 'MFK 1 EP.3', 3, 'Pimpinan rumah sakit memenuhi perencanaan anggaran dan sumber daya serta memastikan rumah sakit memenuhi persyaratan perundang-undangan.', '1', '', '', 10, 1301, 75, 0, 2025, 1, 'Regulasi tentang rencana kerja dan anggaran', NULL, NULL, NULL, NULL, '2025-07-01 10:29:02', 0, 'A'),
(5107, 'MFK 2 EP.1', 1, 'Rumah sakit telah menetapkan Penanggungjawab MFK yang memiliki kompetensi dan pengalaman dalam melakukan pengelolaan pada fasilitas dan keselamatan di lingkungan rumah sakit.', '2', '', '', 10, 1302, 75, 0, 2025, 1, 'Regulasi tentang penetapan  Penanggungjawab  MFK yang memiliki kompetensi dan pengalaman dalam melakukan pengelolaan pada fasilitas dan keselamatan di lingkungan rumah sakit, yang dilengkapi dengan tugas dan tanggung jawab meliputi a) sd j)', NULL, NULL, NULL, NULL, '2025-07-01 10:29:17', 0, 'A'),
(5108, 'MFK 2 EP.2', 2, 'Penanggungjawab MFK telah menyusun Program Manajemen Fasilitas dan Keselamatan (MFK) yang meliputi poin a) hingga j) dalam maksud dan tujuan.', '2', '', '', 10, 1302, 75, 0, 2025, 1, 'Regulasi tentang penetapan Program  Manajemen Fasilitas dan Keselamatan (MFK)', NULL, NULL, NULL, NULL, '2025-07-01 10:29:29', 0, 'A'),
(5109, 'MFK 2 EP.3', 3, 'Penanggungjawab MFK telah melakukan  pengawasan dan evaluasi Manajemen Fasilitas dan Keselamatan  (MFK) setiap tahunnya meliputi poin a) hingga g) dalam maksud dan tujuan serta melakukan penyesuaian program apabila diperlukan.', '2', '', '', 10, 1302, 75, 0, 2025, 1, NULL, 'Bukti pelaksanaan pengawasan   dan evaluasi terhadap Manajemen Fasilitas dan Keselamatan, dalam bentuk ceklis', NULL, '•	Penanggung jawab MFK\r\n•	Bagian Umum/ Kepala IPSRS', NULL, '2025-07-01 10:30:09', 0, 'A'),
(5110, 'MFK 2 EP.4', 4, 'Penerapan program Manajemen Fasilitas dan Keselamatan (MFK) pada tenant/penyewa lahan yang      berada di lingkungan rumah sakit meliputi poin a) hingga e) dalam maksud dan tujuan.', '2', '', '', 10, 1302, 75, 0, 2025, 1, NULL, 'Bukti pelaksanaan  penerapan program Manajemen Fasilitas dan Keselamatan (MFK) pada tenant/penyewa lahan', NULL, '•	Penanggung jawab MFK\r\n•	Bagian Umum/ Kepala IPSRS\r\n•	Tenant/penyewa lahan', NULL, '2025-07-01 10:30:35', 0, 'A'),
(5111, 'MFK 3 EP.1', 1, 'Rumah sakit menerapkan proses pengelolaan keselamatan rumah sakit meliputi poin a)-c) pada maksud dan tujuan.', '3', '', '', 10, 1303, 75, 0, 2025, 1, NULL, 'Bukti pelaksanaan  pengelolaan keselamatan rumah sakit meliputi:\r\na)	Pengelolaan risiko keselamatan di lingkungan rumah sakit \r\nb)	Penyediaan  fasilitas  pendukung  yang  aman  \r\nc)	Pemeriksaan  fasilitas  dan  lingkungan  (ronde  fasilitas)  \r\nsecara berkala', 'Lihat  bangunan, prasarana, lingkungan, properti, teknologi medis dan informasi, peralatan, dan sistem', '•	Komite/tim K3\r\n•	Bagian Umum/ Kepala IPSRS', NULL, '2025-07-01 10:31:20', 0, 'A'),
(5112, 'MFK 3 EP.2', 2, 'Rumah sakit telah mengintegrasikan program Kesehatan dan keselamatan kerja staf ke dalam  program manajemen fasilitas dan keselamatan.', '3', '', '', 10, 1303, 75, 0, 2025, 1, 'Program  Kesehatan  dan keselamatan kerja integrasi dengan program manajemen fasilitas dan keselamatan', NULL, NULL, NULL, NULL, '2025-07-01 10:31:38', 0, 'A'),
(5113, 'MFK 3 EP.3', 3, 'Rumah sakit telah membuat pengkajian risiko secara proaktif terkait keselamatan di rumah sakit  setiap tahun yang didokumentasikan dalam daftar risiko/risk register.', '3', '', '', 10, 1303, 75, 0, 2025, 1, NULL, 'Bukti dokumen daftar risiko/risk register terkait keselamatan di rumah sakit', NULL, '•	Komite/tim K3\r\n•	Komite Mutu \r\n•	Bagian Umum/ Kepala IPSRS', NULL, '2025-07-01 10:32:08', 0, 'A'),
(5114, 'MFK 3 EP.4', 4, 'Rumah sakit telah melakukan pemantauan risiko keselamatan dan dilaporkan setiap 6 (enam) bulan kepada pimpinan rumah sakit.', '3', '', '', 10, 1303, 75, 0, 2025, 1, NULL, 'Bukti  hasil pemantauan risiko keselamatan dan bukti laporan setiap 6 (enam) bulan kepada pimpinan rumah sakit', NULL, '•	Pimpinan RS\r\n•	Komite/tim K3\r\n•	Bagian Umum/ Kepala IPSRS', NULL, '2025-07-01 10:32:36', 0, 'A'),
(5115, 'MFK 4 EP.1', 1, 'Rumah sakit menerapkan proses  pengelolaan keamanan dilingkungan rumah sakit meliputi poin a) hingga e) pada maksud dan tujuan.', '4', '', '', 10, 1304, 75, 0, 2025, 1, NULL, 'Bukti proses pelaksanaan  pengelolaan    keamanan dilingkungan rumah sakit meliputi  :\r\na)	pemberian  identitas (badge nama sementara atau tetap) pada pasien, staf, pekerja kontrak, tenant/penyewa lahan, keluarga (penunggu pasien), atau pengunjung (pengunjung di luar jam besuk dan tamu rumah sakit)\r\nb)	pemeriksaan dan pemantauan keamanan fasilitas dan lingkungan secara berkala\r\nc)	Pemantauan dilakukan petugas keamanan (sekuriti) dan atau memasang kamera sistem CCTV \r\nd)	melindungi semua individu yang berada di lingkungan rumah sakit\r\ne)	menghindari terjadinya kehilangan, kerusakan, atau pengrusakan barang milik pribadi maupun rumah sakit.', '1)	Lihat pemberian identitas pada pasien, staf, pekerja kontrak, tenant/penyewa lahan, keluarga (penunggu pasien), atau pengunjung (pengunjung di luar jam besuk dan tamu rumah sakit)\r\n\r\n2)	Lihat CCTV terpasang di area yang ditetapkan berisiko keamanan', '•	Komite/tim K3\r\n•	Bagian Umum/ Kepala IPSRS\r\n•	Bagian Keamanan', NULL, '2025-07-01 10:33:35', 0, 'A'),
(5116, 'MFK 4 EP.2', 2, 'Rumah sakit telah membuat pengkajian risiko secara proaktif terkait keamanan di rumah sakit setiap tahun yang didokumentasikan dalam daftar risiko/risk register.', '4', '', '', 10, 1304, 75, 0, 2025, 1, NULL, 'Bukti dokumen daftar risiko/ risk register terkait keamanan di  rumah sakit', NULL, '•	Komite/tim K3\r\n•	Komite Mutu \r\n•	Bagian Umum/ Kepala IPSRS', NULL, '0000-00-00 00:00:00', 0, 'A'),
