(5119, 'MFK 5 EP.1', 1, 'Rumah sakit  telah  melaksanakan  proses  pengelolaan  B3 meliputi poin a hingga h pada maksud dan tujuan.', '5', '', '', 10, 1305, 75, 0, 2025, 1, NULL, 'Bukti proses pengelolaan B3 meliputi:\r\na)	Inventarisasi B3 serta limbahnya yang meliputi jenis, jumlah, simbol dan lokasi;\r\nb)	Penanganan, penyimpanan, dan penggunaan B3 serta limbahnya;\r\nc)	Penggunaan alat pelindung diri (APD) dan prosedur penggunaan, prosedur bila terjadi tumpahan, atau paparan/pajanan;\r\nd)	Pelatihan yang dibutuhkan oleh staf yang menangani B3;\r\n\r\ne)	Pemberian label/rambu-rambu yang tepat pada B3 serta limbahnya;\r\nf)	Pelaporan dan investigasi dari tumpahan, eksposur (terpapar), dan insiden lainnya;\r\ng)	Dokumentasi, termasuk izin, lisensi, atau persyaratan peraturan lainnya; dan\r\nh)	Pengadaan/pembelian    B3    dan    pemasok    (supplier)    wajib melampirkan Lembar Data Keselamatan.', 'Lihat tempat penyimpanan B3, label dan lembar data keamanan', '•	Komite/tim K3\r\n•	Bagian Umum/ Kepala IPSRS  \r\n•	Kepala Farmasi/Kepala Laboratorium \r\n•	Kepala unit kerja terkait', NULL, '2025-07-01 10:36:10', 0, 'A'),
(5120, 'MFK 5 EP.2', 2, 'Rumah sakit telah membuat pengkajian risiko secara proaktif terkait pengelolaan B3 di rumah sakit setiap tahun yang didokumentasikan dalam daftar risiko/risk register', '5', '', '', 10, 1305, 75, 0, 2025, 1, NULL, 'Bukti daftar risiko/ risk register terkait pengelolaan B3 (termasuk limbah B-3)', NULL, '•	Komite/tim K3\r\n•	Komite Mutu \r\n•	Bagian Umum/ Kepala IPSRS', NULL, '2025-07-01 10:36:44', 0, 'A'),
(5121, 'MFK 5 EP.3', 3, 'Di area tertentu yang rawan terhadap pajanan telah dilengkapi dengan eye washer/body washer yang berfungsi dan terpelihara baik dan tersedia kit tumpahan/spill kit sesuai ketentuan.', '5', '', '', 10, 1305, 75, 0, 2025, 1, NULL, NULL, '1)	Lihat eye washer/body washer\r\n2)	Kit tumpahan/spill kit', '•	Komite/tim K3\r\n•	Bagian Umum/ Kepala IPSRS  \r\n•	Kepala unit kerja terkait', NULL, '2025-07-01 10:37:05', 0, 'A'),
(5122, 'MFK 5 EP.4', 4, 'Staf dapat menjelaskan dan atau memperagakan penanganan tumpahan B3.', '5', '', '', 10, 1305, 75, 0, 2025, 1, NULL, NULL, NULL, '•	Kepala unit kerja terkait\r\n•	Staf RS', 'Peragaan penanganan tumpahan B3.', '2025-07-01 10:37:34', 0, 'A'),
(5123, 'MFK 5 EP.5', 5, 'Staf dapat menjelaskan dan atau memperagakan tindakan, kewaspadaan, prosedur  dan  partisipasi dalam penyimpanan, penanganan dan pembuangan limbah B3.', '5', '', '', 10, 1305, 75, 0, 2025, 1, NULL, NULL, NULL, 'Staf RS  dapat   menjelaskan   dan   atau   memperagakan tindakan, kewaspadaan,', 'prosedur dan partisipasi dalam penyimpanan, penanganan dan pembuangan limbah B3.', '2025-07-01 10:38:33', 0, 'A'),
(5124, 'MFK 5.1 EP.1', 1, 'Rumah sakit  melakukan  penyimpanan  limbah  B3  sesuai poin a) hingga k) pada maksud dan tujuan.', '5.1', '', '', 10, 1306, 75, 0, 2025, 1, NULL, NULL, 'Lihat penyimpanan  limbah B3', '•	Penanggung jawab sanitasi RS\r\n•	Petugas pelaksana IPAL', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5125, 'MFK 5.1 EP.2', 2, 'Rumah sakit mengolah limbah B3 padat  secara  mandiri atau menggunakan pihak ketiga yang berizin termasuk untuk pemusnahan limbah B3  cair  yang tidak bisa dibuang ke IPAL.', '5.1', '', '', 10, 1306, 75, 0, 2025, 1, NULL, '1)	Bukti pengelolaan  limbah  B3  padat  \r\n2)	Bukti ijin pengelolaan B3 atau kerja sama dengan pihak ketiga yang berijin', 'Lihat incinerator RS, bila RS mengolah limbah B-3 sendiri.', '•	Penanggung jawab sanitasi RS\r\n•	Staf RS terkait', NULL, '2025-07-01 10:39:36', 0, 'A'),
