(5147, 'MFK 8.2 EP.2', 2, 'Air bersih harus tersedia selama 24 jam setiap hari, 7 (tujuh) hari dalam seminggu.', '8.2', '', '', 10, 1311, 75, 0, 2025, 1, NULL, NULL, 'Air bersih telah tersedia selama 24 jam setiap hari, 7 (tujuh) hari dalam seminggu.', '•	Bagian umum/Kepala IPSRS\r\n•	Kepala Sanitasi', NULL, '0000-00-00 00:00:00', 0, 'A'),
