(5151, 'MFK 8.2.1 EP.1', 1, 'Rumah sakit melaksanakan uji coba sumber air bersih dan listrik cadangan/alternatif sekurangnya 6 (enam) bulan sekali atau lebih sering bila diharuskan oleh peraturan perundang-undanganan yang berlaku atau oleh kondisi sumber air.', '8.2.1', '', '', 10, 1312, 75, 0, 2025, 1, NULL, 'Bukti pelaksanaan:\r\n1)	uji coba sumber air bersih cadangan\r\n2)	uji coba sumber listrik cadangan / alternatif', NULL, '•	Bagian umum/Kepala IPSRS\r\n•	Kepala Sanitas', NULL, '2025-07-01 11:01:29', 0, 'A'),
(5152, 'MFK 8.2.1 EP.2', 2, 'Rumah sakit mendokumentasi hasil uji  coba  sumber air bersih cadangan/alternatif tersebut', '8.2.1', '', '', 10, 1312, 75, 0, 2025, 1, NULL, 'Bukti dokumentasi  hasil uji coba sumber air bersih cadangan atau alternatif tersebut', NULL, '•	Bagian umum/Kepala IPSRS\r\n•	Kepala Sanitasi', NULL, '2025-07-01 11:01:46', 0, 'A'),
