(5154, 'MFK 8.2.1 EP.4', 4, 'Rumah sakit mempunyai tempat dan jumlah bahan bakar untuk sumber listrik cadangan/alternatif yang mencukupi.', '8.2.1', '', '', 10, 1312, 75, 0, 2025, 1, NULL, NULL, 'Lihat tempat dan jumlah bahan bakar untuk sumber listrik cadangan/alternatif', 'Bagian umum/Kepala IPSRS', NULL, '2025-07-01 11:02:23', 0, 'A'),
(5155, 'MFK 8.3 EP.1', 1, 'Rumah sakit telah menerapkan proses sekurang- kurangnya meliputi poin a) hingga d) pada maksud dan tujuan.', '8.3', '', '', 10, 1313, 75, 0, 2025, 1, NULL, 'Bukti pelaksanaan :\r\na)	pelaksanaan monitoring mutu air bersih\r\nb)	pemeriksaan air limbah\r\nc)	pemeriksaan mutu air yang digunakan untuk dialisis ginjal\r\nd)	monitoring hasil pemeriksaan air dan perbaikan bila diperlukan', NULL, '•	Bagian umum/Kepala IPSRS\r\n•	Kepala Sanitasi', NULL, '2025-07-01 11:02:42', 0, 'A'),
