(5157, 'MFK 8.3 EP.3', 3, 'Rumah sakit telah menindaklanjuti hasil pemantauan dan evaluasi pada EP 2 dan didokumentasikan.', '8.3', '', '', 10, 1313, 75, 0, 2025, 1, NULL, 'Bukti tindak lanjut hasil pemantauan dan evaluasi pada EP 2)', NULL, '•	Bagian umum/Kepala IPSRS\r\n•	Kepala Sanitasi', NULL, '2025-07-01 11:05:21', 0, 'A'),
(5158, 'MFK 9 EP.1', 1, 'Rumah sakit menerapkan proses pengelolaan bencana yang meliputi poin a) hingga h) pada maksud dan tujuan di atas.', '9', '', '', 10, 1314, 75, 0, 2025, 1, 'Regulasi tentang penerapan proses pengelolaan bencana yang meliputi: \r\na)	menentukan   jenis bencana yang  kemungkinan  terjadi  dan  konsekuensi bahaya, ancaman, dan kejadian;\r\nb)	menetukan integritas struktural dan non struktural di lingkungan pelayanan pasien yang ada dan bagaimana bila terjadi bencana;\r\nc)	menentukan peran rumah sakit dalam peristiwa/kejadian tersebut;\r\nd)	menentukan strategi komunikasi pada waktu kejadian;\r\ne)	mengelola sumber daya selama kejadian termasuk sumber-sumber alternatif;\r\nf)	mengelola  kegiatan  klinis  selama  kejadian  termasuk  tempat pelayanan alternatif pada waktu kejadian; \r\ng)	mengidentifikasi dan penetapan peran serta tanggung jawab staf selama kejadian dan; n\r\nh)	proses  mengelola  keadaan  darurat  ketika terjadi  konflik  antara tanggung jawab pribadi staf dan tanggung jawab rumah sakit untuk tetap menyediakan pelayanan pasien termasuk kesehatan mental dari staf', NULL, NULL, NULL, NULL, '2025-07-01 11:05:48', 0, 'A'),
(5159, 'MFK 9 EP.2', 2, 'Rumah sakit telah mengidentifikasi risiko bencana internal dan eksternal dalam analisis kerentanan bahaya/Hazard Vulnerability Analysis (HVA) secara proaktif setiap tahun dan diintegrasikan ke  dalam daftar risiko/risk register dan profil risiko.', '9', '', '', 10, 1314, 75, 0, 2025, 1, NULL, '1)	Dokumen identifikasi risiko  bencana  internal dan eksternal rumah sakit\r\n2)	Dokumen  Analisa kerentanan bahaya/Hazard Vulnerability Analysis (HVA) secara proaktif\r\n3)	Bukti Integrasi HVA dalam risk register\r\n4)	Bukti Integrasi HVA dalam profil risiko', NULL, '•	Komite / Tim K3 RS \r\n•	Tim penanggulangan bencana RS', NULL, '2025-07-01 11:06:13', 0, 'A'),
(5160, 'MFK 9 EP.3', 3, 'Rumah sakit membuat program pengelolaan  bencana di rumah sakit berdasarkan hasil analisis kerentanan bahaya/Hazard Vulnerability Analysis (HVA) setiap tahun.', '9', '', '', 10, 1314, 75, 0, 2025, 1, 'Regulasi tentang program pengelolaan bencana berdasarkan hasil Analisa kerentanan bahaya/Hazard Vulnerability Analysis (HVA)', NULL, NULL, NULL, NULL, '2025-07-01 11:06:25', 0, 'A'),
(5161, 'MFK 9 EP.4', 4, 'Rumah sakit telah melakukan  simulasi penanggulangan bencana (disaster  drill) minimal setahun sekali termasuk debriefing.', '9', '', '', 10, 1314, 75, 0, 2025, 1, NULL, NULL, NULL, NULL, 'Simulasi penanggulangan bencana (disaster drill)', '2025-07-01 11:07:18', 0, 'A'),
