(5163, 'MFK 9 EP.6', 6, 'Rumah sakit telah menyiapkan area dekontaminasi sesuai ketentuan pada instalasi gawat darurat.', '9', '', '', 10, 1314, 75, 0, 2025, 1, NULL, NULL, 'Lihat area   dekontaminasi   sesuai ketentuan pada instalasi gawat darurat.', '•	Komite / Tim K3 RS \r\n•	Kepala IGD', NULL, '2025-07-01 11:07:45', 0, 'A'),
(5164, 'MFK 10 EP.1', 1, 'Rumah sakit menerapkan penilaian risiko prakonstruksi (PCRA) terkait rencana konstruksi, renovasi dan demolisi meliputi poin a)-j) seperti di maksud dan tujuan diatas.', '10', '', '', 10, 1315, 75, 0, 2025, 1, 'Regulasi tentang penerapan penilaian risiko prakontruksi pada rencana kontruksi, renovasi dan demolisi', NULL, NULL, NULL, NULL, '2025-07-01 11:08:09', 0, 'A');
