(5176, 'PMKP 1 EP.1', 1, 'Direktur telah menetapkan regulasi terkait  peningkatan mutu dan keselamatan pasien serta manajemen risiko', '1', '', '', 10, 1317, 76, 0, 2025, 1, 'Regulasi tentang Pedoman Peningkatan Mutu dan Keselamatan Pasien serta manajemen risiko.', NULL, NULL, NULL, NULL, '2025-07-01 11:14:32', 0, 'A'),
