(5178, 'PMKP 1 EP.3', 3, 'Komite/ Tim Penyelenggara Mutu menyusun program PMKP rumah sakit meliputi poin a - i yang telah ditetapkan Direktur rumah sakit dan disahkan oleh representatif pemilik/dewan pengawas.', '1', '', '', 10, 1317, 76, 0, 2025, 1, 'Regulasi tentang Program PMKP RS meliputi point a)–i) telah ditetapkan oleh Direktur RS dan disahkan oleh representatif pemilik/dewan pengawas.', NULL, NULL, NULL, NULL, '0000-00-00 00:00:00', 0, 'A'),
(5179, 'PMKP 1 EP.4', 4, 'Program PMKP dievaluasi dalam rapat koordinasi mellibatkan komite-komite, pimpinan rumah sakit dan kepala unit setiap triwulan untuk menjamin perbaikan mutu yang berkesinambungan.', '1', '', '', 10, 1317, 76, 0, 2025, 1, NULL, 'Bukti pelaksanaan evaluasi dalam rapat koordinasi dengan melibatkan komite-komite, pimpinan rumah sakit dan Kepala unit setiap triwulan meliputi: undangan, materi rapat, presensi dan notulen', NULL, '•	Pimpinan RS\r\n•	Komite/Tim Mutu \r\n•	Komite-komite lainnya\r\n•	Kepala Unit', NULL, '2025-07-01 11:15:24', 0, 'A'),
(5180, 'PMKP 2 EP.1', 1, 'Komite/Tim Penyelenggara Mutu terlibat dalam pemilihan indikator mutu prioritas baik ditingkat rumah sakit maupun tingkat unit layanan.', '2', '', '', 10, 1318, 76, 0, 2025, 1, NULL, 'Bukti pelaksanaan rapat tentang  pemilihan indikator mutu prioritas baik ditingkat rumah sakit maupun tingkat unit layanan meliputi: undangan, materi rapat, presensi dan notulen', NULL, '•	Komite / Tim Mutu\r\n•	Pimpinan RS\r\n•	Kepala unit kerja', NULL, '2025-07-01 11:17:05', 0, 'A'),
