(5224, 'MRMIK 1 EP.5', 5, 'Apabila terdapat program penelitian dan atau  pendidikan Kesehatan di rumah sakit, terdapat bukti bahwa data dan informasi yang mendukung asuhan pasien, pendidikan, serta riset telah  tersedia  tepat  waktu dari sumber data terkini.', '1', '', '', 10, 1329, 77, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan analisis data menjadi informasi untuk mendukung pendidikan dan penelitian', NULL, '-	Kepala/staf unit SIM-RS\r\n-	Ketua/Timkordik', NULL, '2025-07-01 11:38:33', 0, 'A'),
(5225, 'MRMIK 2 EP.1', 1, 'Terdapat bukti PPA, pimpinan rumah sakit, kepala departemen, unit layanan dan staf telah dilatih tentang prinsip pengelolaan dan penggunaan sistem informasi sesuai dengan peran dan tanggung jawab mereka.', '2', '', '', 10, 1330, 77, 0, 2025, 1, NULL, 'Bukti tentang pelatihan prinsip pengelolaan dan penggunaan informasi sistem bagi PPA, pimpinan rumah sakit, kepala departemen, unit layanan dan staf \r\nberupa TOR, undangan, daftar hadir, materi, laporan, evaluasi, sertifikat', NULL, '-	Kepala Bidang\r\n-	Kepala Unit\r\n-	Kepala/staf unit SIM-RS', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5226, 'MRMIK 2 EP.2', 2, 'Terdapat bukti bahwa data dan informasi klinis serta  non klinis diintegrasikan sesuai kebutuhan dan      digunakan dalam mendukung proses pengambilan keputusan.', '2', '', '', 10, 1330, 77, 0, 2025, 1, NULL, '1)	Bukti rapat koordinasi\r\n2)	Bukti integrasi pelayanan klinis dan non klinis dapat menggunakan: \r\n3)	data dalam pengukuran mutu pelayanan klinis prioritas, atau\r\n4)	data pelayanan dari unit pelayanan dengan data manajemen terkait', NULL, '-	Kepala Bidang\r\n-	Kepala Unit\r\n-	Kepala/staf unit SIM-RS\r\n-	Ketua/tim PMKP\r\n\r\n(Lihat juga MRMIK 13 EP 4)', NULL, '2025-07-01 11:39:14', 0, 'A'),
(5227, 'MRMIK 2.1 EP.1', 1, 'Rumah sakit menerapkan proses untuk memastikan kerahasiaan, keamanan, dan integritas data dan informasi sesuai dengan peraturan perundangan.', '2.1', '', '', 10, 1331, 77, 0, 2025, 1, 'Regulasi tentang kerahasiaan, keamanan, dan integritas data dan informasi.', NULL, NULL, NULL, NULL, '2025-07-01 11:39:29', 0, 'A'),
(5228, 'MRMIK 2.1 EP.2', 2, 'Rumah sakit menerapkan proses pemberian akses kepada staf yang berwenang untuk mengakses data dan informasi, termasuk entry  ke dalam rekam medis pasien.', '2.1', '', '', 10, 1331, 77, 0, 2025, 1, NULL, 'Bukti tentang penetapan staf yang memiliki hak akses data dan informasi termasuk mengisi rekam medis', NULL, 'Kepala/staf unit SIM-RS', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5229, 'MRMIK 2.1 EP.3', 3, 'Rumah sakit memantau kepatuhan terhadap proses ini dan mengambil tindakan ketika terjadi terjadi pelanggaran terhadap kerahasiaan, keamanan, atau integritas data.', '2.1', '', '', 10, 1331, 77, 0, 2025, 1, NULL, 'Bukti tentang hasil monitoring dan evaluasi kepatuhan staf terhadap kerahasiaan, keamanan, atau integritas data.', NULL, '-	Kepala Bidang\r\n-	Kepala Unit\r\n-	Kepala/staf unit SIM-RS', NULL, '2025-07-01 11:40:11', 0, 'A'),
(5230, 'MRMIK 2.2 EP.1', 1, 'Data dan informasi yang disimpan terlindung dari kehilangan, pencurian, kerusakan, dan penghancuran.', '2.2', '', '', 10, 1332, 77, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan perlindungan rekam medis bentuk kertas dan atau elektronik dilindungi dari kehilangan, pencurian, kerusakan, dan penghancuran.', '1)	Lihat tempat penyimpanan berkas rekam medis\r\n2)	Lihat sistem teknologi informasi, software dan hardware rekam medis elektronik', '-	Kepala/staf unit RM\r\n-	Kepala/staf unit SIM-RS', NULL, '2025-07-01 11:40:39', 0, 'A'),
(5231, 'MRMIK 2.2 EP.2', 2, 'Rumah sakit menerapkan pemantauan dan evaluasi terhadap keamanan data dan informasi.', '2.2', '', '', 10, 1332, 77, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan  monitoring dan evaluasi terhadap keamanan data dan informasi serta rencana tindaklanjutnya', NULL, '-	Kepala /staf unit RM\r\n-	Kepala/staf unit SIM-RS', NULL, '2025-07-01 11:41:02', 0, 'A'),
(5232, 'MRMIK 2.2 EP.3', 3, 'Terdapat bukti rumah sakit telah melakukan tindakan perbaikan untuk meningkatkan keamanan data dan informasi.', '2.2', '', '', 10, 1332, 77, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan rencana tindak lanjut hasil monitoring dan evaluasi', NULL, '-	Kepala /staf unit RM\r\n-	Kepala/staf unit SIM-RS', NULL, '2025-07-01 11:41:24', 0, 'A'),
(5233, 'MRMIK 3 EP.1', 1, 'Rumah sakit menerapkan pengelolaan dokumen sesuai dengan butir a - h dalam maksud dan tujuan.', '3', '', '', 10, 1333, 77, 0, 2025, 1, 'Bukti regulasi tentang pengelolaan dokumen sesuai dengan butir a)-h) dalam maksud dan tujuan', NULL, NULL, NULL, NULL, '2025-07-01 13:10:07', 0, 'A'),
(5234, 'MRMIK 3 EP.2', 2, 'Rumah sakit memiliki dan menerapkan format yang seragam untuk semua dokumen sejenis sesuai dengan ketentuan rumah sakit.', '3', '', '', 10, 1333, 77, 0, 2025, 1, NULL, 'Bukti rumah sakit memiliki dan menerapkan format yang seragam', NULL, '-	Kepala /staf unit RM\r\n-	Kepala/staf unit SIM-RS', NULL, '2025-07-01 13:10:33', 0, 'A'),
(5235, 'MRMIK 3 EP.3', 3, 'Rumah sakit  telah  memiliki   dokumen   internal mencakup butir a - c dalam maksud dan tujuan.', '3', '', '', 10, 1333, 77, 0, 2025, 1, NULL, 'Bukti tersedia dokumen internal mencakup butir a)-c) dalam maksud dan tujuan.', NULL, '-	Kepala /staf unit RM\r\n-	Kepala/staf unit SIM-RS', NULL, '2025-07-01 13:11:01', 0, 'A'),
(5236, 'MRMIK 4 EP.1', 1, 'Terdapat bukti bahwa penyebaran data dan informasi memenuhi kebutuhan internal dan eksternal  rumah sakit sesuai dengan yang tercantum dalam maksud dan tujuan.', '4', '', '', 10, 1334, 77, 0, 2025, 1, NULL, 'Bukti tentang laporan data dan informasi telah disampaikan sesuai kebutuhan pengguna internal dan eksternal rumah sakit', NULL, '-	Kepala /staf unit RM\r\n-	Kepala/staf unit SIM-RS', NULL, '2025-07-01 13:11:39', 0, 'A'),
(5237, 'MRMIK 4 EP.2', 2, 'Terdapat proses yang memastikan bahwa data dan informasi yang dibutuhkan untuk perawatan pasien      telah diterima tepat waktu dan sesuai format yang seragam dan sesuai dengan kebutuhan.', '4', '', '', 10, 1334, 77, 0, 2025, 1, NULL, 'Bukti laporan tentang data yang diberikan tepat waktu dan menggunakan format yang ditetapkan.', NULL, '-	Kepala /staf unit RM\r\n-	Kepala/staf unit SIM-RS', NULL, '2025-07-01 13:12:00', 0, 'A'),
(5238, 'MRMIK 5 EP.1', 1, 'Rumah sakit telah menetapkan regulasi tentang penyelenggaraan rekam medis di rumah sakit.', '5', '', '', 10, 1335, 77, 0, 2025, 1, 'Regulasi tentang Pedoman Rekam Medis', NULL, NULL, NULL, NULL, '2025-07-01 13:12:14', 0, 'A'),
(5239, 'MRMIK 5 EP.2', 2, 'Rumah sakit menetapkan unit penyelenggara rekam medis dan 1 (satu) orang yang kompeten mengelola rekam medis.', '5', '', '', 10, 1335, 77, 0, 2025, 1, 'Penetapan unit kerja yang mengelola rekam medis dalam susunan organisasi dan tatakerja (SOTK), disertai:\r\n1)	Pedoman Pengorganisasian\r\n2)	Pedoman Pelayanan Rekam Medis\r\n3)	Program\r\n\r\nKepala unit rekam medik adalah profesi yang kompeten mengelola Rekam Bukti tentang kualifikasi dan kewenangan   pimpinan unit rekam medis sesuai persyaratan jabatan meliputi: Keputusan pengangkatan, ijazah, sertifikasi', NULL, NULL, NULL, NULL, '2025-07-01 13:12:32', 0, 'A'),
(5240, 'MRMIK 5 EP.3', 3, 'Rumah Sakit menerapkan penyelenggaraan Rekam Medis yang dilakukan sejak pasien masuk  sampai  pasien pulang, dirujuk, atau meninggal.', '5', '', '', 10, 1335, 77, 0, 2025, 1, NULL, 'Bukti penyelenggaraan berkas Rekam Medis sejak pasien masuk sampai pasien pulang, dirujuk, atau meninggal', NULL, 'Kepala /staf unit RM', NULL, '2025-07-01 13:13:14', 0, 'A'),
(5241, 'MRMIK 5 EP.4', 4, 'Pengelolaan rekam medis yang menjamin keamanan dan kerahasiaannya, melalui penjaminan mutu secara berkala yang dilakukan oleh tim reviu yang ditetapkan oleh pimpinan rumah sakit', '5', '', '', 10, 1335, 77, 0, 2025, 1, NULL, NULL, '-	Lihat ruang penyimpanan rekam medis di unit rekam medis\r\n-	Lihat penyimpanan saat rekam medis berada di unit pelayanan\r\n-	Lihat sistem teknologi informasi, software dan hardware rekam medis elektronik', NULL, NULL, '2025-07-01 13:13:35', 0, 'A'),
(5242, 'MRMIK 6 EP.1', 1, 'Terdapat bukti bahwa setiap pasien memiliki rekam medik dengan satu nomor RM sesuai sistem penomoran yang ditetapkan.', '6', '', '', 10, 1336, 77, 0, 2025, 1, NULL, 'Bukti tentang setiap pasien memiliki 1 (satu) nomor rekam medis', NULL, NULL, NULL, '2025-07-01 13:14:03', 0, 'A'),
(5243, 'MRMIK 6 EP.2', 2, 'Rekam medis rawat jalan, rawat inap,  gawat  darurat  dan pemeriksaan penunjang disusun dan diisi sesuai ketetapan rumah sakit.', '6', '', '', 10, 1336, 77, 0, 2025, 1, NULL, 'Bukti pengaturan urutan susunan berkas rekam medis, untuk rawat jalan, rawat inap, gawat darurat dan pemeriksaan penunjang.', NULL, NULL, NULL, '2025-07-01 13:14:16', 0, 'A'),
(5244, 'MRMIK 6 EP.3', 3, 'Terdapat bukti bahwa formulir rekam medis dievaluasi dan diperbaharui (terkini) sesuai dengan kebutuhan dan secara periodik.', '6', '', '', 10, 1336, 77, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan evaluasi dan pembaharuan (terkini) formulir/dokumen rekam medis.\r\n?	Periode evaluasi ditetapkan dalam regulasi.\r\n?	Bukti evaluasi dalam forum rapat.\r\n?	Bukti rapat meliputi : undangan, materi rapat, daftar hadir dan notulen', NULL, 'Ketua/anggota tim review', NULL, '2025-07-01 13:14:43', 0, 'A'),
(5245, 'MRMIK 7 EP.1', 1, 'Terdapat bukti rekam medis pasien  telah  berisi informasi yang sesuai dengan ketetapan rumah  sakit  dan peraturan perundangan yang berlaku.', '7', '', '', 10, 1337, 77, 0, 2025, 1, NULL, 'Bukti dalam rekam medis pasien telah berisi informasi yang sesuai dengan ketetapan rumah sakit dan peraturan perundangan yang berlaku', NULL, NULL, NULL, '2025-07-01 13:15:01', 0, 'A'),
(5246, 'MRMIK 7 EP.2', 2, 'Terdapat bukti rekam medis  pasien  mengandung informasi yang memadai sesuai butir   a sampai f pada  maksud dan tujuan.', '7', '', '', 10, 1337, 77, 0, 2025, 1, NULL, 'Bukti dalam rekam medis pasien mengandung informasi yang memadai meliputi:\r\na)	Mengidentifikasi pasien;\r\nb)	Mendukung diagnosis;\r\nc)	Justifikasi/dasar pemberian pengobatan;\r\nd)	Mendokumentasikan hasil pemeriksaan dan hasil pengobatan;\r\ne)	Memuat ringkasan pasien pulang (discharge summary); dan\r\nf)	Meningkatkan kesinambungan pelayanan diantara Profesional Pemberi Asuhan (PPA).', NULL, NULL, NULL, '2025-07-01 13:16:20', 0, 'A'),
(5247, 'MRMIK 8 EP.1', 1, 'PPA mencantumkan identitas secara jelas pada saat mengisi RM.', '8', '', '', 10, 1338, 77, 0, 2025, 1, NULL, 'Bukti dalam rekam medis PPA yang mengisi rekam medis mencantumkan nama dan tanda tangan.', NULL, NULL, NULL, '0000-00-00 00:00:00', 0, 'A'),
(5248, 'MRMIK 8 EP.2', 2, 'Tanggal dan waktu penulisan setiap catatan  dalam rekam medis pasien dapat diidentifikasi.', '8', '', '', 10, 1338, 77, 0, 2025, 1, NULL, 'Bukti dalam rekam medis tentang tanggal, dan jam pengisian rekam medis', NULL, NULL, NULL, '2025-07-01 13:17:05', 0, 'A'),
(5249, 'MRMIK 8 EP.3', 3, 'Terdapat prosedur koreksi penulisan dalam pengisian RM elektronik', '8', '', '', 10, 1338, 77, 0, 2025, 1, 'Bukti tentang regulasi prosedur koreksi penulisan dalam pengisian RM elektronik dan non elektronik', NULL, NULL, NULL, NULL, '2025-07-01 13:17:45', 0, 'A'),
(5250, 'MRMIK 8 EP.4', 4, 'Telah dilakukan pemantauan dan evaluasi terhadap penulisan identitas, tanggal dan waktu penulisan catatan pada rekam medis pasien serta koreksi penulisan catatan dalam rekam medis, dan hasil evaluasi yang ada telah digunakan sebagai dasar upaya perbaikan di rumah sakit.', '8', '', '', 10, 1338, 77, 0, 2025, 1, NULL, '1)	Bukti tentang pelaksanaan review yang ber fokus pada penulisan identitas, tanggal dan waktu penulisan catatan pada rekam medis pasien serta koreksi penulisan catatan dalam rekam medis.\r\n2)	Bukti rencana tindak lanjut', NULL, NULL, NULL, '2025-07-01 13:18:14', 0, 'A'),
(5251, 'MRMIK 9 EP.1', 1, 'Penggunaan kode diagnosis, kode prosedur, singkatan dan simbol sesuai dengan ketetapan rumah sakit.', '9', '', '', 10, 1339, 77, 0, 2025, 1, 'Bukti tentang regulasi: \r\n1)	Standardisasi kode diagnosis, kode prosedur/tindakan, definisi, \r\n2)	simbol yang digunakan dan yang tidak boleh digunakan, \r\n3)	singkatan yang digunakan dan yang tidak boleh digunakan', NULL, NULL, NULL, NULL, '2025-07-01 13:18:31', 0, 'A'),
(5252, 'MRMIK 9 EP.2', 2, 'Dilakukan evaluasi secara berkala penggunaan kode diagnosis, kode prosedur, singkatan dan simbol yang berlaku di rumah sakit dan hasilnya digunakan sebagai upaya tindak lanjut untuk perbaikan.', '9', '', '', 10, 1339, 77, 0, 2025, 1, NULL, '1)	Bukti tentang pelaksanaan monitoring dan evaluasi secara berkala terhadap  regulasi yang meliputi kode diagnosis, kode prosedur/ tindakan, definisi, simbol yang digunakan dan yang tidak boleh digunakan, singkatan yang digunakan dan yang tidak boleh digunakan. \r\n2)	Bukti tentang rencana tindaklanjut untuk perbaikan', NULL, '-	Direktur/pimpinan RS\r\n-	Ketua/anggota tim review', NULL, '2025-07-01 13:23:10', 0, 'A'),
(5253, 'MRMIK 10 EP.1', 1, 'Rumah sakit menentukan otoritas pengisian rekam medis termasuk isi dan format rekam medis.', '10', '', '', 10, 1340, 77, 0, 2025, 1, 'Regulasi tentang penetapan individu yang berwenang mengisi rekam medis', NULL, NULL, NULL, NULL, '2025-07-01 13:23:24', 0, 'A'),
(5254, 'MRMIK 10 EP.2', 2, 'Rumah Sakit menentukan hak akses dalam pelepasan informasi rekam medis', '10', '', '', 10, 1340, 77, 0, 2025, 1, 'Regulasi tentang pelepasan informasi (rahasia kedokteran), termasuk hak pasien mendapatkan isi rekam medis dalam bentuk ringkasan rekam medis', NULL, NULL, NULL, NULL, '2025-07-01 13:23:38', 0, 'A'),
(5255, 'MRMIK 10 EP.3', 3, 'Rumah sakit menjamin otentifikasi, keamanan dan kerahasiaan data rekam medis baik kertas maupun elektronik sebagai bagian dari hak pasien.', '10', '', '', 10, 1340, 77, 0, 2025, 1, NULL, 'Bukti dalam rekam medis tentang hanya individu yang mendapat otoritas untuk mengisi rekam medis.\r\nDibuktikan melalui evaluasi pengisian rekam medis hanya oleh staf klinis yang telah ditetapkan dalam regulasi tentang penetapan tenaga kesehatan yang memiliki hak akses ke rekam medis', NULL, 'Kepala /staf unit RM', NULL, '2025-07-01 13:24:06', 0, 'A'),
(5256, 'MRMIK 11 EP.1', 1, 'Rumah sakit memiliki regulasi jangka waktu penyimpanan berkas rekam medis (kertas/elektronik), serta data dan informasi lainnya terkait dengan pasien dan prosedur pemusnahannya sesuai dengan peraturan perundangan.', '11', '', '', 10, 1341, 77, 0, 2025, 1, 'Regulasi tentang penetapan jangka waktu penyimpanan berkas rekam medis pasien dan prosedur pemusnahannya', NULL, NULL, NULL, NULL, '2025-07-01 13:24:24', 0, 'A'),
(5257, 'MRMIK 11 EP.2', 2, 'Dokumen, data dan/informasi terkait pasien dimusnahkan setelah melampaui periode waktu penyimpanan sesuai dengan peraturan perundang- undangan dengan prosedur yang tidak membahayakan keamanan dan kerahasiaan.', '11', '', '', 10, 1341, 77, 0, 2025, 1, NULL, '1)	Bukti pelaksanaan tentang pemusnahan  \r\nberkas rekam medis\r\n2)	Bukti tentang berita acara pemusnahan rekam medis', NULL, 'Kepala/staf unit RM', NULL, '2025-07-01 13:24:45', 0, 'A'),
(5258, 'MRMIK 11 EP.3', 3, 'Dokumen, data dan/atau informasi tertentu terkait pasien yang bernilai guna, disimpan abadi (permanen) sesuai dengan ketetapan rumah sakit.', '11', '', '', 10, 1341, 77, 0, 2025, 1, NULL, 'Bukti dokumen, data dan/atau informasi tertentu terkait pasien yang bernilai guna, disimpan permanen.', NULL, 'Kepala /staf unit RM', NULL, '2025-07-01 13:25:08', 0, 'A'),
(5259, 'MRMIK 12 EP.1', 1, 'Rumah sakit menetapkan komite/tim rekam medis.', '12', '', '', 10, 1342, 77, 0, 2025, 1, 'Bukti tentan regulasi :\r\n1)	penetapan tim review rekam medis\r\n2)	pedoman kerja; dan\r\n3)	program kerja', NULL, NULL, NULL, NULL, '2025-07-01 13:25:22', 0, 'A'),
(5260, 'MRMIK 12 EP.2', 2, 'Komite/tim secara berkala melakukan  pengkajian  rekam medis pasien secara berkala setiap tahun dan menggunakan sampel yang mewakili (rekam medis pasien yang masih dirawat dan pasien yang sudah pulang).', '12', '', '', 10, 1342, 77, 0, 2025, 1, NULL, '1)	Bukti tentang pelaksanaan review rekam medis secara berkala.\r\n2)	Komite/Tim reviu menetapkan besaran sampel yang akan direviu, yang meliputi  rekam medis pasien yang masih dirawat dan pasien yang sudah pulang dengan menggunakan kaidah statistik.', NULL, 'Komite/Tim reviu', NULL, '2025-07-01 13:25:48', 0, 'A'),
(5261, 'MRMIK 12 EP.3', 3, 'Fokus pengkajian paling sedikit mencakup pada ketepatan waktu, keterbacaan, kelengkapan  rekam medis dan isi rekam medis sesuai dengan peraturan perundangan.', '12', '', '', 10, 1342, 77, 0, 2025, 1, NULL, '1)	Bukti tentang pelaksanaan review yang ber fokus pada ketepatan waktu, keterbacaan dan kelengkapan rekam medis.\r\n2)	Tim reviu menetapkan form sebagai dasar menilai reviu, termasuk kriteria kelengkapan rekam medis', NULL, 'Ketua komite/tim rekam medis', NULL, '2025-07-01 13:26:15', 0, 'A'),
(5262, 'MRMIK 12 EP.4', 4, 'Hasil pengkajian yang dilakukan oleh komite/tim rekam medis dilaporkan kepada pimpinan rumah sakit dan dibuat upaya perbaikan.', '12', '', '', 10, 1342, 77, 0, 2025, 1, NULL, '1)	Bukti laporan tentang hasil review\r\n2)	Bukti  tentang pengiriman laporan review ke direktur rumah sakit', NULL, '-	Ketua komite/tim rekam medis\r\n-	Pimpinan Rumah Sakit', NULL, '2025-07-01 13:26:35', 0, 'A'),
(5263, 'MRMIK 13 EP.1', 1, 'Rumah sakit menetapkan regulasi tentang penyelenggaraan teknologi informasi kesehatan', '13', '', '', 10, 1343, 77, 0, 2025, 1, 'Regulasi tentang penyelenggaraan teknologi informasi kesehatan', NULL, NULL, NULL, NULL, '2025-07-01 13:27:01', 0, 'A'),
(5264, 'MRMIK 13 EP.2', 2, 'Rumah sakit menerapkan SIMRS sesuai dengan ketetapan dan peraturan perundangan yang berlaku.', '13', '', '', 10, 1343, 77, 0, 2025, 1, NULL, 'Bukti penerapan SIMRS yang memproses dan mengintegrasikan seluruh alur proses pelayanan Rumah Sakit dalam bentuk jaringan koordinasi, pengumpulan data, pelaporan dan prosedur administrasi untuk memperoleh informasi secara tepat dan akurat.', NULL, '-	Kepala Unit rekam medis\r\n-	Kepala unit SIMRS\r\n-	Pimpinan Rumah Sakit', NULL, '2025-07-01 13:27:35', 0, 'A'),
(5265, 'MRMIK 13 EP.3', 3, 'Rumah sakit menetapkan unit yang bertanggung jawab sebagai penyelenggara SIMRS dan dipimpim oleh staf kompeten.', '13', '', '', 10, 1343, 77, 0, 2025, 1, '1)	Regulasi unit kerja yang mengelola SIM-RS dalam susunan organisasi dan tatakerja rumah sakit (SOTK)\r\n2)	Pedoman pengorganisasian unit SIM-RS', NULL, NULL, NULL, NULL, '0000-00-00 00:00:00', 0, 'A'),
(5266, 'MRMIK 13 EP.4', 4, 'Data serta informasi klinis dan non klinis diintegrasikan sesuai dengan kebutuhan untuk mendukung pengambilan keputusan', '13', '', '', 10, 1343, 77, 0, 2025, 1, NULL, '1)	Bukti rapat meliputi undangan, materi rapat, daftar hadir dan notulen \r\n2)	Bentuk integrasi pelayanan klinis dan non klinis dapat menggunakan: \r\n3)	data dalam pengukuran mutu pelayanan klinis prioritas, atau\r\n4)	data pelayanan dari unit pelayanan dengan data manajemen terkait', NULL, '-	Kepala Unit rekam medis\r\n-	Kepala unit SIMRS\r\n-	Pimpinan Rumah Sakit\r\n\r\n(Lihat juga MRMIK 2 EP 2)', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5267, 'MRMIK 13 EP.5', 5, 'Rumah sakit telah menerapkan proses untuk menilai efektifitas sistem rekam medis elektronik  dan  melakukan upaya perbaikan terkait hasil penilaian yang ada.', '13', '', '', 10, 1343, 77, 0, 2025, 1, NULL, '1)	Bukti tentang pelaksanaan monitoring dan evaluasi efektifitas sistem rekam medis elektronik\r\n2)	Bukti tentang rencana tindak lanjut untuk perbaikan', NULL, '-	Kepala/Staf Unit rekam medis\r\n-	Kepala/Staf unit SIMRS', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5268, 'MRMIK 13.1 EP.1', 1, 'Terdapat prosedur yang harus dilakukan jika terjadi waktu henti sistem data (down time) untuk mengatasi masalah pelayanan.', '13.1', '', '', 10, 1344, 77, 0, 2025, 1, 'Bukti tentang regulasi waktu henti sistem data (down time)', NULL, NULL, NULL, NULL, '2025-07-01 13:31:07', 0, 'A'),
(5269, 'MRMIK 13.1 EP.2', 2, 'Staf dilatih dan memahami perannya di dalam prosedur penanganan waktu henti sistem data (down time), baik yang terencana maupun yang tidak terencana.', '13.1', '', '', 10, 1344, 77, 0, 2025, 1, NULL, 'Bukti pelaksanaan pelatihan staf tentang prosedur penanganan waktu henti sistem data (down time) berupa TOR, undangan, daftar hadir, materi, laporan, evaluasi, sertifikat', NULL, 'Kepala/staf unit SIMRS', NULL, '0000-00-00 00:00:00', 0, 'A');
INSERT INTO `accreditation_instrument` (`instrument_id`, `instrument_reference_code`, `instrument_order_id`, `instrument_name`, `instrument_objective`, `instrument_material`, `instrument_document`, `instrument_maximum_score`, `instrument_standard_id`, `instrument_chapter_id`, `instrument_class_id`, `instrument_version`, `instrument_institution_group_id`, `instrument_r`, `instrument_d`, `instrument_o`, `instrument_w`, `instrument_s`, `instrument_update`, `instrument_user_id`, `instrument_record_status`) VALUES
(5270, 'MRMIK 13.1 EP.3', 3, 'Rumah sakit melakukan evaluasi  pasca  terjadinya  waktu henti sistem data (down time) dan menggunakan informasi dari data tersebut untuk persiapan dan perbaikan apabila terjadi waktu henti (down time) berikutnya.', '13.1', '', '', 10, 1344, 77, 0, 2025, 1, NULL, 'Bukti pelaksanaan monitoring dan evaluasi pasca terjadinya waktu henti sistem data (down time) dan bukti rencana tindak lanjutnya', NULL, 'Kepala/staf unit SIMRS', NULL, '2025-07-01 13:32:14', 0, 'A'),
(5271, 'PPI 1 EP.1', 1, 'Direktur rumah sakit telah menetapkan regulasi PPI meliputi a - m pada gambaran umum.', '1', '', '', 10, 1345, 78, 0, 2025, 1, 'Regulasi tentang PPI meliputi: \r\na)	Penyelenggaraan PPI di Rumah Sakit \r\nb)	Program PPI ?\r\nc)	Pengkajian Risiko ?\r\nd)	Peralatan medis dan/atau Bahan Medis Habis Pakai (BMHP) ?\r\ne)	Kebersihan lingkungan ?\r\nf)	Manajemen linen ?\r\ng)	Limbah infeksius ?\r\nh)	Pelayanan makanan ?\r\ni)	Risiko infeksi pada konstruksi dan renovasi ?\r\nj)	Penularan infeksi ?\r\nk)	Kebersihan Tangan ?\r\nl)	Peningkatan mutu dan program edukasi ?\r\nm)	Edukasi, Pendidikan dan Pelatihan', NULL, NULL, NULL, NULL, '2025-07-01 13:33:47', 0, 'A'),
(5272, 'PPI 1 EP.2', 2, 'Direktur rumah sakit telah menetapkan  komite/tim  PPI untuk untuk mengelola dan mengawasi  kegiatan PPI di rumah sakit.', '1', '', '', 10, 1345, 78, 0, 2025, 1, 'Regulasi tentang penetapan komite/ tim PPI dilengkapi dengan Pedoman Kerja dan Program Kerja.', NULL, NULL, NULL, NULL, '2025-07-01 13:34:00', 0, 'A'),
(5273, 'PPI 1 EP.3', 3, 'Rumah sakit telah menerapkan mekanisme koordinasi yang melibatkan pimpinan rumah sakit  dan  komite/tim PPI untuk melaksanakan program PPI sesuai dalam maksud dan tujuan.', '1', '', '', 10, 1345, 78, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan koordinasi yang melibatkan pimpinan rumah sakit dan komite/tim PPI untuk melaksanakan program PPI. Koordinasi tersebut meliputi:\r\na)	Menetapkan kriteria untuk mendefinisikan infeksi terkait pelayanan kesehatan; \r\nb)	Menetapkan metode pengumpulan data (surveilans); ?\r\nc)	Membuat strategi untuk menangani risiko PPI, dan pelaporannya; dan ?\r\nd)	Berkomunikasi dengan semua unit untuk memastikan ?bahwa program berkelanjutan dan proaktif.', NULL, '-	Komite/Tim PPI\r\n-	IPCN', NULL, '2025-07-01 13:34:29', 0, 'A'),
(5274, 'PPI 1 EP.4', 4, 'Direktur rumah sakit memberikan dukungan sumber daya terhadap penyelenggaraan kegiatan PPI meliputi namun tidak terbatas pada maksud dan tujuan.', '1', '', '', 10, 1345, 78, 0, 2025, 1, NULL, 'Bukti tentang dukungan direktur RS terhadap sumber daya, meliputi tapi tidak terbatas pada: \r\na)	Ketersedian anggaran; ?\r\nb)	Sumber daya manusia yang terlatih; ?\r\nc)	Sarana prasarana dan perbekalan, untuk mencuci ?tangan berbasis alkohol (handrub), dan mencuci tangan dengan air mengalir (handwash), kantong pembuangan sampah infeksius dll; \r\nd)	Sistem manajemen informasi untuk mendukung penelusuran risiko, angka, dan tren infeksi yang terkait dengan pelayanan kesehatan; dan ?\r\ne)	Sarana penunjang lainnya untuk menunjang kegiatan PPI yang dapat mempermudah kegiatan PPI.', '-	Lihat kelengkapan fasilitas pendukung penyelenggaraan kegiatan PPI', '-	Komite/Tim PPI\r\n-	IPCN', NULL, '2025-07-01 13:35:25', 0, 'A'),
(5275, 'PPI 1.1 EP.1', 1, 'Rumah sakit menetapkan perawat PPI/IPCN purna waktu dan IPCLN berdasarkan jumlah dan kualifikasi sesuai ukuran rumah sakit, kompleksitas kegiatan, tingkat risiko, cakupan program dan sesuai dengan peraturan perundang-undangan.', '1.1', '', '', 10, 1346, 78, 0, 2025, 1, 'Regulasi tentang: \r\na)	Penetapan perawat PPI/IPCN purna waktu dan IPCLN \r\nb)	Jumlah dan kualifikasi sesuai dengan peraturan perundang-undangan.', NULL, NULL, NULL, NULL, '2025-07-01 13:35:38', 0, 'A'),
(5276, 'PPI 1.1 EP.2', 2, 'Ada bukti perawat PPI/IPCN melaksanakan supervisi pada semua kegiatan pencegahan dan pengendalian infeksi di rumah sakit.', '1.1', '', '', 10, 1346, 78, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan supervisi oleh perawat PPI/IPCN.', NULL, '-	IPCN\r\n-	Kepala Unit/Kepala Ruangan\r\n-	Kepala Instalasi', NULL, '2025-07-01 13:36:06', 0, 'A'),
(5277, 'PPI 2 EP.1', 1, 'Rumah sakit menetapkan kebijakan Program PPI yang terdiri dari kewaspadaan standar dan kewaspadaan transmisi sesuai maksud dan tujuan diatas.', '2', '', '', 10, 1347, 78, 0, 2025, 1, 'Regulasi tentang Program PPI yang terdiri dari kewaspadaan standar dan kewaspadaan transmisi.', NULL, NULL, NULL, NULL, '2025-07-01 13:37:33', 0, 'A'),
(5278, 'PPI 2 EP.2', 2, 'Rumah sakit melakukan  evaluasi  pelaksanaan  program PPI.', '2', '', '', 10, 1347, 78, 0, 2025, 1, NULL, 'Bukti tentang:\r\na)	Hasil evaluasi pelaksanaan propram PPI.\r\nb)	Rencana tindak lanjut', NULL, '-	Komite/Tim PPI\r\n-	IPCN', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5279, 'PPI 3 EP.1', 1, 'Rumah sakit secara proaktif telah melaksanakan pengkajian risiko pengendalian infeksi (ICRA) setiap tahunnya terhadap tingkat dan kecenderungan infeksi layanan kesehatan sesuai poin   a) sampai k) pada  maksud  dan tujuan  dan  selanjutnya  menggunakan   data  tersebut untuk membuat dan  menentukan  prioritas/fokus pada Program PPI.', '3', '', '', 10, 1348, 78, 0, 2025, 1, NULL, '1)	Bukti tentang pengkajian risiko pengendalian infeksi (ICRA) setiap tahunnya, meliputi:\r\na)	Infeksi-infeksi yang penting secara epidemiologis yang merupakan data surveilans; ?\r\nb)	Proses kegiatan di area-area yang berisiko tinggi terjadinya infeksi; ?\r\nc)	Pelayanan yang menggunakan peralatan yang berisiko infeksi; ?\r\nd)	Prosedur/tindakan-tindakan berisiko tinggi; ?\r\ne)	Pelayanan distribusi linen bersih dan kotor; ?\r\nf)	Pelayanan sterilisasi alat; ?\r\ng)	Kebersihan permukaan dan lingkungan; ?\r\nh)	Pengelolaan linen/laundri; ?\r\ni)	Pengelolaan sampah; ?\r\nj)	Penyediaan makanan; dan ?\r\nk)	Pengelolaan kamar jenazah ?\r\n2)	Program PPI prioritas/fokus berdasarkan hasil kajian risiko', NULL, '-	Komite/Tim PPI\r\n-	IPCN', NULL, '2025-07-01 13:38:42', 0, 'A'),
(5280, 'PPI 3 EP.2', 2, 'Rumah sakit telah melaksanakan surveilans  data  secara periodik dan dianalisis setiap triwulan meliputi a)-f) dalam maksud dan tujuan.', '3', '', '', 10, 1348, 78, 0, 2025, 1, NULL, '1)	Bukti tentang pelaksanaan surveilans data secara periodic meliputi:\r\na)	Saluran pernapasan seperti prosedur dan tindakan terkait intubasi, bantuan ventilasi mekanis, trakeostomi, dan lain-lain;\r\nb)	Saluran kemih seperti kateter, pembilasan urine, dan lain lain;\r\nc)	Alat invasif intravaskular, saluran vena verifer, saluran vena sentral, dan lain-lain ?\r\nd)	Lokasi operasi, perawatan, pembalutan luka, prosedur aseptik, dan lain-lain; ?\r\ne)	Penyakit dan organisme yang penting dari sudut epidemiologik seperti Multidrug Resistant Organism dan infeksi yang virulen; dan\r\nf)	Timbul nya penyakit infeksi baru atau timbul kembali penyakit infeksi di masyarakat (Emerging and or Re- Emerging Disease). ?\r\n2)	Data surveilans dianalisis setiap triwulan', NULL, '-	Komite/Tim PPI\r\n-	IPCN', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5281, 'PPI 4 EP.1', 1, 'Rumah sakit telah menerapkan pengolahan sterilisasi mengikuti peraturan perundang-undangan.', '4', '', '', 10, 1349, 78, 0, 2025, 1, NULL, 'Bukti tentang pengelolaan sterilisasi mengikuti peraturan perundang-undangan.', NULL, '-	IPCN\r\n-	Kepala/staf CSSD', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5282, 'PPI 4 EP.2', 2, 'Staf yang memroses peralatan medis dan/atau BMHP telah diberikan pelatihan dalam pembersihan, desinfeksi, dan sterilisasi serta mendapat pengawasan.', '4', '', '', 10, 1349, 78, 0, 2025, 1, NULL, 'Bukti tentang :\r\na)	Pelaksanaan pelatihan staf tentang pembersihan, desinfeksi, dan sterilisasi, berupa: TOR, laporan pelaksanaan, daftar hadir, dan evaluasi.\r\nb)	Pelaksanaan supervisi', NULL, '-	IPCN\r\n-	Kepala/staf CSSD', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5283, 'PPI 4 EP.3', 3, '  Metode pembersihan, desinfeksi, dan sterilisasi dilakukan secara seragam di semua area di  rumah  sakit.', '4', '', '', 10, 1349, 78, 0, 2025, 1, NULL, NULL, 'Lihat proses pembersihan, desinfeksi, dan sterilisasi dilakukan secara seragam di semua area di rumah sakit.', '-	IPCN\r\n-	Kepala/staf CSSD\r\n-	Kepala Unit/Staf unit pelayanan', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5284, 'PPI 4 EP.4', 4, 'Penyimpanan peralatan medis dan/atau BMHP bersih dan steril disimpan dengan baik di area penyimpanan yang ditetapkan, bersih dan kering dan terlindungi dari debu, kelembaban, serta perubahan suhu  yang  ekstrem.', '4', '', '', 10, 1349, 78, 0, 2025, 1, NULL, NULL, 'Lihat tempat penyimpanan peralatan medis dan/atau BMHP bersih dan steril.', '-	IPCN\r\n-	Kepala/staf CSSD\r\n-	Kepala Unit/Staf unit pelayanan', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5285, 'PPI 4 EP.5', 5, 'Bila sterilisasi dilaksanakan di luar rumah sakit harus dilakukan oleh lembaga yang memiliki sertifikasi mutu dan ada kerjasama yang menjamin kepatuhan proses sterilisasi sesuai dengan peraturan perundang- undangan.', '4', '', '', 10, 1349, 78, 0, 2025, 1, NULL, 'ukti tentang:\r\na)	MOU dengan pihak ketiga\r\nb)	Sertifikasi mutu', NULL, '-	Komite/Tim PPI\r\n-	IPCN', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5286, 'PPI 4.1 EP.1', 1, 'Rumah sakit menetapkan peralatan medis dan/atau BMHP yang dapat digunakan ulang meliputi a) sampai g) dalam maksud dan tujuan.', '4.1', '', '', 10, 1350, 78, 0, 2025, 1, 'Regulasi tentang BMHP yang dapat digunakan ulang meliputi:\r\na)	Alat dan material yang dapat dipakai kemba\r\nb)	Jumlah maksimum pemakaian ulang dari setiap alat secara spesifik;?\r\nc)	Identifikasi kerusakan akibat pemakaian dan keretakan yang menandakan alat tidak dapat dipakai; \r\nd)	Proses pembersihan setiap alat yang segera dilakukan sesudah pemakaian dan mengikuti protokol yang jelas; \r\ne)	Pencantuman identifikasi pasien pada bahan medis habis pakai untuk hemodialisis;\r\nf)	Pencatatan bahan medis habis pakai yang reuse di rekam medis; dan\r\ng)	Evaluasi untuk menurunkan risiko infeksi bahan medis habis pakai yang di-reuse.', NULL, NULL, NULL, NULL, '0000-00-00 00:00:00', 0, 'A'),
(5287, 'PPI 4.1 EP.2', 2, 'Rumah sakit menggunakan proses terstandardisasi untuk menentukan kapan peralatan medis dan/atau BMHP yang digunakan ulang sudah tidak aman atau tidak layak digunakan ulang.', '4.1', '', '', 10, 1350, 78, 0, 2025, 1, 'Regulasi tentang standardisasi BMHP yang digunakan ulang.', NULL, NULL, NULL, NULL, '0000-00-00 00:00:00', 0, 'A'),
(5288, 'PPI 4.1 EP.3', 3, 'Ada bukti pemantauan, evaluasi, dan tindak lanjut pelaksanaan penggunaan kembali (reuse) peralatan medis dan/atau BMHP meliputi a) sampai g) dalam maksud dan tujuan.', '4.1', '', '', 10, 1350, 78, 0, 2025, 1, NULL, 'Bukti tentang: \r\n1)	Pelaksanaan supervisi\r\n2)	Tindak lanjut hasil supervise BMHP, meliputi:\r\na)	Alat dan material yang dapat dipakai kembali;?\r\nb)	Jumlah maksimum pemakaian ulang dari setiap alat secara spesifik;?\r\nc)	Identifikasi kerusakan akibat pemakaian dan keretakan yang menandakan alat tidak dapat dipakai; \r\nd)	Proses pembersihan setiap alat yang segera dilakukan sesudah pemakaian dan mengikuti protokol yang jelas; \r\ne)	Pencantuman identifikasi pasien pada bahan medis habis pakai untuk hemodialisis;\r\nf)	Pencatatan bahan medis habis pakai yang reuse di rekam medis; dan\r\ng)	Evaluasi untuk menurunkan risiko infeksi bahan medis habis pakai yang di-reuse.', NULL, NULL, NULL, '0000-00-00 00:00:00', 0, 'A'),
(5289, 'PPI 5 EP.1', 1, 'Rumah sakit menerapkan prosedur pembersihan dan disinfeksi permukaan dan lingkungan sesuai  standar PPI', '5', '', '', 10, 1351, 78, 0, 2025, 1, NULL, NULL, 'Lihat pelaksanaan pembersihan dan disinfeksi permukaan dan lingkungan.', '-	Komite/Tim PPI\r\n-	IPCN\r\n-	Penanggungjawab Kesling', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5290, 'PPI 5 EP.2', 2, 'Rumah sakit melaksanakan pembersihan dan  desinfeksi tambahan di area berisiko tinggi  berdasarkan hasil pengkajian risiko', '5', '', '', 10, 1351, 78, 0, 2025, 1, NULL, 'Bukti hasil pengkajian risiko sebagai dasar pembersihan dan desinfeksi tambahan di area berisiko tinggi', 'Lihat pelaksanaan pembersihan dan desinfeksi tambahan di area berisiko tinggi', '-	Komite/Tim PPI\r\n-	IPCN\r\n-	Penanggungjawab Kesling', NULL, '2025-07-01 14:00:21', 0, 'A'),
(5291, 'PPI 5 EP.3', 3, 'Rumah sakit telah melakukan pemantauan proses pembersihan dan disinfeksi lingkungan.', '5', '', '', 10, 1351, 78, 0, 2025, 1, NULL, 'Bukti tentang: \r\na)	pelaksanaan supervisi\r\nb)	tindak lanjut hasil supervisi.', NULL, '-	IPCN\r\n-	Komite/Tim PPI\r\n-	Penanggungjawab Kesling', NULL, '2025-07-01 14:00:44', 0, 'A'),
(5292, 'PPI 6 EP.1', 1, 'Ada unit kerja pengelola linen/laundry yang menyelenggarakan penatalaksanaan sesuai dengan peraturan perundang-undangan.', '6', '', '', 10, 1352, 78, 0, 2025, 1, 'Regulasi tentang penetapan unit kerja pengelola linen/laundry', NULL, NULL, NULL, NULL, '2025-07-01 14:01:41', 0, 'A'),
(5293, 'PPI 6 EP.2', 2, 'Prinsip-prinsip PPI diterapkan pada pengelolaan linen/laundry, termasuk pemilahan, transportasi, pencucian, pengeringan, penyimpanan, dan distribusi', '6', '', '', 10, 1352, 78, 0, 2025, 1, NULL, NULL, 'Lihat pengelolaan linen/laundry, termasuk pemilahan, transportasi, pencucian, pengeringan, penyimpanan, dan distribusi.', '-	IPCN\r\n-	Komite/Tim PPI\r\n-	Kepala/ Staf linen/laundry', NULL, '2025-07-01 14:02:09', 0, 'A'),
(5294, 'PPI 6 EP.3', 3, 'Ada bukti supervisi oleh IPCN terhadap pengelolaan linen/laundry sesuai dengan prinsip PPI termasuk bila dilaksanakan oleh pihak luar rumah sakit.', '6', '', '', 10, 1352, 78, 0, 2025, 1, NULL, 'Bukti tentang: \r\na)	Pelaksanaan supervisi\r\nb)	Tindak lanjut hasil supervisi.', NULL, 'IPCN', NULL, '2025-07-01 14:02:30', 0, 'A'),
(5295, 'PPI 7 EP.1', 1, 'Rumah sakit telah menerapkan pengelolaan limbah rumah sakit untuk meminimalkan risiko infeksi yang meliputi  a) sampai e) pada maksud dan tujuan.', '7', '', '', 10, 1353, 78, 0, 2025, 1, NULL, 'Bukti tentang pengelolaan limbah rumah sakit meliputi:\r\na)	Pengelolaan limbah cairan tubuh infeksius; ?\r\nb)	Penanganan dan pembuangan darah serta komponen darah; ?\r\nc)	Pemulasaraan jenazah dan bedah mayat; ?\r\nd)	Pengelolaan limbah cair; ?\r\ne)	Pelaporan pajanan limbah infeksius.', NULL, '-	IPCN\r\n-	Penanggung jawab Kesling', NULL, '2025-07-01 14:03:16', 0, 'A'),
(5296, 'PPI 7 EP.2', 2, 'Penanganan dan pembuangan darah serta komponen darah sesuai dengan regulasi, dipantau dan dievaluasi, serta di tindak lanjutnya.', '7', '', '', 10, 1353, 78, 0, 2025, 1, NULL, 'Bukti tentang: \r\na)	Pelaksanaan supervisi\r\nb)	Tindak lanjut hasil supervisi.', NULL, '-	IPCN\r\n-	Penanggung jawab Kesling', NULL, '2025-07-01 14:03:40', 0, 'A'),
(5297, 'PPI 7 EP.3', 3, 'Pelaporan pajanan limbah infeksius sesuai dengan regulasi dan dilaksanakan pemantauan, evaluasi, serta tindak lanjutnya.', '7', '', '', 10, 1353, 78, 0, 2025, 1, NULL, 'Bukti tentang:\r\na)	Hasil supervisi\r\nb)	Pelaporan pajanan limbah infeksius\r\nc)	Tindak lanjut hasil supervisi', NULL, '-	IPCN\r\n-	Penanggung jawab Kesling', NULL, '2025-07-01 14:04:03', 0, 'A'),
(5298, 'PPI 7 EP.4', 4, 'Bila pengelolaan limbah dilaksanakan oleh pihak luar rumah sakit harus berdasar atas kerjasama dengan pihak yang memiliki izin dan sertifikasi mutu sesuai dengan peraturan perundang-undangan', '7', '', '', 10, 1353, 78, 0, 2025, 1, NULL, 'Bukti tentang:\r\na)	MOU dengan pihak transporter dan pengolah B3\r\nb)	Izin transporter \r\nc)	Izin pengolah B3\r\nd)	Sertifikasi mutu', NULL, '-	IPCN\r\n-	Penanggung jawab Kesling\r\n-	Petugas pengelola limbah', NULL, '2025-07-01 14:04:20', 0, 'A'),
(5299, 'PPI 7.1 EP.1', 1, 'Pemulasaraan jenazah dan bedah mayat sesuai dengan regulasi.', '7.1', '', '', 10, 1354, 78, 0, 2025, 1, NULL, 'Bukti tentang laporan kegiatan pemulasaran jenazah dan bedah mayat', NULL, '-	IPCN\r\n-	Kepala/staf kamar jenazah', NULL, '2025-07-01 14:04:38', 0, 'A'),
