(5341, 'PPK 3 EP.2', 2, 'Terdapat bukti perhitungan peserta didik yang diterima di rumah sakit per periode untuk proses pendidikan disesuaikan dengan jumlah pasien untuk menjamin mutu dan keselamatan pasien.', '3', '', '', 10, 1366, 79, 0, 2025, 1, NULL, 'Bukti tentang peserta didik yang diterima di rumah sakit per periode untuk proses pendidikan disesuaikan dengan jumlah pasien', NULL, '-	Komkordik/Timkordik.\r\n-	Kepala Departemen.\r\n-	Peserta didik.', NULL, '2025-07-01 14:29:16', 0, 'A'),
(5342, 'PPK 3 EP.3', 3, 'Terdapat bukti bahwa  sarana  prasarana,  teknologi, dan sumber daya lain di rumah sakit tersedia untuk mendukung pendidikan peserta didik.', '3', '', '', 10, 1366, 79, 0, 2025, 1, NULL, NULL, 'Lihat ketersediaan  sarana  prasarana,  teknologi, dan sumber daya lain di rumah sakit untuk mendukung pendidikan peserta didik', NULL, NULL, '2025-07-01 14:29:33', 0, 'A'),
(5343, 'PPK 4 EP.1', 1, 'Rumah sakit menetapkan staf klinis yang memberikan pendidikan klinis dan penetapan  penugasan  klinis serta rincian kewenangan klinis dari rumah sakit.', '4', '', '', 10, 1367, 79, 0, 2025, 1, 'Regulasi tentang: \r\n1)	SK pendidik klinis/dosen klinis/ instruktur klinis dari RS. \r\n2)	SPK/RKK staf klinis dari RS \r\n3)	SK penugasan dari institusi pendidikan untuk seluruh staf pendidik klinis dari Rumah sakit', NULL, NULL, NULL, NULL, '2025-07-01 14:29:48', 0, 'A'),
(5344, 'PPK 4 EP.2', 2, 'Rumah sakit memiliki daftar staf klinis yang memberikan pendidikan klinis secara lengkap (akademik dan profesi) sesuai dengan jenis pendidikan yang dilaksanakan di rumah sakit.', '4', '', '', 10, 1367, 79, 0, 2025, 1, NULL, 'Bukti tentang daftar staf klinis yang memberikan pendidikan klinis lengkap dengan status kepegawaiannya.', NULL, '-	Komkordik/Timkordik.\r\n-	Manajer SDM. \r\n-	Staf klinis.', NULL, '2025-07-01 14:30:21', 0, 'A'),
(5345, 'PPK 4 EP.3', 3, 'Rumah sakit memiliki bukti staf klinis yang memberikan pendidikan klinis telah mengikuti pendidikan sebagai pendidikan dan keprofesian berkelanjutan.', '4', '', '', 10, 1367, 79, 0, 2025, 1, NULL, 'Bukti sertifikat pelatihan/pendidikan berkelanjutan staf klinis yang memberikan pendidikan klinis (pelatihan menjadi Instrukstur/pendidik klinis dan pendidikan/pelatihan keprofesian).', NULL, NULL, NULL, '2025-07-01 14:30:33', 0, 'A'),
(5346, 'PPK 5 EP.1', 1, 'Rumah sakit telah memiliki tingkat supervisi yang diperlukan oleh setiap peserta pendidikan klinis di rumah sakit untuk setiap jenjang pendidikan', '5', '', '', 10, 1368, 79, 0, 2025, 1, 'Regulasi tentang tingkat supervisi utk semua tingkat dan jenis peserta pendidikan klinis, termasuk penetapan frekuensi supervisi untuk setiap pendidik klinis (Buku Panduan Supervisi).', NULL, NULL, NULL, NULL, '0000-00-00 00:00:00', 0, 'A'),
(5347, 'PPK 5 EP.2', 2, 'Setiap peserta pendidikan klinis mengetahui tingkat, frekuensi, dan dokumentasi untuk supervisinya.', '5', '', '', 10, 1368, 79, 0, 2025, 1, NULL, 'Bukti Informasi untuk peserta pendidikan klinis tentang tingkat, frekuensi dan cara supervisi.', 'Tanda pengenal untuk tingkat supervisi setiap peserta pendidikan klinis.', 'Peserta pendidikan klinis.', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5348, 'PPK 5 EP.3', 3, 'Rumah sakit telah memiliki format spesifik untuk mendokumentasikan proses supervisi yang sesuai dengan kebijakan rumah sakit, tujuan program pendidikan, serta mutu dan keselamatan asuhan  pasien.', '5', '', '', 10, 1368, 79, 0, 2025, 1, NULL, 'Bukti adanya buku log terisi lengkap untuk setiap peserta didik dengan format yang disesuaikan dengan kebutuhan supervisi setiap jenis pendidikan', NULL, 'Peserta pendidikan klinis.', NULL, '2025-07-01 14:32:20', 0, 'A'),
(5349, 'PPK 5 EP.4', 4, 'Rumah sakit telah memiliki proses pengkajian rekam medis untuk memastikan kepatuhan batasan kewenangan dan proses supervisi peserta pendidikan yang mempunyai akses pengisian rekam medis.', '5', '', '', 10, 1368, 79, 0, 2025, 1, NULL, 'Bukti pelaksanaan proses pengkajian rekam medis untuk memastikan kepatuhan batasan kewenangan dan proses supervisi peserta pendidikan yang mempunyai akses pengisian rekam medis', NULL, '-	Peserta pendidikan klinis.\r\n-	Tim review rekam medis RS', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5350, 'PPK 6 EP.1', 1, 'Rumah sakit menetapkan unit yang bertanggung jawab untuk mengelola pelaksanaan pendidikan klinis di rumah sakit.', '6', '', '', 10, 1369, 79, 0, 2025, 1, 'Regulasi tentang penetapan unit yang bertanggung jawab untuk mengelola pelaksanaan pendidikan klinis di rumah sakit', NULL, NULL, NULL, NULL, '2025-07-01 14:33:12', 0, 'A'),
(5351, 'PPK 6 EP.2', 2, 'Rumah sakit menetapkan program orientasi peserta pendidikan klinis.', '6', '', '', 10, 1369, 79, 0, 2025, 1, 'Regulasi tentang program orientasi meliputi: \r\n1)	Mutu dan keselamatan pasien. \r\n2)	Pengendalian infeksi.\r\n3)	Keselamatan penggunaan obat. \r\n4)	Sasaran keselamatan pasien.', NULL, NULL, NULL, NULL, '2025-07-01 14:33:34', 0, 'A'),
(5352, 'PPK 6 EP.3', 3, 'Rumah sakit telah memiliki bukti pelaksanaan dan sertifikat program orientasi peserta pendidikan klinis.', '6', '', '', 10, 1369, 79, 0, 2025, 1, NULL, 'Bukti pelaksanaan orientasi dan dokumen pelaksanaan (TOR, materi, narasum berdaftar hadir peserta).', NULL, 'Peserta didik klinis.', NULL, '2025-07-01 14:34:08', 0, 'A'),
(5353, 'PPK 6 EP.4', 4, 'Rumah sakit telah memiliki bukti pelaksanaan dan dokumentasi peserta didik diikutsertakan  dalam  semua program peningkatan mutu dan keselamatan pasien di rumah sakit.', '6', '', '', 10, 1369, 79, 0, 2025, 1, NULL, 'Bukti pelaksanaan peserta didik diikutsertakan dalam semua program peningkatan mutu dan keselamatan pasien', NULL, '-	Peserta didik klinis.\r\n-	Kepala unit pelayanan', NULL, '2025-07-01 14:34:48', 0, 'A'),
(5354, 'PPK 6 EP.5', 5, 'Rumah sakit telah memantau dan mengevaluasi bahwa pelaksanaan program pendidikan kesehatan tidak menurunkan mutu dan keselamatan pasien yang dilaksanakan sekurang-kurangnya sekali setahun yang terintegrasi dengan program mutu dan keselamatan pasien.', '6', '', '', 10, 1369, 79, 0, 2025, 1, NULL, 'Bukti evaluasi pelaksanaan pendidikan tidak menurunkan mutu dan keselamatan pasien', NULL, 'Komite Mutu RS', NULL, '2025-07-01 14:35:24', 0, 'A'),
(5355, 'PPK 6 EP.6', 6, 'Rumah sakit telah melakukan survei mengenai kepuasan pasien terhadap pelayanan rumah sakit atas dilaksanakannya pendidikan klinis sekurang- kurangnya sekali setahun.', '6', '', '', 10, 1369, 79, 0, 2025, 1, NULL, 'Bukti pelaksanaan survei kepuasan pasien terhadap pelayanan rumah sakit yang dilaksanakan dengan melibatkan pendidikanklinis.', NULL, '-	Pasien dan keluarga\r\n-	Customer service', NULL, '2025-07-01 14:37:10', 0, 'A'),
(5356, 'AKP 1 EP.1', 1, 'Rumah sakit telah menetapkan regulasi akses dan kesinambungan pelayanan (AKP) meliputi poin a) sampai f) pada gambaran umum.', '1', '', '', 10, 1370, 80, 0, 2025, 1, 'Regulasi tentang akses dan kesinambungan pasien meliputi:\r\na.	Skrining pasien di rumah sakit; \r\nb.	Registrasi dan admisi di rumah sakit; \r\nc.	Pelayanan berkesinambungan; \r\nd.	Transfer pasien internal dalam rumah sakit;\r\ne.	Pemulangan, rujukan dan tindak lanjut; dan\r\nf.	Transportasi.', NULL, NULL, NULL, NULL, '2025-07-01 14:39:05', 0, 'A'),
(5357, 'AKP 1 EP.2', 2, 'Rumah sakit telah menerapkan proses skrining baik di dalam maupun di luar rumah sakit dan  terdokumentasi.', '1', '', '', 10, 1370, 80, 0, 2025, 1, NULL, 'Bukti pelaksanaan proses skrining sesuai regulasi yang digunakan di dalam dan di luar RS', NULL, '-	Staf Medis\r\n-	Staf Keperawatan', NULL, '2025-07-01 14:39:45', 0, 'A'),
(5358, 'AKP 1 EP.3', 3, 'Ada proses untuk memberikan hasil pemeriksaan diagnostik kepada tenaga kesehatan yang kompeten/terlatih untuk bertanggung jawab menentukan apakah pasien akan diterima, ditransfer, atau dirujuk.', '1', '', '', 10, 1370, 80, 0, 2025, 1, NULL, 'Bukti proses untuk memberikan hasil pemeriksaan diagnostik kepada tenaga medis yang bertanggung jawab untuk menentukan apakah pasien akan admisi, ditransfer, atau dirujuk.', NULL, '-	Staf medis\r\n-	Staf keperawatan\r\n-	Staf klinis laboratorium dan radiologi', NULL, '2025-07-01 14:40:05', 0, 'A'),
(5359, 'AKP 1 EP.4', 4, 'Bila kebutuhan pasien tidak dapat  dipenuhi  sesuai  misi dan sumber daya yang ada, maka rumah sakit  akan merujuk atau membantu pasien ke fasilitas pelayanan yang sesuai kebutuhannya.', '1', '', '', 10, 1370, 80, 0, 2025, 1, NULL, '1)	Bukti tindak lanjut hasil skrining di rekam medis.\r\n2)	Form rujukan bila pasien dirujuk.', NULL, '-	Staf medis\r\n-	Staf keperawatan', NULL, '2025-07-01 14:42:24', 0, 'A'),
(5360, 'AKP 1.1 EP.1', 1, 'Proses triase dan pelayanan kegawatdaruratan telah diterapkan oleh staf yang kompeten  dan  bukti dokumen kompetensi dan kewenangan klinisnya tersedia.', '1.1', '', '', 10, 1371, 80, 0, 2025, 1, NULL, '1)	Bukti pelaksanaan proses triase berbasis bukti\r\n2)	SPK-RKK staf klinis di IGD. (Lihat Std KPS 11 untuk medis dan KPS 15 untuk perawat)', NULL, 'Staf klinis IGD', NULL, '2025-07-01 14:43:12', 0, 'A'),
(5361, 'AKP 1.1 EP.2', 2, 'Staf telah menggunakan kriteria triase berbasis bukti untuk memprioritaskan pasien sesuai dengan kegawatannya.', '1.1', '', '', 10, 1371, 80, 0, 2025, 1, NULL, 'Bukti pelaksanaan proses triase berbasis bukti untuk memprioritaskan pasien sesuai dengan kegawatannya', NULL, '-	Dokter IGD\r\n-	Perawat IGD', NULL, '2025-07-01 14:43:35', 0, 'A'),
(5362, 'AKP 1.1 EP.3', 3, 'Pasien darurat dinilai dan distabilkan sesuai kapasitas rumah sakit sebelum ditransfer ke ruang rawat atau dirujuk dan didokumentasikan dalam rekam medik.', '1.1', '', '', 10, 1371, 80, 0, 2025, 1, NULL, 'Bukti dalam rekam medis proses stabilisasi sebelum pasien dipindahkan ke rawat inap, atau dirujuk', NULL, '-	Dokter IGD\r\n-	Perawat IGD', NULL, '2025-07-01 14:44:22', 0, 'A'),
(5363, 'AKP 1.2 EP.1', 1, 'Rumah  sakit telah melaksanakan skrining pasien masuk rawat  inap untuk menetapkan kebutuhan pelayanan preventif, paliatif, kuratif, dan rehabilitatif, pelayanan khusus/spesialistik atau pelayanan intensif.', '1.2', '', '', 10, 1372, 80, 0, 2025, 1, NULL, ' Bukti  pelaksanaan skrining pasien masuk rawat inap untuk menetapkan prioritas kebutuhan pelayanan preventif, paliatif, kuratif, dan rehabilitatif, pelayanan khusus/spesialistik atau pelayanan intensif\r\n2a) contoh prioritas pelayanan preventif (dalam proses admisi) adalah untuk mencegah perburukan/ komplikasi pasien tersebut, misalnya antara lain, kasus luka tusuk dalam dan kotor diberikan ATS.\r\n2b) contoh prioritas pelayanan kuratif antara lain pasien datang dengan kehamilan misalnya 34 minggu dan dengan nyeri dada kiri, agar ditetapkan penanganannya apakah prioritasnya untuk obstetri atau untuk kardiologi.', NULL, '-	Staf medis\r\n-	Staf keperawatan', NULL, '2025-07-01 14:45:05', 0, 'A'),
(5364, 'AKP 1.2 EP.2', 2, 'Rumah sakit telah menetapkan kriteria masuk dan kriteria keluar di unit pelayanan khusus/spesialistik menggunakan parameter diagnostik dan  atau parameter objektif termasuk kriteria berbasis fisiologis dan terdokumentasikan di rekam medik.', '1.2', '', '', 10, 1372, 80, 0, 2025, 1, 'Regulasi tentang penetapan kriteria masuk dan keluar \r\n1)	Di rawat intensif, antara lain ICU, ICCU, PICU, NICU.\r\n2)	Di unit spesialistik antara lain  pelayanan luka bakar, pelayanan  stroke, perawatan paliatif.', NULL, NULL, NULL, NULL, '2025-07-01 14:45:48', 0, 'A'),
(5365, 'AKP 1.2 EP.3', 3, 'Rumah sakit telah menerapkan kriteria masuk dan kriteria keluar di unit pelayanan intensif menggunakan parameter diagnostik dan atau parameter objektif termasuk kriteria berbasis fisiologis dan terdokumentasikan di rekam medik', '1.2', '', '', 10, 1372, 80, 0, 2025, 1, NULL, 'Bukti penerapan kriteria masuk dan kriteria keluar di unit pelayanan intensif menggunakan parameter diagnostik dan atau parameter objektif termasuk kriteria berbasis fisiologis dan terdokumentasikan di rekam medik', NULL, '-	Dokter unit terkait\r\n-	Perawat unit terkait\r\n-	Kepala unit terkait', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5366, 'AKP 1.2 EP.4', 4, 'Staf yang kompeten dan berwenang di unit pelayanan khusus dan unit pelayanan intensif terlibat dalam penyusunan kriteria masuk dan kriteria keluar di unitnya.', '1.2', '', '', 10, 1372, 80, 0, 2025, 1, NULL, 'Bukti rapat dimana  staf yang kompeten dan  berwenang terlibat menentukan kriteria masuk dan kriteria keluar, berupa: Undangan, Materi, Absensi, Notulen.', NULL, '-	Dokter unit terkait\r\n-	Perawat unit terkait\r\n-	Kepala unit terkait', NULL, '2025-07-01 14:47:23', 0, 'A'),
(5367, 'AKP 1.3 EP.1', 1, 'Pasien dan atau keluarga diberi informasi jika ada penundaan dan atau keterlambatan pelayanan beserta alasannya dan dicatat di rekam medis.', '1.3', '', '', 10, 1373, 80, 0, 2025, 1, NULL, '1)	Bukti pasien dan atau keluarga diberi informasi jika ada penundaan dan atau kelambatan pelayanan beserta alasannya dan dicatat di rekam medis\r\n2)	Kelambatan pada pasien adalah kondisi dimana suatu pelayanan/tindakan melebihi durasi yang normatif, misalnya operasi yang normatif satu jam tetapi berlangsung lebih dari satu jam.', NULL, '-	Staf medis\r\n-	Staf keperawatan\r\n-	Pasien', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5368, 'AKP 1.3 EP.2', 2, 'Pasien dan atau keluarga diberi informasi tentang alternatif yang tersedia sesuai kebutuhan klinis pasien dan dicatat di rekam medis.', '1.3', '', '', 10, 1373, 80, 0, 2025, 1, NULL, 'Bukti Pasien dan atau keluarga diberi informasi tentang alternatif yang tersedia sesuai kebutuhan klinis pasien dan dicatat di rekam medis', NULL, '-	Staf medis\r\n-	Staf keperawatan\r\n-	Pasien', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5369, 'AKP 2 EP.1', 1, 'Rumah sakit telah menerapkan  proses  penerimaan pasien meliputi poin a)-f) pada maksud dan tujuan.', '2', '', '', 10, 1374, 80, 0, 2025, 1, NULL, '1)	Bukti penerapan proses penerimaan pasien meliputi:\r\na)	Pendaftaran pasien gawat darurat; \r\nb)	Penerimaan langsung pasien dari IGD ke rawat inap; \r\nc)	Admisi pasien rawat inap; \r\nd)	Pendaftaran pasien rawat jalan; \r\ne)	Observasi pasien; dan \r\nf)	Mengelola pasien bila tidak tersedia tempat tidur\r\n2)	Bukti termasuk penerimaan pasien dengan hambatan. Lihat juga Std HPK 1.1.', NULL, '-	Staf medis, \r\n-	Staf keperawatan,\r\n-	Petugas pendaftaran rajal dan  ranap, pasien', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5370, 'AKP 2 EP.2', 2, 'Rumah sakit telah menerapkan sistim pendaftaran pasien rawat jalan dan rawat inap baik secara offline maupun secara online dan dilakukan evaluasi dan tindak lanjutnya.', '2', '', '', 10, 1374, 80, 0, 2025, 1, NULL, '1)	Bukti  pelaksanaan pendaftaran pasien rawat jalan dan rawat inap baik secara offline maupun secara online.\r\n2)	Bukti dilakukan evaluasi dan tindak. lanjutnya.', NULL, '-	Staf admisi\r\n-	Pasien/keluarga', NULL, '0000-00-00 00:00:00', 0, 'A');
INSERT INTO `accreditation_instrument` (`instrument_id`, `instrument_reference_code`, `instrument_order_id`, `instrument_name`, `instrument_objective`, `instrument_material`, `instrument_document`, `instrument_maximum_score`, `instrument_standard_id`, `instrument_chapter_id`, `instrument_class_id`, `instrument_version`, `instrument_institution_group_id`, `instrument_r`, `instrument_d`, `instrument_o`, `instrument_w`, `instrument_s`, `instrument_update`, `instrument_user_id`, `instrument_record_status`) VALUES
(5371, 'AKP 2 EP.3', 3, 'Rumah sakit telah memberikan informasi tentang rencana asuhan yang akan diberikan, hasil  asuhan  yang diharapkan serta perkiraan biaya yang harus dibayarkan oleh pasien/keluarga.', '2', '', '', 10, 1374, 80, 0, 2025, 1, NULL, 'Bukti telah diberikan informasi tentang : \r\n1)	Rencana  asuhan saat admisi disampaikan oleh dokter  yang memutuskan untuk dirawat\r\n2)	Hasil asuhan yang diharapkan\r\n3)	Perkiraan biaya \r\n(Lihat Std KE 4 EP 2)', NULL, '-	Staf Admisi\r\n-	Staf medis\r\n-	Staf keperawatan\r\n-	Pasien/keluarga', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5372, 'AKP 2 EP.4', 4, 'Saat diterima sebagai pasien rawat inap, pasien dan keluarga mendapat edukasi dan orientasi  tentang  ruang rawat inap.', '2', '', '', 10, 1374, 80, 0, 2025, 1, NULL, 'Bukti dilakukan edukasi kepada pasien dan keluarga tentang ruang rawat inap.', NULL, '-	Staf keperawatan\r\n-	Pasien/keluarga', 'Staf memperagakan saat memberikan edukasi dan orientasi tentang ruang rawat inap kepada pasien dan keluarga \r\n(Lihat Std KE 2 EP 4)', '0000-00-00 00:00:00', 0, 'A'),
(5373, 'AKP 2.1 EP.1', 1, 'Rumah sakit telah  melaksanakan  pengelolaan  alur pasien untuk  menghindari  penumpukan.   mencakup poin a)-g) pada maksud dan tujuan.', '2.1', '', '', 10, 1375, 80, 0, 2025, 1, NULL, 'Bukti pelaksanaan pengaturan alur pasien untuk menghindari penumpukan mencakup:\r\na)	ketersediaan tempat tidur di tempat sementara/transit/intermediate sebelum mendapatkan tempat tidur di rawat inap; \r\nb)	perencanaan fasilitas, peralatan, utilitas, teknologi medis, dan kebutuhan lain untuk mendukung penempatan sementara pasien; \r\nc)	perencanaan tenaga untuk memberikan asuhan pasien di tempat sementara/transit termasuk pasien yang diobservasi di unit gawat darurat; \r\nd)	alur pelayanan pasien di tempat sementara/transit meliputi pemberian asuhan, tindakan, pemeriksaan laboratorium, pemeriksaan radiologi, tindakan di kamar operasi, dan unit pascaanestes harus sama seperti yang diberikan dirawat inap; \r\ne)	efisiensi pelayanan nonklinis penunjang asuhan dan tindakan kepada pasien (seperti kerumahtanggaan dan transportasi); \r\nf)	memberikan asuhan pasien yang sama kepada pasien yang dirawat di tempat sementara/transit/intermediate seperti perawatan kepada pasien yang dirawat di ruang rawat inap; dan\r\ng)	akses pelayanan yang bersifat mendukung (seperti pekerja sosial, keagamaan atau bantuan spiritual, dan sebagainya).', NULL, '-	Dokter\r\n-	Perawat\r\n-	MPP', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5374, 'AKP 2.1 EP.2', 2, 'Manajer pelayanan pasien (MPP)/case  manager bertanggung jawab terhadap pelaksanaan pengaturan alur pasien untuk menghindari penumpukan.', '2.1', '', '', 10, 1375, 80, 0, 2025, 1, 'Penetapan uraian tugas (MPP)/case manager, terkait EP 1) tentang poin a) – g), yaitu dalam konteks koordinasi  oleh manajemen terkait.', NULL, NULL, NULL, NULL, '0000-00-00 00:00:00', 0, 'A'),
(5375, 'AKP 2.1 EP.3', 3, 'Rumah sakit telah melakukan evaluasi terhadap pengelolaan alur pasien secara berkala dan melaksanakan upaya perbaikannya.', '2.1', '', '', 10, 1375, 80, 0, 2025, 1, NULL, 'Bukti evaluasi terhadap pengelolaan alur pasien secara berkala dan melaksanakan upaya perbaikannya.', NULL, '-	Dokter IGD, Perawat IGD, Kepala IGD\r\n-	Kepala unit\r\n-	Perawat di rawat inap\r\n-	Manajer Pelayanan Pasien\r\n-	Pasien/keluarga', NULL, '2025-07-01 15:00:03', 0, 'A'),
(5376, 'AKP 2.1 EP.4', 4, 'Ada sistem informasi tentang  ketersediaan  tempat tidur secara online kepada masyarakat.', '2.1', '', '', 10, 1375, 80, 0, 2025, 1, NULL, NULL, 'Bukti pelaksanaan sistem informasi tentang ketersediaan tempat tidur secara online kepada masyarakat', '-	Bagian admisi\r\n-	IT', NULL, '2025-07-01 15:00:28', 0, 'A'),
(5377, 'AKP 3 EP.1', 1, 'Para PPA telah memberikan asuhan pasien secara terintegrasi berfokus pada pasien meliputi poin a)-f) pada maksud dan tujuan.', '3', '', '', 10, 1376, 80, 0, 2025, 1, NULL, '1)	Pelaksanaan asuhan pasien secara terintegrasi fokus pada pasien mencakup: \r\na)	Keterlibatan dan pemberdayaan pasien dan keluarga; \r\nb)	Dokter penanggung jawab pelayanan (DPJP) sebagai Ketua tim asuhan pasien oleh profesional pemberi asuhan (PPA) (clinical leader); \r\nc)	Profesional pemberi asuhan (PPA) bekerja sebagai tim interdisiplin dengan kolaborasi interprofesional dibantu antara lain oleh Panduan Praktik Klinis (PPK), Panduan Asuhan Profesional Pemberi Asuhan (PPA) lainnya, Alur Klinis/clinical pathway terintegrasi, Algoritme, Protokol, Prosedur, Standing Order dan CPPT (Catatan Perkembangan Pasien Terintegrasi); \r\nd)	Perencanaan pemulangan pasien (P3)/discharge planning terintegrasi; \r\ne)	Asuhan gizi terintegrasi; dan \r\nf)	Manajer pelayanan pasien/case manager.\r\n2)	Termasuk juga: Alur Klinis (Clinical Pathway terintegrasi, Perencanaan pemulangan pasien/Discharge planning terintegrasi.', NULL, '-	DPJP\r\n-	PPJA\r\n-	MPP\r\n-	PPA lain yang terkait\r\n-	Pasien/ keluarga', NULL, '2025-07-01 15:01:15', 0, 'A'),
(5378, 'AKP 3 EP.2', 2, 'Ada penunjukkan MPP dengan uraian tugas meliputi poin a)-h) pada maksud dan tujuan.', '3', '', '', 10, 1376, 80, 0, 2025, 1, 'Bukti penetapan MPP dengan uraian tugas meliputi:\r\na)	Memfasilitasi pemenuhan kebutuhan asuhan pasien; \r\nb)	Mengoptimalkan terlaksananya pelayanan berfokus pada pasien;\r\nc)	Mengoptimalkan proses reimbursemen; dan dengan fungsi sebagai berikut; \r\nd)	Asesmen untuk manajemen pelayanan pasien; \r\ne)	Perencanaan untuk manajemen pelayanan pasien; \r\nf)	Komunikasi dan koordinasi; \r\ng)	Edukasi dan advokasi; dan \r\nh)	Kendali mutu dan biaya pelayanan pasien', 'Bukti pelaksanaan tugas MPP di Formulir A (evaluasi awal MPP) dan Formulir B (catatan implementasi).', NULL, 'MPP', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5379, 'AKP 3 EP.3', 3, 'Para profesional pemberi asuhan (PPA) dan manajer pelayanan pasien (MPP) telah melaksanakan kesinambungan dan koordinasi pelayanan  meliputi poin a)-e) pada maksud dan tujuan.', '3', '', '', 10, 1376, 80, 0, 2025, 1, NULL, 'Bukti para Profesional Pemberi Asuhan (PPA) dan Manajer Pelayanan Pasien (MPP) telah melaksanakan kesinambungan dan koordinasi pelayanan meliputi:\r\na)	Pelayanan darurat dan penerimaan rawat inap; \r\nb)	Pelayanan diagnostik dan tindakan; \r\nc)	Pelayanan bedah dan nonbedah; \r\nd)	Pelayanan rawat jalan; dan \r\ne)	Organisasi lain atau bentuk pelayanan lainnya.', NULL, '-	DPJP/PPA lainnya\r\n-	MPP Pasien\r\n-	Kepala instalasi rawat inap/kepala ruang  rawat inap\r\n-	Pasien', NULL, '2025-07-01 15:03:16', 0, 'A'),
(5380, 'AKP 3 EP.4', 4, 'Pencatatan perkembangan pasien didokumentasikan para PPA di formulir catatan pasien terintegrasi (CPPT).', '3', '', '', 10, 1376, 80, 0, 2025, 1, NULL, 'Bukti pencatatan perkembangan pasien didokumentasikan para PPA di formulir catatan pasien terintegrasi (CPPT)', NULL, '-	DPJP\r\n-	PPJA\r\n-	PPA lain', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5381, 'AKP 3 EP.5', 5, 'Pencatatan di unit intensif atau unit khusus menggunakan lembar pemantauan pasien khusus, pencatatan perkembangan pasien dilakukan pada lembar tersebut oleh DPJP di unit tersebut, PPA lain dapat melakukan pencatatan perkembangan pasien di formulir catatan pasien terintegrasi (CPPT).', '3', '', '', 10, 1376, 80, 0, 2025, 1, NULL, 'Bukti  pencatatan perkembangan pasien di unit intensif atau unit khusus oleh, DPJP dan PPA lainnya', NULL, '-	DPJP\r\n-	PPJA\r\n-	PPA lain', NULL, '2025-07-01 15:04:37', 0, 'A'),
(5382, 'AKP 3 EP.6', 6, 'Perencanaan dan pelayanan pasien secara terintegrasi diinformasikan kepada pasien dan atau  keluarga  secara berkala sesuai ketentuan Rumah Sakit.', '3', '', '', 10, 1376, 80, 0, 2025, 1, NULL, 'Bukti  pemberian informasi tentang perencanaan dan pelayanan pasien secara terintegrasi kepada pasien dan keluarga secara berkala', NULL, '-	DPJP\r\n-	PPJA\r\n-	Pasien/ keluarga', NULL, '2025-07-01 15:05:05', 0, 'A'),
(5383, 'AKP 3.1 EP.1', 1, 'Rumah sakit telah menetapkan bahwa setiap pasien memiliki dokter penanggung jawab pelayanan (DPJP) dan telah melakukan asuhan pasien secara terkoordinasi dan terdokumentasi dalam rekam medis pasien.', '3.1', '', '', 10, 1377, 80, 0, 2025, 1, 'Bukti penetepan setiap pasien memiliki dokter penganggung jawab pelayanan (DPJP)', 'Bukti tentang setiap pasien memiliki DPJP dan telah melakukan asuhan pasien secara terkoordinasi dan terdokumentasi dalam rekam medis pasien', NULL, '-	DPJP\r\n-	Pasien/keluarga', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5384, 'AKP 3.1 EP.2', 2, 'Rumah sakit juga menetapkan proses perpindahan tanggung jawab koordinasi asuhan pasien dari satu dokter penanggung jawab pelayanan (DPJP) ke DPJP lain, termasuk bila terjadi perubahan DPJP utama.', '3.1', '', '', 10, 1377, 80, 0, 2025, 1, '1)	Regulasi tentang proses perpindahan tanggung jawab koordinasi asuhan pasien dari satu dokter penanggung jawab pelayanan (DPJP) ke DPJP lain, termasuk bila terjadi perubahan DPJP Utama.\r\n2)	Regulasi DPJP sebagai ketua tim asuhan pasien (clinical leader):\r\na.	Lihat Std PP di Gambaran Umum tentang Asuhan Pasien Terintegrasi poin a)\r\nb.	Lihat Std PAP 1.2 di maksud dan tujuan : “DPJP sebagai ketua tim PPA melakukan evaluasi / reviu berkala dan verifikasi harian untuk memantau terlaksananya asuhan secara terintegrasi dan membuat notasi sesuai dengan kebutuhan.”', NULL, NULL, NULL, NULL, '2025-07-01 15:09:08', 0, 'A'),
(5385, 'AKP 3.1 EP.3', 3, 'Bila dilaksanakan rawat bersama ditetapkan DPJP utama sebagai koordinator asuhan pasien.', '3.1', '', '', 10, 1377, 80, 0, 2025, 1, NULL, 'Bukti penetapan DPJP Utama bila dilakukan rawat bersama', NULL, '-	DPJP\r\n-	Kepala instalasi rawat inap/kepala ruang  rawat inap\r\n-	Pasien/keluarga', NULL, '2025-07-01 15:09:34', 0, 'A'),
(5386, 'AKP 4 EP.1', 1, 'Rumah sakit telah menerapkan proses transfer pasien antar unit pelayanan di dalam rumah sakit dilengkapi dengan formulir transfer pasien.', '4', '', '', 10, 1378, 80, 0, 2025, 1, NULL, 'Bukti penerapan  proses transfer pasien antar unit pelayanan di dalam rumah sakit dalam formulir transfer pasien', NULL, 'Staf klinis', NULL, '2025-07-01 15:10:07', 0, 'A'),
(5387, 'AKP 4 EP.2', 2, 'Formulir transfer internal meliputi poin - pada maksud dan tujuan.', '4', '', '', 10, 1378, 80, 0, 2025, 1, NULL, 'Form transfer meliputi:\r\na)	alasan admisi; \r\nb)	temuan signifikan; \r\nc)	diagnosis; \r\nd)	prosedur yang telah dilakukan; \r\ne)	obat-obatan; \r\nf)	perawatan lain yang diterima pasien; dan \r\ng)	kondisi pasien saat transfer.', NULL, NULL, NULL, '2025-07-01 15:10:37', 0, 'A'),
(5388, 'AKP 5 EP.1', 1, 'Rumah sakit telah menetapkan kriteria pemulangan pasien sesuai dengan kondisi  kesehatan  dan  kebutuhan pelayanan pasien beserta edukasinya.', '5', '', '', 10, 1379, 80, 0, 2025, 1, 'a)	Kriteria pasien yang memerlukan Rencana Pemulangan Pasien (discharge planning) yang dicatat di pengkajian awal\r\nb)	Regulasi tentang kriteria pemulangan pasien sesuai dengan kondisi kesehatan dan kebutuhan pelayanan pasien beserta edukasinya meliputi:\r\n1)	kriteria pemulangan pasien sesuai kondisi Kesehatan\r\n2)	kriteria pasien yang memerlukan kesinambungan asuhan dirumah beserta edukasinya', NULL, NULL, NULL, NULL, '0000-00-00 00:00:00', 0, 'A'),
(5389, 'AKP 5 EP.2', 2, 'Rumah sakit telah menetapkan kemungkinan pasien diizinkan keluar rumah sakit dalam jangka waktu tertentu untuk keperluan penting.', '5', '', '', 10, 1379, 80, 0, 2025, 1, 'Regulasi tentang penetapan kriteria tentang  pasien yang diizinkan untuk keluar meninggalkan RS selama periode waktu  tertentu untuk keperluan penting.\r\nCatatan (di maksud dan tujuan): RS dapat menetapkan kemungkinan pasien diizinkan keluar RS.', NULL, NULL, NULL, NULL, '2025-07-01 15:11:07', 0, 'A'),
(5390, 'AKP 5 EP.3', 3, 'Penyusunan rencana dan instruksi pemulangan didokumentasikan dalam rekam medis pasien dan diberikan kepada pasien secara tertulis.', '5', '', '', 10, 1379, 80, 0, 2025, 1, NULL, 'Bukti dalam ringkasan pulang memuat instruksi tindak lanjut dan dijelaskan kepada pasien/ keluarga serta ditanda tangani oleh pasien/ keluarga.', NULL, '-	DPJP\r\n-	PPJA\r\n-	Pasien/ keluarga', NULL, '2025-07-01 15:11:25', 0, 'A'),
(5391, 'AKP 5 EP.4', 4, 'Tindak lanjut pemulangan pasien bila  diperlukan  dapat ditujukan kepada fasilitas pelayanan kesehatan baik perorangan ataupun dimana pasien untuk memberikan pelayanan berkelanjutan.', '5', '', '', 10, 1379, 80, 0, 2025, 1, NULL, 'Bukti pelaksanaan tindak lanjut pemulangan pasien yang memerlukan rujukan kepada fasilitas pelayanan kesehatan primer atau mandiri sesuai domisili pasien.', NULL, '-	DPJP\r\n-	Kepala ruang rawat inap\r\n-	Manajer Pelayanan Pasien\r\n-	Pasien/keluarga', NULL, '2025-07-01 15:11:44', 0, 'A'),
(5392, 'AKP 5.1 EP.1', 1, 'Rumah sakit telah  menetapkan  Ringkasan  pasien  pulang meliputi a)-f) pada maksud dan tujuan.', '5.1', '', '', 10, 1380, 80, 0, 2025, 1, '1)	Regulasi tentang penetapan ringkasan pasien pulang meliputi: \r\na)	indikasi pasien masuk dirawat, diagnosis, dan komorbiditas lain; \r\nb)	temuan fisik penting dan temuan-temuan lain; \r\nc)	tindakan diagnostik dan prosedur terapi yang telah dikerjakan; \r\nd)	obat yang diberikan selama dirawat inap dengan potensi akibat efek residual setelah obat tidak diteruskan dan semua obat yang harus digunakan di rumah; \r\ne)	kondisi pasien (status present); dan \r\nf)	instruksi tindak lanjut.\r\n2)	Salinan Ringkasan pasien pulang minimal berjumlah empat, diperuntukkan: 1. Di Rekam Medis, 2. Diberikan kepada tenaga Kesehatan yang bertanggung jawab memberikan tindak lanjut asuhan, 3. Pasien/Keluarga, 4. Penjamin.', NULL, NULL, NULL, NULL, '2025-07-01 15:12:13', 0, 'A'),
(5393, 'AKP 5.1 EP.2', 2, 'Rumah sakit memberikan salinan ringkasan pasien pulang kepada pihak yang berkepentingan dan tersimpan di dalam rekam medik.', '5.1', '', '', 10, 1380, 80, 0, 2025, 1, NULL, 'Bukti pelaksanaan pemberian salinan  ringkasan pulang kepada pihak yang berkepentingan dan tersimpan di dalam rekam medik.', NULL, '-	DPJP\r\n-	Kepala unit  rawat inap\r\n-	Staf Rekam Medis\r\n-	Pasien/keluarga', NULL, '2025-07-01 15:12:37', 0, 'A'),
(5394, 'AKP 5.1 EP.3', 3, 'Formulir Ringkasan pasien pulang dijelaskan kepada pasien dan atau keluarga.', '5.1', '', '', 10, 1380, 80, 0, 2025, 1, NULL, 'Bukti pelaksanaan ringkasan pulang sudah dijelaskan kepada pasien/ keluarga dan ringkasan pulang ditandatangani pasien/keluarga.', NULL, '-	DPJP\r\n-	PPJA\r\n-	Pasien/ keluarga', NULL, '2024-10-25 13:42:01', 0, 'A'),
(5395, 'AKP 5.2 EP.1', 1, 'Rumah sakit telah menetapkan  proses  untuk  mengelola pasien rawat jalan dan rawat inap yang menolak rencana asuhan medis termasuk  keluar  rumah sakit atas permintaan sendiri dan pasien yang menghendaki penghentian pengobatan.', '5.2', '', '', 10, 1381, 80, 0, 2025, 1, 'Penetapan tentang proses mengelola pasien rawat jalan dan rawat inap yang menolak rencana asuhan medis termasuk keluar rumah sakit atas permintaan sendiri dan pasien yang menghendaki penghentian pengobatan.', NULL, NULL, NULL, NULL, '2025-07-01 15:13:28', 0, 'A'),
(5396, 'AKP 5.2 EP.2', 2, 'Ada bukti pemberian edukasi kepada pasien tentang risiko medis akibat asuhan medis yang belum lengkap.', '5.2', '', '', 10, 1381, 80, 0, 2025, 1, NULL, 'Bukti pelaksanaan pemberian edukasi kepada pasien tentang risiko medis akibat asuhan medis yang belum lengkap. Risiko terhadap dirinya atau lingkungan sekitarnya.', NULL, 'DPJP', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5397, 'AKP 5.2 EP.3', 3, 'Pasien keluar rumah sakit atas permintaan sendiri, tetapi tetap mengikuti proses pemulangan pasien.', '5.2', '', '', 10, 1381, 80, 0, 2025, 1, NULL, 'Bukti pelaksanaan pasien keluar RS atas permintaan sendiri tetap mengikuti proses pemulangan pasien', NULL, '-	DPJP\r\n-	PPJA\r\n-	Kepala ruang unit pelayanan', NULL, '2025-07-01 15:14:13', 0, 'A'),
(5398, 'AKP 5.2 EP.4', 4, 'Dokter keluarga (bila ada) atau dokter yang memberi asuhan berikutnya kepada pasien diberitahu tentang kondisi tersebut.', '5.2', '', '', 10, 1381, 80, 0, 2025, 1, NULL, 'Bukti pelaksanaan pemberian informasi kepada dokter keluarga atau dokter yang memberi asuhan berikutnya terkait pasien yang pulang atas permintaan sendiri pada EP 2)', NULL, '-	DPJP\r\n-	PPJA\r\n-	Kepala ruang unit pelayanan', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5399, 'AKP 5.2 EP.5', 5, 'Ada dokumentasi rumah sakit melakukan pengkajian untuk mengetahui alasan pasien keluar rumah sakit apakah permintaan sendiri, menolak asuhan medis, atau tidak melanjutkan program pengobatan.', '5.2', '', '', 10, 1381, 80, 0, 2025, 1, NULL, 'Bukti dokumentasi dan evaluasi berupa pengkajian untuk mengetahui alasan pasien keluar rumah sakit apakah permintaan sendiri, menolak asuhan medis, atau tidak melanjuntukan program pengobatan, baik individual maupun agregat per satuan waktu.', NULL, '-	Kepala unit pelayanan\r\n-	Unit Mutu/ PMKP', NULL, '2025-07-01 15:15:16', 0, 'A'),
(5400, 'AKP 5.3 EP.1', 1, 'Ada regulasi yang mengatur pasien rawat inap dan rawat jalan yang meninggalkan rumah sakit tanpa pemberitahuan (melarikan diri).', '5.3', '', '', 10, 1382, 80, 0, 2025, 1, 'Regulasi tentang pengaturan pasien rawat inap dan rawat jalan yang meninggalkan rumah sakit tanpa pemberitahuan (melarikan diri) antara lain pencatatan di rekam medis, identifikasi pasien yang cenderung membahayakan dirinya (misalnya bunuh diri), atau linkungannya (misalnya penyakit menular, pasien agresif)', NULL, NULL, NULL, NULL, '2025-07-01 15:15:40', 0, 'A'),
(5401, 'AKP 5.3 EP.2', 2, 'Rumah sakit melakukan identifikasi pasien menderita penyakit yang membahayakan dirinya sendiri atau lingkungan.', '5.3', '', '', 10, 1382, 80, 0, 2025, 1, NULL, 'Bukti pelaksanaan identifikasi pasien menderita penyakit yang membahayakan dirinya sendiri atau lingkungan. Pencatatan dilakukan di pengkajian awal.', NULL, 'Staf klinis.', NULL, '2025-07-01 15:16:00', 0, 'A'),
(5402, 'AKP 5.3 EP.3', 3, 'Rumah sakit melaporkan kepada pihak  yang  berwenang bila ada indikasi kondisi pasien yang membahayakan dirinya sendiri atau lingkungan.', '5.3', '', '', 10, 1382, 80, 0, 2025, 1, NULL, 'Bukti pemberian laporan kepada pihak yang berwenang bila ada indikasi kondisi pasien yang membahayakan dirinya sendiri atau lingkungan', NULL, '-	Direktur RS\r\n-	Manajer terkait', NULL, '2025-07-01 15:16:15', 0, 'A'),
(5403, 'AKP 5.4 EP.1', 1, 'Ada regulasi tentang rujukan sesuai dengan peraturan perundang-undangan.', '5.4', '', '', 10, 1383, 80, 0, 2025, 1, 'Regulasi tentang rujukan sesuai dengan peraturan perundangundangan.', NULL, NULL, NULL, NULL, '2025-07-01 15:16:34', 0, 'A'),
(5404, 'AKP 5.4 EP.2', 2, 'Rujukan pasien dilakukan sesuai dengan kebutuhan kesinambungan asuhan pasien.', '5.4', '', '', 10, 1383, 80, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan rujukan pasien sesuai dengan kebutuhan kesinambungan asuhan pasien', NULL, NULL, NULL, '2025-07-01 15:16:44', 0, 'A'),
(5405, 'AKP 5.4 EP.3', 3, 'Rumah sakit yang merujuk  memastikan  bahwa  fasilitas kesehatan yang menerima dapat memenuhi kebutuhan pasien yang dirujuk.', '5.4', '', '', 10, 1383, 80, 0, 2025, 1, NULL, 'Bukti tentang kepastian fasilitas kesehatan yang menerima dapat memenuhi kebutuhan pasien yang dirujuk.', NULL, '-	DPJP\r\n-	Staf keperawatan\r\n-	Petugas Ambulans', NULL, '2025-07-01 15:17:05', 0, 'A'),
(5406, 'AKP 5.4 EP.4', 4, 'Ada kerjasama rumah sakit yang merujuk dengan rumah sakit yang menerima rujukan yang sering dirujuk.', '5.4', '', '', 10, 1383, 80, 0, 2025, 1, 'Regulasi tentang kerjasama rumah sakit yang merujuk dengan rumah sakit yang sering dirujuk.', NULL, NULL, NULL, NULL, '2025-07-01 15:17:29', 0, 'A'),
(5407, 'AKP 5.5 EP.1', 1, 'Rumah sakit memiliki staf yang bertanggung jawab dalam pengelolaan rujukan termasuk untuk memastikan pasien diterima di rumah sakit rujukan yang dapat memenuhi kebutuhan pasien.', '5.5', '', '', 10, 1384, 80, 0, 2025, 1, 'Regulasi tentang penetapan staf yang  bertanggung jawab dalam pengelolaan rujukan  termasuk untuk memastikan pasien diterima dirumah sakit rujukan yang dapat memenuhi  kebutuhan pasien.', NULL, NULL, NULL, NULL, '2025-07-01 15:17:40', 0, 'A'),
(5408, 'AKP 5.5 EP.2', 2, 'Selama proses rujukan ada staf yang kompeten sesuai dengan kondisi pasien yang selalu memantau dan mencatatnya dalam rekam medis.', '5.5', '', '', 10, 1384, 80, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan proses rujukan ada staf yang kompeten sesuai dengan kondisi pasien dan yang selalu memantau dan mencatatnya dalam rekam medis.', NULL, '-	Staf keperawatan\r\n-	Petugas pendamping', NULL, '2025-07-01 15:18:00', 0, 'A'),
(5409, 'AKP 5.5 EP.3', 3, 'Selama proses rujukan tersedia obat, bahan medis  habis pakai, alat kesehatan, dan  peralatan  medis  sesuai dengan kebutuhan kondisi pasien.', '5.5', '', '', 10, 1384, 80, 0, 2025, 1, NULL, NULL, 'Lihat ketersediaan obat,  bahan medis habis pakai, alat kesehatan, dan peralatan medis sesuai dengan kebutuhan kondisi pasien selama proses rujukan', '-	Staf keperawatan\r\n-	Staf farmasi', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5410, 'AKP 5.5 EP.4', 4, 'Rumah sakit memiliki proses serah terima  pasien antara staf pengantar dan yang menerima.', '5.5', '', '', 10, 1384, 80, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan  serah terima pasien antara staf pengantar dan yang menerima dalam form rujukan', NULL, '-	Staf terkait\r\n-	Petugas ambulans', NULL, '2025-07-01 15:20:19', 0, 'A'),
(5411, 'AKP 5.6 EP.1', 1, 'Dokumen rujukan berisi nama dari fasilitas pelayanan kesehatan yang menerima dan nama orang yang menyetujui menerima pasien.', '5.6', '', '', 10, 1385, 80, 0, 2025, 1, NULL, '1)	Bukti form rujukan berisi minimal poin a) – f) di maksud dan tujuan :\r\na)	identitas pasien; \r\nb)	hasil pemeriksaan (anamesis, pemeriksaan fisis, dan pemeriksaan penunjang) yang telah dilakukan; \r\nc)	diagnosis kerja; \r\nd)	terapi dan/atau tindakan yang telah diberikan; \r\ne)	tujuan rujukan; dan \r\nf)	nama dan tanda tangan tenaga kesehatan yang memberikan pelayanan rujukan.\r\n2)	Bukti form rujukan memuat nama dari fasilitas pelayanan kesehatan yang menerima dan nama orang yang menyetujui menerima pasien.', NULL, NULL, NULL, '2025-07-01 15:21:15', 0, 'A'),
(5412, 'AKP 5.6 EP.2', 2, 'Dokumen rujukan berisi alasan pasien  dirujuk,  memuat kondisi pasien, dan  kebutuhan  pelayanan lebih lanjut.', '5.6', '', '', 10, 1385, 80, 0, 2025, 1, NULL, 'Bukti form rujukan memuat alasan pasien dirujuk,  memuat kondisi pasien, dan kebutuhan pelayanan lebih lanjut', NULL, NULL, NULL, '2025-07-01 15:21:37', 0, 'A'),
(5413, 'AKP 5.6 EP.3', 3, 'Dokumen rujukan juga memuat prosedur dan  intervensi yang sudah dilakukan.', '5.6', '', '', 10, 1385, 80, 0, 2025, 1, NULL, 'Bukti form rujukan  memuat prosedur dan intervensi yang sudah dilakukan', NULL, NULL, NULL, '2025-07-01 15:21:45', 0, 'A'),
(5414, 'AKP 5.6 EP.4', 4, 'Proses rujukan dievaluasi dalam aspek mutu dan keselamatan pasien.', '5.6', '', '', 10, 1385, 80, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan evaluasi proses rujukan dalam aspek mutu dan keselamatan pasien.', NULL, NULL, NULL, '0000-00-00 00:00:00', 0, 'A'),
(5415, 'AKP 5.7 EP.1', 1, 'Rumah sakit telah menetapkan kriteria pasien rawat jalan dengan asuhan yang kompleks atau yang diagnosisnya kompleks diperlukan  Profil  Ringkas Medis Rawat Jalan (PRMRJ) meliputi poin a)-d) dalam maksud tujuan.', '5.7', '', '', 10, 1386, 80, 0, 2025, 1, 'Regulasi tentang penetapan kriteria pasien rawat jalan yang  asuhannya kompleks sehingga memerlukan lembar ringkasan PRMRJ meliputi:\r\na)	Identifikasi pasien yang menerima asuhan kompleks atau dengan diagnosis kompleks. \r\nb)	Identifikasi informasi yang dibutuhkan oleh para dokter penanggung jawab pelayanan (DPJP) yang menangani pasien tersebut \r\nc)	Menentukan proses yang digunakan untuk memastikan bahwa informasi medis yang dibutuhkan dokter penanggung jawab pelayanan (DPJP) tersedia dalam format mudah ditelusur (easy-to-retrieve) dan mudah di-review. \r\nd)	Evaluasi hasil implementasi proses untuk mengkaji bahwa informasi dan proses memenuhi kebutuhan dokter penanggung jawab.', NULL, NULL, NULL, NULL, '2025-07-01 15:23:03', 0, 'A'),
(5416, 'AKP 5.7 EP.2', 2, 'Rumah sakit memiliki proses yang dapat dibuktikan bahwa PRMRJ mudah ditelusur dan mudah di-review.', '5.7', '', '', 10, 1386, 80, 0, 2025, 1, NULL, 'Bukti pelaksanaan/ adanya lembar ringkasan PRMRJ.', NULL, NULL, 'Peragaan bahwa PRMRJ mudah ditelusur dan mudah di-review.', '2025-07-01 15:23:39', 0, 'A'),
(5417, 'AKP 5.7 EP.3', 3, 'Proses tersebut dievaluasi  untuk  memenuhi  kebutuhan para DPJP dan meningkatkan mutu serta keselamatan pasien.', '5.7', '', '', 10, 1386, 80, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan evaluasi proses pada EP 2 untuk peningkatan mutu dan keselamatan pasien.', NULL, '-	Staf klinis\r\n-	Staf Rekam Medis\r\n-	Komite mutu RS.', NULL, '2025-07-01 15:24:29', 0, 'A'),
(5418, 'AKP 6 EP.1', 1, 'Rumah sakit memiliki proses transportasi  pasien  sesuai dengan kebutuhannya yang meliputi pengkajian kebutuhan transportasi, SDM, obat,  bahan  medis  habis pakai, alat kesehatan, peralatan medis dan persyaratan PPI yang sesuai dengan kebutuhan pasien.', '6', '', '', 10, 1387, 80, 0, 2025, 1, NULL, 'Bukti tentang pengkajian:\r\n1)	kebutuhan transportasi pasien,\r\n2)	SDM : pendamping pasien\r\n3)	obat, bahan medis habis pakai, alat kesehatan, peralatan medis dan\r\n4)	persyaratan PPI yang sesuai dengan kebutuhan pasien untuk proses transportasi pasien.', NULL, 'Staf klinis.', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5419, 'AKP 6 EP.2', 2, 'Bila rumah sakit memiliki kendaraan transport sendiri, ada bukti pemeliharan kendaraan tersebut sesuai dengan peraturan perundang-undangan.', '6', '', '', 10, 1387, 80, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan pemeliharan kendaraan tersebut', NULL, '-	Staf terkait\r\n-	Sopir ambulans', NULL, '2025-07-01 15:25:13', 0, 'A'),
(5420, 'AKP 6 EP.3', 3, 'Bila rumah sakit bekerja sama dengan jasa transportasi pasien mandiri, ada bukti kerja sama tersebut dan evaluasi berkala dari rumah sakit mengenai kelayakan kendaraan transportasi, memenuhi aspek mutu, keselamatan pasien dan keselamatan transportasi. ', '6', '', '', 10, 1387, 80, 0, 2025, 1, NULL, 'Bukti kontrak layanan transportasi  dan pelaksanaan evaluasi berkala dari rumah sakit mengenai  kelayakan kendaraan transportasi, memenuhi aspek mutu, keselamatan pasien dan keselamatan transportasi sesuai kontrak kerja sama', NULL, '-	Staf terkait\r\n-	Sopir ambulans.', NULL, '2025-07-01 15:25:32', 0, 'A'),
(5421, 'AKP 6 EP.4', 4, 'Kriteria alat transportasi yang digunakan untuk merujuk, memindahkan, atau memulangkan pasien ditentukan oleh rumah sakit (staf yang kompeten), harus sesuai dengan Program PPI, memenuhi aspek mutu, keselamatan pasien dan keselamatan transportasi.', '6', '', '', 10, 1387, 80, 0, 2025, 1, 'Regulasi tentang kriteria alat transportasi yang digunakan untuk merujuk, memindahkan, atau memulangkan pasien harus sesuai dengan program PPI, memenuhi aspek mutu, keselamatan pasien dan keselamatan transportasi.', NULL, NULL, NULL, NULL, '2025-07-01 15:25:48', 0, 'A'),
(5422, 'HPK 1 EP.1', 1, 'Rumah sakit menerapkan regulasi hak pasien dan keluarga sebagaimana tercantum dalam poin a) sampai d) pada gambaran umum dan peraturan perundang- undangan.', '1', '', '', 10, 1388, 81, 0, 2025, 1, NULL, 'Bukti tentang penerapan tentang hak  dan kewajiban pasien dan keluarga  sesuai regulasi, meliputi;\r\na)	Mengidentifikasi, melindungi, dan mempromosikan hak-hak pasien;\r\nb)	Menginformasikan pasien tentang hak-hak mereka;\r\nc)	Melibatkan keluarga pasien, bila perlu, dalam keputusan tentang perawatan pasien;\r\nd)	Mendapatkan persetujuan (informed consent);\r\ne)	Mendidik staf tentang hak pasien', NULL, NULL, NULL, '2025-07-01 15:26:44', 0, 'A'),
(5423, 'HPK 1 EP.2', 2, 'Rumah sakit memiliki proses untuk mengidentifikasi      siapa yang diinginkan pasien untuk berpartisipasi dalam pengambilan keputusan terkait perawatannya.', '1', '', '', 10, 1388, 81, 0, 2025, 1, NULL, 'Bukti dokumen proses identifikasi penetapan pihak  yang diijinkan  pasien untuk berpartisipasi dalam pengambilan keputusan terkait perawatannya.', NULL, '-	Staf klinis\r\n-	Staf pendaftaran\r\n-	Pasien dan keluarga', NULL, '2025-07-01 15:27:01', 0, 'A'),
(5424, 'HPK 1 EP.3', 3, 'Rumah sakit memiliki proses untuk menentukan preferensi pasien, dan pada beberapa keadaan preferensi keluarga pasien, dalam menentukan informasi apa mengenai perawatan pasien yang dapat diberikan kepada keluarga/pihak lain, dan dalam  situasi apa.', '1', '', '', 10, 1388, 81, 0, 2025, 1, NULL, 'Ada bukti dokumen proses persetujuan pasien tentang informasi mengenai perawatan pasien yang   dapat diberikan kepada keluarga/pihak lain termasuk situasi tertentu (contoh; keadaan pasien kritis atau terkait penyakit menular).', NULL, '-	Staf klinis\r\n-	Staf pendaftaran\r\n-	Pasien dan keluarga', NULL, '2025-07-01 15:27:18', 0, 'A'),
(5425, 'HPK 1 EP.4', 4, 'Semua staff dilatih tentang proses dan peran mereka dalam mendukung hak-hak serta partisipasi  pasien  dan keluarga dalam perawatan.', '1', '', '', 10, 1388, 81, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan pelatihan tentang proses dan peran dalam mendukung hak-hak serta partisipasi pasien dan keluarga dalam perawatan, meliputi TOR, undangan, daftar hadir, materi, laporan, evaluasi, sertifikat', NULL, '-	Kepala diklat\r\n-	Staf klinis', NULL, '2025-07-01 15:27:39', 0, 'A'),
(5426, 'HPK 1.1 EP.1', 1, 'Rumah mengidentifikasi hambatan serta menerapkan proses untuk mengurangi hambatan bagi pasien dalam mendapatkan akses, proses penerimaan dan pelayanan perawatan.', '1.1', '', '', 10, 1389, 81, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan  identifikasi hambatan serta menerapkan proses untuk mengurangi hambatan bagi pasien dalam mendapatkan akses, proses penerimaan dan pelayanan perawatan.', NULL, '-	Staf Admisi\r\n-	Staf klinis\r\n-	Pasien/keluarga', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5427, 'HPK 1.1 EP.2', 2, 'Informasi terkait aspek perawatan dan tata laksana medis pasien diberikan dengan cara dan bahasa yang dipahami pasien.', '1.1', '', '', 10, 1389, 81, 0, 2025, 1, NULL, 'Bukti tentang dokumen pemberian informasi terkait aspek perawatan dan tata laksana medis pasien diberikan dengan cara dan bahasa yang dipahami pasien.', NULL, '-	Staf Admisi\r\n-	Staf klinis', NULL, '2025-07-01 15:28:14', 0, 'A'),
(5428, 'HPK 1.2 EP.1', 1, 'Staf memberikan perawatan yang penuh penghargaan dengan memerhatikan harkat dan martabat pasien.', '1.2', '', '', 10, 1390, 81, 0, 2025, 1, NULL, NULL, NULL, '-	Staf klinis\r\n-	Pasien/keluarga', 'Simulasi tentang pelaksanaan memberikan perawatan yang penuh penghargaan dengan memerhatikan harkat dan martabat pasien.', '2025-07-01 15:29:01', 0, 'A'),
(5429, 'HPK 1.1 EP.3', 3, 'Informasi mengenai hak dan tanggung jawab pasien terpampang di area rumah sakit atau diberikan kepada setiap pasien secara tertulis atau dalam metode lain dalam bahasa yang dipahami pasien.', '1.1', '', '', 10, 1389, 81, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan  pemberian informasi mengenai hak dan tanggung jawab pasien terpampang di area rumah sakit atau diberikan kepada setiap pasien secara tertulis atau dalam metode lain dalam bahasa yang dipahami pasien', 'Lihat Informasi mengenai hak dan tanggung jawab pasien terpampang di area rumah sakit', '-	Staf Admisi\r\n-	Pasien/keluarga', NULL, '2025-07-01 15:28:43', 0, 'A'),
(5430, 'HPK 1.2 EP.2', 2, 'Rumah sakit menghormati keyakinan spiritual dan budaya pasien serta nilai-nilai yang dianut pasien.', '1.2', '', '', 10, 1390, 81, 0, 2025, 1, NULL, 'Bukti tentang identifikasi untuk menghormati keyakinan spiritual dan budaya pasien serta nilai-nilai yang dianut pasien.', NULL, '-	Staf klinis\r\n-	Pasien/keluarga', NULL, '2025-07-01 15:29:21', 0, 'A'),
(5431, 'HPK 1.2 EP.3', 3, 'Rumah sakit memenuhi kebutuhan pasien terhadap bimbingan rohani.', '1.2', '', '', 10, 1390, 81, 0, 2025, 1, NULL, 'Ada bukti rumah sakit memenuhi kebutuhan pasien terhadap bimbingan rohani berupa;\r\n1)	Bukti kerjasama dengan rohaniawan\r\n2)	Bukti permintaan pelayanan rohani\r\n3)	Bukti pelaksanaan pelayanan rohani', NULL, '-	Staf klinis\r\n-	Pasien/keluarga', NULL, '2025-07-01 15:29:43', 0, 'A'),
(5432, 'HPK 1.3 EP.1', 1, 'Rumah sakit menjamin kebutuhan privasi pasien selama perawatan dan pengobatan di rumah sakit.', '1.3', '', '', 10, 1391, 81, 0, 2025, 1, NULL, 'Ada bukti rumah sakit menjamin kebutuhan privasi pasien selama perawatan dan pengobatan di rumah sakit.', 'Bukti implementasi rumah sakit menjamin kebutuhan privasi pasien selama perawatan dan pengobatan di rumah sakit.', '-	Staf Admisi\r\n-	Staf klinis', NULL, '2025-07-01 15:30:16', 0, 'A'),
(5433, 'HPK 1.3 EP.2', 2, 'Kerahasiaan informasi pasien dijaga sesuai dengan peraturan perundangan.', '1.3', '', '', 10, 1391, 81, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan kerahasiaan informasi pasien dijaga sesuai dengan peraturan perundangan', NULL, '-	Staf klinis\r\n-	Pasien/keluarga', NULL, '2025-07-01 15:30:38', 0, 'A'),
(5434, 'HPK 1.3 EP.3', 3, 'Rumah sakit memiliki proses untuk meminta persetujuan pasien terkait pemberian informasi.', '1.3', '', '', 10, 1391, 81, 0, 2025, 1, NULL, 'Ada bukti rumah sakit memiliki proses untuk meminta persetujuan pasien terkait pemberian informasi.', NULL, '-	Staf klinis\r\n-	Pasien/keluarga', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5435, 'HPK 1.3 EP.4', 4, 'Rumah sakit memiliki proses untuk memberikan pasien akses terhadap informasi kesehatan mereka.', '1.3', '', '', 10, 1391, 81, 0, 2025, 1, NULL, 'Ada bukti rumah sakit memiliki proses untuk memberikan pasien akses terhadap informasi kesehatan mereka', NULL, '-	Staf klinis\r\n-	Pasien/keluarga', NULL, '2025-07-01 15:31:15', 0, 'A'),
(5436, 'HPK 1.4 EP.1', 1, 'Rumah sakit menetapkan proses untuk mencatat dan melindungi pertanggungjawaban harta benda pasien.', '1.4', '', '', 10, 1392, 81, 0, 2025, 1, 'Regulasi tentang penetapan proses untuk mencatat dan melindungi serta pertanggungjawaban terhadap harta benda pasien', NULL, NULL, NULL, NULL, '2025-07-01 15:31:26', 0, 'A'),
(5437, 'HPK 1.4 EP.2', 2, 'Pasien mendapat informasi mengenai tanggung jawab rumah sakit untuk melindungi harta benda pribadi mereka.', '1.4', '', '', 10, 1392, 81, 0, 2025, 1, NULL, 'Ada bukti pasien mendapat\r\ninformasi mengenai tanggung jawab rumah sakit untuk melindungi harta benda pribadi mereka', 'Tempat penyimpanan barang milik pasien', '-	Staf klinis\r\n-	Staf terkait\r\n-	Pasien/keluarga', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5438, 'HPK 1.5 EP.1', 1, 'Rumah sakit mengembangkan dan menerapkan proses untuk melindungi semua pasien dari serangan  fisik  dan verbal.', '1.5', '', '', 10, 1393, 81, 0, 2025, 1, NULL, NULL, 'Bukti penerapan proses untuk melindungi semua pasien dari serangan fisik dan verbal.', '-	Staf terkait\r\n-	Pasien/keluarga', NULL, '2025-07-01 15:32:12', 0, 'A'),
(5439, 'HPK 1.5 EP.2', 2, 'Rumah sakit mengidentifikasi populasi yang memiliki risiko lebih tinggi untuk mengalami serangan.', '1.5', '', '', 10, 1393, 81, 0, 2025, 1, 'Regulasi tentang   populasi yang memiliki risiko lebih tinggi untuk mengalami serangan, misalnya; bayi, pasien koma, pasien dengan kelemahan fisik', NULL, NULL, NULL, NULL, '2025-07-01 15:32:22', 0, 'A'),
(5440, 'HPK 1.5 EP.3', 3, 'Rumah sakit memantau area fasilitas yang terisolasi  dan terpencil.', '1.5', '', '', 10, 1393, 81, 0, 2025, 1, NULL, NULL, 'Lihat pelaksanaan perlindungan pasien di daerah terpencil/terisolasi/rawan, seperti: pengawasan berkala, CCTV yang adekuat, pengunjung diluar jam kunjungan memakai identitas, dsb', 'Staf terkait', NULL, '2025-07-01 15:32:40', 0, 'A'),
(5441, 'HPK 2 EP.1', 1, 'Rumah sakit menerapkan proses untuk mendukung pasien dan keluarga terlibat dan berpartisipasi dalam proses asuhan dan dalam pengambilan keputusan.', '2', '', '', 10, 1394, 81, 0, 2025, 1, NULL, 'Bukti tentang penerapan proses untuk mendukung pasien dan keluarga terlibat dan berpartisipasi dalam proses perawatan dan dalam pengambilan keputusan.', NULL, '-	Staf klinis\r\n-	Pasien/keluarga\r\nLihat juga HPK 4.1 EP 1, KE 4 EP 2', NULL, '2025-07-01 15:33:01', 0, 'A'),
(5442, 'HPK 2 EP.2', 2, 'Rumah sakit menerapkan proses untuk memberikan edukasi kepada pasien dan keluarganya mengenai kondisi medis, diagnosis, serta rencana perawatan dan terapi yang diberikan.', '2', '', '', 10, 1394, 81, 0, 2025, 1, NULL, 'Bukti tentang penerapan proses untuk memberikan edukasi kepada pasien dan keluarganya mengenai kondisi medis, diagnosis, serta rencana perawatan dan terapi yang diberikan.\r\n\r\n-	Staf klinis\r\n-	Pasien/keluarga', NULL, '(Lihat juga KE 4 EP 2)', NULL, '2025-07-01 15:33:30', 0, 'A'),
(5443, 'HPK 2 EP.3', 3, 'Pasien diberikan informasi mengenai hasil asuhan dan tata laksana yang diharapkan.', '2', '', '', 10, 1394, 81, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan pemberian informasi mengenai hasil perawatan yang diharapkan dan tata laksana yang direncanakan.', NULL, '-	Staf klinis\r\n-	Pasien/keluarga', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5444, 'HPK 2 EP.4', 4, 'Pasien diberikan informasi mengenai kemungkinan hasil yang tidak dapat diantisipasi dari terapi dan perawatan.', '2', '', '', 10, 1394, 81, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan pemberian informasi mengenai kemungkinan hasil yang tidak dapat diantisipasi dari terapi dan perawatan', NULL, '-	Staf klinis\r\n-	Pasien/keluarga', NULL, '2025-07-01 15:34:13', 0, 'A'),
(5445, 'HPK 2 EP.5', 5, 'Rumah sakit memfasilitasi permintaan pasien untuk mencari pendapat kedua tanpa perlu khawatir akan mempengaruhi perawatannya selama di dalam atau  luar rumah sakit.', '2', '', '', 10, 1394, 81, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan  rumah sakit memfasilitasi permintaan pasien untuk memperoleh (second opinion) pendapat kedua tanpa perlu khawatir akan mempengaruhi perawatannya selama di dalam atau luar rumah sakit.', NULL, '-	Staf klinis\r\n-	Pasien/keluarga', NULL, '2025-07-01 15:34:29', 0, 'A'),
(5446, 'HPK 2.1 EP.1', 1, 'Rumah sakit menerapkan proses mengenai pemberian pelayanan resusitasi dan penghentian  terapi  penunjang kehidupan untuk pasien.', '2.1', '', '', 10, 1395, 81, 0, 2025, 1, NULL, 'Bukti rumah sakit menerapkan proses mengenai penghentian pelayanan resusitasi dan penghentian terapi penunjang kehidupan untuk pasien', NULL, 'Staf klinis', NULL, '2025-07-01 15:34:48', 0, 'A'),
(5447, 'HPK 2.1 EP.2', 2, 'Rumah sakit memberi informasi kepada pasien dan keluarga mengenai hak mereka untuk menolak atau menghentikan terapi, konsekuensi  dari  keputusan yang dibuat serta terapi dan alternatif lain yang dapat dijadikan pilihan.', '2.1', '', '', 10, 1395, 81, 0, 2025, 1, NULL, 'Bukti pemberian informasi kepada pasien dan keluarga mengenai hak mereka untuk menolak atau menghentikan terapi, konsekuensi dari keputusan yang dibuat serta terapi dan alternatif lain yang dapat dijadikan pilihan.', NULL, '-	Staf klinis\r\n-	Pasien / keluarga', NULL, '2025-07-01 15:35:08', 0, 'A'),
(5448, 'HPK 2.2 EP.1', 1, 'Rumah sakit menerapkan proses untuk menghargai  dan mendukung hak pasien mendapatkan pengkajian dan pengelolaan nyeri.', '2.2', '', '', 10, 1396, 81, 0, 2025, 1, NULL, 'Bukti penerapan proses untuk menghargai dan mendukung hak pasien mendapatkan pengkajian dan pengelolaan nyeri.', NULL, '-	DPJP/PPJA/PPA lainnya\r\n-	Staf klinis keperawatan\r\n-	Pasien', NULL, '2025-07-01 15:35:27', 0, 'A'),
(5449, 'HPK 2.2 EP.2', 2, 'Rumah sakit menerapkan proses untuk menghargai  dan mendukung hak pasien untuk mendapatkan pengkajian dan pengelolaan terhadap kebutuhan  pasien menjelang akhir hayat.', '2.2', '', '', 10, 1396, 81, 0, 2025, 1, NULL, 'Bukti penerapan  proses untuk menghargai dan mendukung hak pasien untuk mendapatkan pengkajian dan pengelolaan terhadap kebutuhan pasien menjelang akhir hayat.', NULL, '-	DPJP/PPJA/PPA lainnya\r\n-	Staf klinis keperawatan\r\n-	Pasien', NULL, '2025-07-01 15:35:44', 0, 'A'),
(5450, 'HPK 3 EP.1', 1, 'Pasien diberikan informasi mengenai proses untuk menyampaikan keluhan dan proses yang harus dilakukan pada saat terjadi konflik/perbedaan  pendapat pada proses perawatan.', '3', '', '', 10, 1397, 81, 0, 2025, 1, NULL, 'Bukti Pasien diberikan informasi mengenai proses untuk menyampaikan keluhan dan proses yang harus dilakukan pada saat terjadi konflik/perbedaan pendapat pada proses perawatan', NULL, '-	Staf pendaftaran\r\n-	Staf klinis\r\n-	Customer service\r\n-	Pasien / keluarga', NULL, '2025-07-01 15:36:03', 0, 'A'),
(5451, 'HPK 3 EP.2', 2, 'Keluhan, konflik, dan perbedaan pendapat tersebut dikaji dan diselesaikan oleh unit/petugas yang bertanggung jawab melalui sebuah  alur/proses  spesifik.', '3', '', '', 10, 1397, 81, 0, 2025, 1, NULL, 'Bukti dokumentasi  keluhan, konflik, dan perbedaan pendapat tersebut dikaji dan diselesaikan oleh unit/petugas yang bertanggung jawab melalui sebuah alur/proses spesifik.', NULL, '-	Staf klinis\r\n-	Customer service\r\n-	Pasien / keluarga', NULL, '2025-07-01 15:36:24', 0, 'A'),
(5452, 'HPK 3 EP.3', 3, 'Pasien dan keluarga berpartisipasi dalam proses penyelesaian keluhan, konflik, dan perbedaan  pendapat.', '3', '', '', 10, 1397, 81, 0, 2025, 1, NULL, 'Bukti dokumentasi  pasien dan keluarga berpartisipasi dalam proses penyelesaian keluhan, konflik, dan perbedaan pendapat', NULL, '-	Staf klinis\r\n-	Customer service\r\n-	Pasien / keluarga', NULL, '2025-07-01 15:36:38', 0, 'A'),
(5453, 'HPK 4 EP.1', 1, 'Rumah sakit menerapkan proses bagaimana persetujuan umum didokumentasikan dalam rekam medis pasien.', '4', '', '', 10, 1398, 81, 0, 2025, 1, NULL, 'Bukti dokumen persetujuan umum', NULL, '-	Staf admisi\r\n-	Staf rekam medis \r\n-	Pasien/keluarga', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5454, 'HPK 4 EP.2', 2, 'Pasien dan keluarga diberikan informasi mengenai pemeriksaan, tindakan dan pengobatan yang memerlukan informed consent.', '4', '', '', 10, 1398, 81, 0, 2025, 1, NULL, 'Bukti pemberian informasi kepada pasien dan keluarga diberikan informasi mengenai pemeriksaan, tindakan dan pengobatan yang memerlukan informed consent.', NULL, '-	DPJP\r\n-	PPJA/staf klinis\r\n-	Pasien/keluarga', NULL, '2025-07-01 15:37:14', 0, 'A'),
(5455, 'HPK 4 EP.3', 3, 'Pasien menerima informasi mengenai kemungkinan keterlibatan peserta didik, mahasiswa, residen traine dan fellow yang berpartisipasi dalam proses perawatan.', '4', '', '', 10, 1398, 81, 0, 2025, 1, NULL, 'Bukti Pasien menerima informasi mengenai kemungkinan keterlibatan peserta didik, mahasiswa, residen traine dan fellow yang berpartisipasi dalam proses perawatan.', NULL, '-	Staf admisi\r\n-	Pasien/keluarga', NULL, '2025-07-01 15:37:30', 0, 'A'),
(5456, 'HPK 4.1 EP.1', 1, 'Rumah sakit menerapkan proses bagi pasien untuk mendapatkan informed consent.', '4.1', '', '', 10, 1399, 81, 0, 2025, 1, NULL, 'Bukti penerapan proses bagi pasien untuk memberikan informed consent (persetujuan tindakan kedokteran)', NULL, '-	DPJP\r\n-	Dokter Anestesi\r\n-	Staf klinis\r\n-	Pasien/keluarga', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5457, 'HPK 4.1 EP.2', 2, 'Pemberian informed consent dilakukan oleh staf yang kompeten dan diberikan dengan cara dan bahasa yang mudah dipahami pasien.', '4.1', '', '', 10, 1399, 81, 0, 2025, 1, NULL, 'Bukti pelaksanaan informed consent dilakukan oleh staf yang kompeten dan diberikan dengan cara dan bahasa yang mudah dipahami pasien.', NULL, '-	DPJP\r\n-	Staf klinis', NULL, '2025-07-01 15:38:08', 0, 'A'),
(5458, 'HPK 4.1 EP.3', 3, 'Rumah sakit memiliki daftar tindakan invasif, pemeriksaan dan terapi tambahan yang memerlukan informed consent.', '4.1', '', '', 10, 1399, 81, 0, 2025, 1, 'Regulasi tentang  daftar tindakan invasif, pemeriksaan dan terapi tambahan yang memerlukan informed consent', NULL, NULL, NULL, NULL, '2025-07-01 15:38:17', 0, 'A'),
(5459, 'HPK 4.2 EP.1', 1, 'Rumah sakit menerapkan proses untuk pemberian informed consent oleh orang lain selain pasien sesuai peraturan perundangan yang berlaku.', '4.2', '', '', 10, 1400, 81, 0, 2025, 1, NULL, 'Bukti penerapan proses  proses untuk pemberian informed consent oleh orang lain selain pasien sesuai peraturan perundangan yang berlaku', NULL, '-	DPJP\r\n-	Dokter Anestesi\r\n-	Staf klinis\r\n-	Pasien/keluarga', NULL, '2025-07-01 15:38:48', 0, 'A'),
(5460, 'HPK 4.2 EP.2', 2, 'Rekam medis pasien mencantumkan (satu atau lebih) nama individu yang menyatakan persetujuan.', '4.2', '', '', 10, 1400, 81, 0, 2025, 1, NULL, 'Bukti dalam rekam medis mencantumkan (satu atau lebih) nama individu yang menyatakan persetujuan.', NULL, '-	Staf klinis\r\n-	Pasien/keluarga', NULL, '2025-07-01 15:39:05', 0, 'A'),
(5461, 'PP 1 EP.1', 1, 'Rumah sakit menetapkan regulasi tentang pengkajian awal dan pengkajian ulang medis dan keperawatan di unit gawat darurat, rawat inap dan rawat jalan.', '1', '', '', 10, 1401, 82, 0, 2025, 1, '1)	Regulasi tentang penetapan pengkajian awal dan pengkajian ulang medis dan keperawatan di unit gawat darurat, rawat inap dan rawat jalan. \r\n2)	Regulasi hanya PPA yang kompeten, diperbolehkan untuk melakukan pengkajian\r\n3)	Regulasi termasuk metode tiga proses utama sesuai poin a) – c)  pada Gambaran Umum yang disingkat sebagai metode IAR (Informasi-Analisis-Rencana).\r\n4)	Regulasi termasuk pada pasien tertentu misalnya nyeri, risiko jatuh, Pengkajian awal terdiri dari skrining (rapid assessment) dan pengkajian lanjutan\r\n5)	Regulasi terkait Pengkajian Ulang didokumentasikan di CPPT sesuai maksud dan tujuan PP 2.\r\n6)	Regulasi terkait interval Pengkajian Ulang sesuai dengan Std PP 2.\r\n7)	Regulasi termasuk adanya pengintegrasian dalam rencana asuhan  baik pengkajian awal maupun ulang. \r\nLihat Std PAP 1.2 di maksud dan tujuan : “DPJP sebagai ketua tim PPA melakukan evaluasi / reviu berkala dan verifikasi harian untuk memantau terlaksananya asuhan secara terintegrasi dan membuat notasi sesuai dengan kebutuhan.”', NULL, NULL, NULL, NULL, '0000-00-00 00:00:00', 0, 'A'),
(5462, 'PP 1 EP.2', 2, 'Rumah sakit menetapkan isi minimal pengkajian awal meliputi poin a) sampai m) pada maksud dan tujuan.', '1', '', '', 10, 1401, 82, 0, 2025, 1, '1)	Regulasi tentang penetapan isi minimal pengkajian awal meliputi poin a) – m):\r\na)	Keluhan saat ini \r\nb)	Status fisik; \r\nc)	Psiko-sosio-spiritual; \r\nd)	Ekonomi; \r\ne)	Riwayat kesehatan pasien; \r\nf)	Riwayat alergi; \r\ng)	Riwayat penggunaan obat; \r\nh)	Pengkajian nyeri; \r\ni)	Risiko jatuh; \r\nj)	Pengkajian fungsional; \r\nk)	Risiko nutrisional; \r\nl)	Kebutuhan edukasi; dan \r\nm)	Perencanaan pemulangan pasien (Discharge Planning). disertai kriteria pasien pada rawat inap\r\n2)	Regulasi tentang selesainya 24 jam pengkajian awal rawat inap (lihat PP 1.1. EP 1).', NULL, NULL, NULL, NULL, '0000-00-00 00:00:00', 0, 'A'),
(5463, 'PP 1 EP.3', 3, 'Hanya PPA yang kompeten, diperbolehkan untuk melakukan pengkajian sesuai  dengan  ketentuan  rumah sakit.', '1', '', '', 10, 1401, 82, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan dalam rekam medis hanya PPA yang kompeten, diperbolehkan untuk melakukan pengkajian sesuai dengan ketentuan rumah sakit.', NULL, '-	DPJP\r\n-	PPJA \r\n-	Kepala/staf unit rekam medis', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5464, 'PP 1 EP.4', 4, 'Perencanaanan pulang yang mencakup identifikasi kebutuhan khusus dan rencana untuk memenuhi kebutuhan tersebut, disusun sejak pengkajian awal.', '1', '', '', 10, 1401, 82, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan perencanaanan pemulangan pasien yang mencakup identifikasi kebutuhan khusus dan rencana untuk memenuhi kebutuhan tersebut, disusun sejak pengkajian awal', NULL, '-	DPJP\r\n-	PPJA \r\n-	MPP', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5465, 'PP 1.1 EP.1', 1, 'Pengkajian awal medis dan keperawatan dilaksanakan dan didokumentasikan dalam kurun waktu 24 jam pertama sejak pasien masuk rawat inap, atau  lebih  awal bila diperlukan sesuai dengan kondisi pasien.', '1.1', '', '', 10, 1402, 82, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan pengkajian awal medis dan keperawatan dilaksanakan dan didokumentasikan dalam kurun waktu 24 jam pertama sejak pasien masuk rawat inap, atau lebih awal bila diperlukan sesuai dengan kondisi pasien. (Lihat juga Std MRMIK 7).', NULL, '-	DPJP\r\n-	PPJA.', NULL, '2025-07-02 10:35:27', 0, 'A'),
(5466, 'PP 1.1 EP.2', 2, 'Pengkajian awal medis menghasilkan diagnosis medis yang mencakup kondisi utama dan kondisi lainnya  yang membutuhkan tata laksana dan pemantauan', '1.1', '', '', 10, 1402, 82, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan  pengkajian awal medis menghasilkan diagnosis medis yang mencakup kondisi utama dan kondisi lainnya yang membutuhkan tata laksana dan pemantauan.', NULL, 'DPJP.', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5467, 'PP 1.1 EP.3', 3, 'Pengkajian awal keperawatan menghasilkan diagnosis keperawatan untuk menentukan kebutuhan asuhan keperawatan, intervensi atau pemantauan pasien yang spesifik.', '1.1', '', '', 10, 1402, 82, 0, 2025, 1, NULL, '1)	Bukti tentang pelaksanaan  pengkajian awal keperawatan menghasilkan diagnosis keperawatan untuk menentukan kebutuhan asuhan keperawatan, intervensi atau pemantauan pasien yang spesifik. \r\n2)	Bukti evaluasi / reviu dan verifikasi harian oleh DPJP.', NULL, '-	PPJA\r\n-	DPJP.', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5468, 'PP 1.1 EP.4', 4, 'Sebelum pembedahan pada kondisi  mendesak,  minimal terdapat catatan singkat dan diagnosis praoperasi yang didokumentasikan di dalam rekam medik.', '1.1', '', '', 10, 1402, 82, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan  sebelum pembedahan pada kondisi mendesak, minimal terdapat catatan singkat dan diagnosis praoperasi  (Lihat PAB 7).', NULL, '-	DPJP\r\n-	PPJA.', NULL, '0000-00-00 00:00:00', 0, 'A');
INSERT INTO `accreditation_instrument` (`instrument_id`, `instrument_reference_code`, `instrument_order_id`, `instrument_name`, `instrument_objective`, `instrument_material`, `instrument_document`, `instrument_maximum_score`, `instrument_standard_id`, `instrument_chapter_id`, `instrument_class_id`, `instrument_version`, `instrument_institution_group_id`, `instrument_r`, `instrument_d`, `instrument_o`, `instrument_w`, `instrument_s`, `instrument_update`, `instrument_user_id`, `instrument_record_status`) VALUES
(5469, 'PP 1.1 EP.5', 5, 'Pengkajian medis yang dilakukan sebelum  masuk  rawat inap atau sebelum pasien menjalani prosedur di layanan rawat jalan rumah sakit harus  dilakukan  dalam waktu kurang atau sama dengan 30 (tiga puluh) hari sebelumnya. Jika lebih dari 30 (tiga puluh) hari, maka harus dilakukan pengkajian ulang.', '1.1', '', '', 10, 1402, 82, 0, 2025, 1, NULL, '1)	Pengkajian awal pasien  di rawat jalan dengan suatu diagnosis “X”, bila pasien berulang / kambuh dengan penyakit “X” dan datang kurang dari /sama dengan 30 hari, maka dilakukan pengkajian ulang.\r\n2)	Pengkajian awal pasien  di rawat jalan dengan suatu diagnosis “X”, bila pasien berulang / kambuh dengan penyakit “X” dan datang lebih dari 30 hari kemudian maka harus dilakukan pengkajian awal.', NULL, '-	DPJP\r\n-	PPJA.', NULL, '2025-07-02 12:04:23', 0, 'A'),
(5470, 'PP 1.1 EP.6', 6, 'Hasil dari seluruh pengkajian yang dikerjakan di luar rumah sakit ditinjau dan/atau diverifikasi pada saat      masuk rawat inap atau sebelum tindakan di unit rawat Jalan', '1.1', '', '', 10, 1402, 82, 0, 2025, 1, NULL, '1)	Pasien dari luar rumah sakit dan membawa informasi kesehatan akan menjalani proses pengkajian pasien terdiri dari tiga proses primer sesuai maksud dan tujuan a) – c) (proses IAR).\r\n2)	Bukti hasil dari seluruh pengkajian yang dikerjakan di luar rumah sakit ditinjau dan/atau diverifikasi pada saat masuk rawat inap atau sebelum tindakan di unit rawat jalan.', NULL, '-	DPJP\r\n-	PPJA.', NULL, '2025-07-02 12:38:40', 0, 'A'),
(5471, 'PP 1.2 EP.1', 1, 'Rumah sakit menetapkan kriteria risiko nutrisional yang dikembangkan bersama staf yang kompeten dan berwenang.', '1.2', '', '', 10, 1403, 82, 0, 2025, 1, 'Regulasi tentang penetapan kriteria risiko nutrisional yang dikembangkan bersama staf yang kompeten dan berwenang.', 'Bukti rapat keterlibatan staf yang kompeten dan berwenang dalam pembuatan regulasi tentang penetapan kriteria risiko nutrisional.', NULL, NULL, NULL, '2025-07-02 12:39:19', 0, 'A'),
(5472, 'PP 1.2 EP.2', 2, 'Pasien diskrining untuk risiko nutrisi sebagai bagian dari pengkajian awal.', '1.2', '', '', 10, 1403, 82, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan  pasien diskrining untuk risiko nutrisi sebagai bagian dari pengkajian awal. (Lihat Std PP  1 EP 2).', NULL, '-	PPJA\r\n-	Dietisien\r\n-	Pasien/keluarga.', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5473, 'PP 1.2 EP.3', 3, 'Pasien dengan risiko nutrisional dilanjutkan dengan pengkajian gizi.', '1.2', '', '', 10, 1403, 82, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan pasien dengan risiko nutrisional dilanjutkan dengan pengkajian gizi.', NULL, '-	PPJA\r\n-	Dietisien\r\n-	Pasien/keluarga.', NULL, '2025-07-02 12:42:43', 0, 'A'),
(5474, 'PP 1.2 EP.4', 4, 'Pasien diskrining untuk kebutuhan fungsional  termasuk risiko jatuh.', '1.2', '', '', 10, 1403, 82, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan pasien diskrining untuk kebutuhan fungsional termasuk risiko jatuh.', NULL, '-	PPJA\r\n-	Pasien/keluarga.', NULL, '2025-07-02 12:43:14', 0, 'A'),
(5475, 'PP 1.3 EP.1', 1, 'Rumah sakit menetapkan jenis populasi khusus yang akan dilakukan pengkajian meliputi poin - pada maksud dan tujuan.', '1.3', '', '', 10, 1404, 82, 0, 2025, 1, 'Regulasi tentang penetapan jenis populasi khusus yang akan dilakukan pengkajian meliputi antara lain poin a) - m) pada maksud dan tujuan:\r\na)	Neonatus. \r\nb)	Anak. \r\nc)	Remaja. \r\nd)	Obsteri / maternitas. \r\ne)	Geriatri. \r\nf)	Sakit terminal / menghadapi kematian. \r\ng)	Pasien dengan nyeri kronik atau nyeri (intense). \r\nh)	Pasien dengan gangguan emosional atau pasien psikiatris. \r\ni)	Pasien kecanduan obat terlarang atau alkohol. \r\nj)	Korban kekerasan atau kesewenangan. \r\nk)	Pasien dengan penyakit menular atau infeksius. \r\nl)	Pasien yang menerima kemoterapi atau terapi radiasi. \r\nm)	Pasien dengan sistem imunologi terganggu.', NULL, NULL, NULL, NULL, '2025-07-02 12:43:44', 0, 'A'),
(5476, 'PP 1.3 EP.2', 2, 'Rumah sakit  telah  melaksanakan  pengkajian tambahan terhadap populasi pasien khusus sesuai ketentuan rumah sakit.', '1.3', '', '', 10, 1404, 82, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan pengkajian tambahan terhadap populasi pasien khusus sesuai ketentuan rumah sakit.', NULL, '-	DPJP\r\n-	PPJA\r\n-	Kepala/staf unit rekam medis.', NULL, '2025-07-02 12:44:30', 0, 'A'),
(5477, 'PP 2 EP.1', 1, 'Rumah sakit melaksanakan pengkajian ulang oleh DPJP, perawat dan PPA lainnya untuk menentukan rencana asuhan lanjutan.', '2', '', '', 10, 1405, 82, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan  pengkajian ulang oleh DPJP, perawat dan PPA lainnya termasuk untuk menentukan rencana asuhan lanjutan.  (Sesuai IAR).\r\nCatatan: lihat juga  Std PAP 1.2 di maksud dan tujuan : “DPJP sebagai ketua tim PPA melakukan evaluasi / reviu berkala dan verifikasi harian untuk memantau terlaksananya asuhan secara terintegrasi dan membuat notasi sesuai dengan kebutuhan.”', NULL, '-	DPJP\r\n-	PPA lainnya.', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5478, 'PP 2 EP.2', 2, 'Terdapat bukti pelaksanaan pengkajian ulang medis dilaksanakan minimal satu kali sehari, termasuk akhir minggu/libur untuk pasien akut.', '2', '', '', 10, 1405, 82, 0, 2025, 1, NULL, 'Bukti tentang  pelaksanaan pengkajian ulang medis dilaksanakan minimal satu kali sehari, termasuk akhir minggu/libur untuk pasien akut.', NULL, '-	DPJP \r\n-	Pasien/keluarga.', NULL, '2025-07-02 12:45:21', 0, 'A'),
(5479, 'PP 2 EP.3', 3, 'Terdapat bukti pelaksanaan pengkajian ulang oleh perawat minimal satu kali per shift atau sesuai dengan perubahan kondisi pasien.', '2', '', '', 10, 1405, 82, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan pengkajian ulang oleh perawat minimal satu kali per shift atau sesuai dengan perubahan kondisi pasien.', NULL, '-	PPJA\r\n-	Pasien/keluarga.', NULL, '2025-07-02 12:45:47', 0, 'A'),
(5480, 'PP 2 EP.4', 4, 'Terdapat bukti pengkajian ulang oleh PPA lainnya dilaksanakan dengan interval sesuai regulasi rumah sakit.', '2', '', '', 10, 1405, 82, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan pengkajian ulang oleh PPA lainnya dilaksanakan dengan interval sesuai regulasi rumah sakit.', NULL, '-	PPA lainnya \r\n-	Pasien/keluarga.', NULL, '2025-07-02 12:46:06', 0, 'A'),
(5481, 'PP 3 EP.1', 1, 'Rumah sakit menetapkan regulasi tentang pelayanan laboratorium di rumah sakit.', '3', '', '', 10, 1406, 82, 0, 2025, 1, '1)	Regulasi tentang penetapan  pelayanan laboratorium terintegrasi di rumah sakit. (Sesuai penjelasan pada Maksud dan Tujuan).\r\n2)	Regulasi termasuk : \r\na.	pemeriksaan laboratorium  keluar melalui satu pintu : Laboratorium rumah sakit.\r\nb.	manajemen risiko laboratorium.\r\nc.	kondisi bila terjadi kekosongan reagensia. \r\nd.	kompetensi staf klinis dan nakes lainnya\r\ne.	tatakelola pelayanan darah dan produk darah.', NULL, NULL, NULL, NULL, '2025-07-02 12:46:30', 0, 'A'),
(5482, 'PP 3 EP.2', 2, 'Pelayanan laboratorium buka 24 jam, 7 (tujuh) hari seminggu, sesuai dengan kebutuhan pasien.', '3', '', '', 10, 1406, 82, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan pelayanan laboratorium buka 24 jam, 7 (tujuh) hari seminggu, sesuai dengan kebutuhan pasien.', NULL, 'Staf unit laboratorium.', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5483, 'PP 3.1 EP.1', 1, 'Direktur rumah sakit menetapkan penanggung jawab laboratorium yang memiliki kompetensi sesuai ketentuan perundang-undangan.', '3.1', '', '', 10, 1407, 82, 0, 2025, 1, 'Regulasi tentang penetapan penanggung jawab laboratorium yang memiliki kompetensi sesuai ketentuan perundang-undangan.', NULL, NULL, NULL, NULL, '2025-07-02 12:47:11', 0, 'A'),
(5484, 'PP 3.1 EP.2', 2, 'Terdapat bukti pelaksanaan tanggung jawab pimpinan laboratorium sesuai poin a sampai e pada maksud dan tujuan.', '3.1', '', '', 10, 1407, 82, 0, 2025, 1, NULL, 'Bukti tentang  pelaksanaan tanggung jawab pimpinan laboratorium sesuai poin a) - e) pada maksud dan tujuan.\r\na)	Menyusun dan evaluasi regulasi. \r\nb)	Pengawasan pelaksanaan administrasi. \r\nc)	Melaksanakan program kendali mutu (PMI dan PME) dan mengintegrasikan program mutu laboratorium dengan program Manajemen Fasilitas dan Keamanan serta program Pencegahan dan Pengendalian Infeksi di rumah sakit. \r\nd)	Melakukan pemantauan dan evaluasi semua jenis pelayanan laboratorium.\r\ne)	Mereview dan menindak lanjuti hasil pemeriksaan laboratorium rujukan.', NULL, '-	Kepala unit laboratorium\r\n-	Staf unit laboratorium', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5485, 'PP 3.2 EP.1', 1, 'Staf laboratorium yang membuat interpretasi telah memenuhi persyaratan kredensial.', '3.2', '', '', 10, 1408, 82, 0, 2025, 1, NULL, 'Bukti Staf Medis laboratorium yang membuat interpretasi telah memenuhi persyaratan kredensial.', NULL, '-	Komite medis\r\n-	Sub komite kredensial\r\n-	Staf medis.', NULL, '2025-07-02 12:48:21', 0, 'A'),
(5486, 'PP 3.2 EP.2', 2, 'Staf laboratorium dan staf lain yang melaksanakan pemeriksaan termasuk yang mengerjakan Point-of-care testing (POCT), memenuhi persyaratan kredensial.', '3.2', '', '', 10, 1408, 82, 0, 2025, 1, NULL, 'Bukti Staf laboratorium dan staf lain yang melaksanakan pemeriksaan termasuk yang mengerjakan Point-of-care testing (POCT), memenuhi persyaratan kredensial.', NULL, '-	Kepala /staf unit  laboratorium\r\n-	Staf klinis.', NULL, '2025-07-02 12:48:46', 0, 'A'),
(5487, 'PP 3.3 EP.1', 1, 'Rumah sakit menetapkan dan menerapkan kerangka waktu penyelesaian pemeriksaan laboratorium regular dan cito.', '3.3', '', '', 10, 1409, 82, 0, 2025, 1, 'Regulasi rumah sakit tentang pengaturan kerangka waktu penyelesaian pemeriksaan laboratorium regular dan cito.', 'Bukti penyelesaian pemeriksaan laboratorium regular dan cito sesuai kerangka waktu yang ditetapkan dalam regulasi RS.', NULL, NULL, NULL, '0000-00-00 00:00:00', 0, 'A'),
