(5491, 'PP 3.4 EP.1', 1, 'Terdapat bukti pelaksanaan semua reagensia esensial disimpan dan diberi label, serta didistribusi sesuai prosedur dari pembuatnya atau instruksi pada kemasannya', '3.4', '', '', 10, 1410, 82, 0, 2025, 1, NULL, NULL, '1)	Bukti tentang pelaksanaan semua  reagensia esensial disimpan dan  diberi label, termasuk tanggal kadaluwarsa, kondisi fisik reagensia.\r\n2)	Bukti tentang  pelaksanaan distribusi sesuai prosedur dari pembuatnya atau instruksi pada kemasannya.', '-	Kepala/staf unit laboratorium\r\n-	Staf unit farmasi.', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5492, 'PP 3.4 EP.2', 2, 'Terdapat bukti pelaksanaan evaluasi/audit semua reagen.', '3.4', '', '', 10, 1410, 82, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan evaluasi/audit semua reagen:\r\n1)	Bukti form ceklis\r\n2)	Bukti pelaksanaan audit minimal terdiri dari  aspek penyimpanan, pelabelan,  tanggal kadaluarsa dan kondisi fisik.', NULL, '-	Kepala/staf unit laboratorium\r\n-	Staf unit farmasi.', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5493, 'PP 3.5 EP.1', 1, 'Pengelolaan spesimen dilaksanakan sesuai poin a)-d) pada maksud dan tujuan.', '3.5', '', '', 10, 1411, 82, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan pengelolaan spesimen sesuai regulasi meliputi:\r\na)	Permintaan pemeriksaan.\r\nb)	Pengambilan, pengumpulan dan identifikasi spesimen. \r\nc)	Pengiriman, pembuangan, penyimpanan dan pengawetan spesimen. \r\nd)	Penerimaan, penyimpanan, telusur spesimen (tracking).', NULL, '-	PPA\r\n-	Staf unit laboratorium.', NULL, '0000-00-00 00:00:00', 0, 'A'),
