(5496, 'PP 3.6 EP.2', 2, 'Setiap hasil pemeriksaan laboratorium dilengkapi dengan rentang nilai normal.', '3.6', '', '', 10, 1412, 82, 0, 2025, 1, NULL, 'Bukti hasil pemeriksaan laboratorium dilengkapi dengan rentang nilai normal.', NULL, '-	Kepala unit laboratorium\r\n-	Staf unit laboratorium.', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5497, 'PP 3.7 EP.1', 1, 'Terdapat bukti bahwa unit laboratorium telah melakukan Pemantapan Mutu Internal (PMI) secara rutin yang meliputi poin a-e pada maksud dan tujuan.', '3.7', '', '', 10, 1413, 82, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan unit laboratorium telah melakukan Pemantapan Mutu Internal (PMI) secara rutin yang meliputi poin a)-e) pada maksud dan tujuan.\r\na)	Validasi tes yang digunakan untuk tes akurasi, presisi, hasil rentang nilai;\r\nb)	Dilakukan surveilans hasil pemeriksaan oleh staf yang kompeten;\r\nc)	Reagensia di tes; \r\nd)	Koreksi cepat jika ditemukan kekurangan;\r\ne)	Dokumentasi hasil dan tindakan koreksi;', NULL, '-	Kepala unit laboratorium\r\n-	Staf unit laboratorium.', NULL, '2025-07-02 13:13:25', 0, 'A'),
(5498, 'PP 3.7 EP.2', 2, 'Terdapat bukti bahwa unit laboratorium telah melakukan Pemantapan Mutu Eksternal (PME) secara rutin.', '3.7', '', '', 10, 1413, 82, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan unit laboratorium telah melakukan Pemantapan Mutu Eksternal (PME) secara rutin.', NULL, '-	Kepala unit laboratorium\r\n-	Staf unit laboratorium.', NULL, '2025-07-02 13:13:16', 0, 'A'),
