(5500, 'PP 3.8 EP.2', 2, 'Telah dilakukan pemantauan dan evaluasi kerjasama pelayanan kontrak sesuai dengan kesepakatan kedua belah pihak.', '3.8', '', '', 10, 1414, 82, 0, 2025, 1, NULL, 'Bukti perjanjian kerjasama dengan laboratorium rujukan dan  dilakukan pemantauan dan evaluasi kerjasama pelayanan kontrak sesuai dengan kesepakatan kedua belah pihak.', NULL, '-	Kepala unit laboratorium\r\n-	Staf unit laboratorium.', NULL, '2025-07-02 13:14:13', 0, 'A'),
(5501, 'PP 3.9 EP.1', 1, 'Rumah sakit menerapkan regulasi tentang penyelenggaraan pelayanan darah di rumah sakit.', '3.9', '', '', 10, 1415, 82, 0, 2025, 1, 'RS menetapkan regulasi tentang penyelenggaraan pelayanan darah.', 'Bukti penerapan penyelenggaraan pelayanan darah di rumah sakit sesuai regulasi (Lihat juga Std PAP 2.5).', NULL, '-	Kepala laboratorium/unit BDRS  (Bank Darah)\r\n-	Staf unit laboratorium/unit BDRS  (Bank Darah).', NULL, '2025-07-02 13:15:28', 0, 'A'),
