(5504, 'PP 3.9 EP.4', 4, 'Rumah sakit menerapkan proses persetujuan tindakan pasien untuk pemberian darah dan produk darah.', '3.9', '', '', 10, 1415, 82, 0, 2025, 1, NULL, '1)	Bukti tentang pelaksanaan penjelasan tentang  tujuan, manfaat, risiko dan komplikasi  pemberian transfusi darah dan produk darah.\r\n2)	Bukti persetujuan pemberian darah  dan produk darah.', NULL, '-	PPA\r\n-	Staf klinis\r\n-	Pasien/keluarga\r\n(Lihat juga HPK 4.1 EP 1) dan 2).', NULL, '2025-07-02 13:16:35', 0, 'A'),
(5505, 'PP 4 EP.1', 1, 'Rumah Sakit menetapkan dan melaksanakan regulasi pelayanan radiologi klinik.', '4', '', '', 10, 1416, 82, 0, 2025, 1, NULL, '1)	Pelayanan radiologi klinik terintegrasi dilaksanakan sesuai regulasi RS (sesuai penjelasan pada Maksud dan Tujuan).\r\n2)	Regulasi termasuk : \r\na.	pemeriksaan radiologi keluar melalui satu pintu: Pelayanan Radiologi rumah sakit.\r\nb.	manajemen risiko Pelayanan Radiologi\r\nc.	pengorganisasian, kualifikasi fdan kompetensi staf RIR\r\nd.	pelayanan RIR terintegrasi\r\ne.	tatakelola kendali mutu', NULL, NULL, NULL, '2025-07-02 13:17:14', 0, 'A'),
(5506, 'PP 4 EP.2', 2, 'Terdapat pelayanan radiologi klinik selama 24 jam, 7 (tujuh) hari seminggu, sesuai dengan  kebutuhan pasien.', '4', '', '', 10, 1416, 82, 0, 2025, 1, NULL, NULL, '1)	Pelayanan radiologi klinik selama 24 jam, 7 (tujuh) hari seminggu, sesuai dengan kebutuhan pasien. \r\n2)	Lihat daftar jaga, form permintaan dan hasil pemeriksaan.', '-	Staf klinis\r\n-	Staf unit RIR.', NULL, '2025-07-02 13:18:10', 0, 'A'),
(5507, 'PP 4.1 EP.1', 1, 'Direktur menetapkankan penanggung jawab radiologi klinik yang memiliki kompetensi sesuai ketentuan dengan peraturan perundang-undangan.', '4.1', '', '', 10, 1417, 82, 0, 2025, 1, 'Regulasi tentang penetapan penanggung jawab radiologi klinik yang memiliki kompetensi sesuai ketentuan dengan peraturan perundang-undangan.', NULL, NULL, NULL, NULL, '2025-07-02 13:18:42', 0, 'A'),
(5508, 'PP 4.1 EP.2', 2, 'Terdapat bukti pengawasan pelayanan radiologi klinik oleh penanggung jawab radiologi klinik sesuai poin a)-e) pada maksud dan tujuan.', '4.1', '', '', 10, 1417, 82, 0, 2025, 1, NULL, 'Bukti pelaksanaan pengawasan pelayanan radiologi klinik oleh penanggung jawab radiologi klinik sesuai poin a) – e) pada maksud dan tujuan. \r\na)	Menyusun dan evaluasi regulasi. \r\nb)	Pengawasan pelaksanaan administrasi. \r\nc)	Melaksanakan program kendali mutu (PMI dan PME) dan mengintegrasikan program mutu radiologi dengan program Manajemen Fasilitas dan Keamanan serta program Pencegahan dan Pengendalian Infeksi di rumah sakit. \r\nd)	Memonitor dan evaluasi semua jenis pelayanan radiologi. \r\ne)	Mereviu dan menindak lanjuti hasil pemeriksaan pelayanan RIR rujukan.', NULL, '-	Kepala unit radiologi\r\n-	Staf unit radiologi.', NULL, '2025-07-02 13:19:09', 0, 'A'),
(5509, 'PP 4.2 EP.1', 1, 'Staf radiologi klinik yang membuat interpretasi telah memenuhi persyaratan kredensial', '4.2', '', '', 10, 1418, 82, 0, 2025, 1, NULL, 'Bukti staf medis radiologi klinik yang membuat interpretasi telah memenuhi persyaratan kredensial.', NULL, '-	Kepala/staf unit RIR\r\n-	Staf medis.', NULL, '2025-07-02 13:19:31', 0, 'A'),
(5510, 'PP 4.2 EP.2', 2, 'Staf radiologi klinik dan staf lain yang melaksanakan pemeriksaan termasuk yang mengerjakan tindakan di Ruang Rawat pasien, memenuhi  persyaratan kredensial.', '4.2', '', '', 10, 1418, 82, 0, 2025, 1, NULL, 'Bukti staf radiologi klinik dan staf lain yang melaksanakan pemeriksaan termasuk yang mengerjakan tindakan di Ruang Rawat pasien, memenuhi persyaratan kredensial.', NULL, '-	Komite medis\r\n-	Sub komite kredensial\r\n-	Staf klinis antara lain perawat\r\n-	Staf lain : radiografer, fisikawan medis.', NULL, '2025-07-02 13:19:48', 0, 'A'),
(5511, 'PP 4.3 EP.1', 1, 'Rumah sakit menetapkan kerangka waktu penyelesaian pemeriksaan radiologi klinik.', '4.3', '', '', 10, 1419, 82, 0, 2025, 1, 'Regulasi tentang penetapan kerangka waktu penyelesaian pemeriksaan radiologi klinik.', NULL, NULL, NULL, NULL, '2025-07-02 13:20:22', 0, 'A'),
