(5514, 'PP 4.3 EP.4', 4, 'Terdapat bukti pencatatan dan evaluasi pelayanan radiologi rujukan.', '4.3', '', '', 10, 1419, 82, 0, 2025, 1, NULL, 'Bukti pencatatan dan pelaksanaan  evaluasi waktu penyelesaian pemeriksaan radiologi rujukan.', NULL, '-	Kepala/staf unit RIR\r\n-	Penanggung jawab data.', NULL, '2025-07-02 13:21:26', 0, 'A'),
(5515, 'PP 4.4 EP.1', 1, 'Rumah sakit menetapkan proses pengelolaan logistik film x-ray, reagens, dan bahan lainnya, termasuk kondisi bila terjadi kekosongan.', '4.4', '', '', 10, 1420, 82, 0, 2025, 1, 'Regulasi tentang penetapan  proses pengelolaan logistik film x-ray, reagens, dan bahan lainnya, termasuk kondisi bila terjadi kekosongan.', NULL, NULL, NULL, NULL, '2025-07-02 13:21:38', 0, 'A'),
(5516, 'PP 4.4 EP.2', 2, 'Semua film x-ray disimpan dan diberi label, serta didistribusi sesuai pedoman dari pembuatnya atau instruksi pada kemasannya.', '4.4', '', '', 10, 1420, 82, 0, 2025, 1, NULL, NULL, '1)	Semua film x-ray disimpan dan diberi label\r\n2)	Distribusi sesuai pedoman dari pembuatnya atau instruksi pada kemasannya.', '-	Staf Radiologi \r\n-	Staf farmasi.', NULL, '2025-07-02 13:21:10', 0, 'A'),
(5517, 'PP 4.5 EP.1', 1, 'Terdapat bukti bahwa unit radiologi klinik telah melaksanakan Pemantapan Mutu Internal (PMI).', '4.5', '', '', 10, 1421, 82, 0, 2025, 1, NULL, 'Bukti unit radiologi klinik telah melaksanakan Pemantapan Mutu Internal (PMI), meliputi: uji alat x-ray, uji perlengkapan seperti film, cassete dan sarana processing film.', NULL, 'Kepala/staf radiologi.', NULL, '2025-07-02 13:22:20', 0, 'A'),
(5518, 'PP 4.5 EP.2', 2, 'Terdapat bukti bahwa unit radiologi klinik melaksanakan Pemantapan Mutu Eksternal (PME).', '4.5', '', '', 10, 1421, 82, 0, 2025, 1, NULL, 'Bukti unit radiologi klinik melaksanakan Pemantapan Mutu Eksternal (PME). Pelibatan Badan eksternal yg ditetapkan Dirjen atau/dan Badan ekstrenal lainnya.', NULL, 'Kepala/staf unit radiologi.', NULL, '2025-07-02 13:22:43', 0, 'A'),
(5519, 'PAP 1 EP.1', 1, 'Rumah sakit menetapkan  regulasi  tentang  Pelayanan dan Asuhan Pasien (PAP) yang meliputi poin a)-e) dalam gambaran umum.', '1', '', '', 10, 1422, 83, 0, 2025, 1, 'Regulasi tentang pelayanan dan Asuhan Pasien, meliputi: \r\na)	Pemberian pelayanan yang seragam;\r\nb)	Pelayanan pasien risiko tinggi dan penyediaan pelayanan risiko tinggi;\r\nc)	Pemberian makanan dan terapi nutrisi;\r\nd)	Pengelolaan nyeri; dan\r\ne)	Pelayanan menjelang akhir hayat.', NULL, NULL, NULL, NULL, '2025-07-02 13:25:25', 0, 'A'),
(5520, 'PAP 1 EP.2', 2, 'Asuhan yang seragam diberikan kepada setiap pasien meliputi poin a)sampai e) dalam maksud dan tujuan.', '1', '', '', 10, 1422, 83, 0, 2025, 1, NULL, '1)	Bukti pelaksanaan asuhan seragam diberikan kepada setiap pasien.\r\n2)	Asuhan pasien yang seragam sesuai butir a) – e) di maksud dan tujuan:\r\na)	Akses untuk mendapatkan asuhan dan pengobatan tidak bergantung pada kemampuan pasien untuk membayar atau sumber pembayaran.\r\nb)	Akses untuk mendapatkan asuhan dan pengobatan yang diberikan oleh PPA yang kompeten tidak bergantung pada hari atau jam yaitu 7 (tujuh) hari, 24 (dua puluh empat) jam.\r\nc)	Kondisi pasien menentukan sumber daya yang akan dialokasikan untuk memenuhi kebutuhannya.\r\nd)	Pemberian asuhan yang diberikan kepada pasien, sama di semua unit pelayanan di rumah sakit misalnya pelayanan anestesi.\r\ne)	Pasien yang membutuhkan asuhan keperawatan yang sama akan menerima tingkat asuhan keperawatan yang sama di semua unit pelayanan di rumah sakit.', NULL, '-	DPJP\r\n-	PPJA\r\n-	MPP\r\n-	Pasien/keluarga', NULL, '2025-07-02 13:26:09', 0, 'A'),
(5521, 'PAP 1.1 EP.1', 1, 'Rumah sakit telah melakukan pelayanan dan asuhan yang terintegrasi serta terkoordinasi kepada setiap pasien.', '1.1', '', '', 10, 1423, 83, 0, 2025, 1, NULL, '1)	Bukti dalam rekam medis pelaksanaan pelayanan dan asuhan yang terintegrasi serta terkoordinasi kepada setiap pasien.\r\n2)	Bukti pelaksanaan Asuhan pasien terintegrasi dilaksanakan dengan beberapa elemen poin a. – d. di Gambaran Umum :\r\na.	Dokter penanggung jawab pelayanan (DPJP) sebagai pimpinan klinis/ketua tim PPA (clinical leader).\r\nb.	PPA bekerja sebagai tim intra- dan interdisiplin dengan kolaborasi interprofessional, dibantu antara lain dengan panduan praktik klinis (PPK), panduan asuhan PPA lainnya, alur klinis/clinical pathway  terintegrasi, algoritma, protokol, prosedur, standing order, dan catatan perkembangan pasien terintegrasi (CPPT).\r\nc.	Manajer Pelayanan Pasien (MPP)/ Case Manager menjaga kesinambungan pelayanan. \r\nd.	Keterlibatan serta pemberdayaan pasien dan keluarga dalam asuhan bersama PPA harus memastikan:\r\n1)	Asuhan direncanakan untuk memenuhi kebutuhan pasien yang unik berdasar atas pengkajian;\r\n2)	Rencana asuhan diberikan kepada tiap pasien;\r\n3)	Respons pasien terhadap asuhan dipantau; dan\r\n4)	Rencana asuhan dimodifikasi bila perlu berdasarkan respons pasien.\r\n(Lihat juga Std AKP 3 di maksud-tujuan poin a) – f).', NULL, '-	DPJP\r\n-	PPJA\r\n-	MPP\r\n-	Pasien/keluarga', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5522, 'PAP 1.1 EP.2', 2, 'Rumah sakit telah menetapkan  kewenangan  pemberian instruksi oleh PPA yang kompeten, tata cara pemberian instruksi dan pendokumentasiannya.', '1.1', '', '', 10, 1423, 83, 0, 2025, 1, 'Rumah sakit menetapkan kewenangan pemberian instruksi oleh PPA yang kompeten, tata cara pemberian instruksi dan pendokumentasiannya.', 'Pemberian instruksi dan pendokumentasiannya oleh PPA yang kompeten dan berwenang di CPPT pada kolom Instruksi oleh PPA.', NULL, '-	DPJP\r\n-	PPJA', NULL, '2025-07-02 13:27:19', 0, 'A'),
(5523, 'PAP 1.1 EP.3', 3, 'Permintaan pemeriksaan laboratorium dan diagnostik imajing harus disertai indikasi klinis apabila meminta hasilnya berupa interpretasi.', '1.1', '', '', 10, 1423, 83, 0, 2025, 1, NULL, 'Bukti permintaan pemeriksaan laboratorium dan diagnostik imajing disertai indikasi klinis bila hasil nya berupa interpretasi.', NULL, '-	DPJP\r\n-	Staf unit laboratorium\r\n-	Staf unit radiologi', NULL, '2025-07-02 13:28:12', 0, 'A'),
(5524, 'PAP 1.1 EP.4', 4, 'Prosedur dan tindakan telah  dilakukan  sesuai  instruksi dan PPA yang memberikan instruksi, alasan dilakukan prosedur atau tindakan serta hasilnya telah didokumentasikan di dalam rekam medis pasien', '1.1', '', '', 10, 1423, 83, 0, 2025, 1, NULL, '1)	Bukti prosedur dan tindakan yang dilakukan sesuai dengan instruksi PPA \r\n2)	Bukti alasan dilakukan prosedur atau tindakan serta hasilnya didokumentasikan di dalam rekam medis pasien.\r\n(Lihat juga SKP 2 EP 1).', NULL, '-	DPJP \r\n-	PPJA', NULL, '2025-07-02 13:28:31', 0, 'A'),
(5525, 'PAP 1.1 EP.5', 5, 'Pasien yang menjalani tindakan invasif/berisiko di rawat jalan telah dilakukan pengkajian dan didokumentasikan dalam rekam medis.', '1.1', '', '', 10, 1423, 83, 0, 2025, 1, NULL, 'Bukti dalam rekam medis dilakukan pengkajian pada pasien rawat jalan yang menjalani tindakan invasif/berisiko, termasuk pencatatan efek samping dll.', NULL, '-	DPJP\r\n-	Kepala/staf unit pelayanan diagnostik antara lain Unit Laboratorium, Unit Radiologi', NULL, '2025-07-02 13:29:02', 0, 'A'),
(5526, 'PAP 1.2 EP.1', 1, 'PPA telah membuat rencana asuhan untuk  setiap pasien setelah diterima sebagai pasien rawat  inap dalam waktu 24 jam berdasarkan hasil pengkajian  awal.', '1.2', '', '', 10, 1424, 83, 0, 2025, 1, NULL, 'Bukti dalam rekam medis PPA membuat rencana asuhan untuk setiap pasien setelah diterima sebagai pasien rawat inap dalam waktu 24 jam berdasarkan hasil pengkajian awal.', NULL, 'PPA', NULL, '2025-07-02 13:29:34', 0, 'A'),
(5527, 'PAP 1.2 EP.2', 2, 'Rencana asuhan dievaluasi  secara  berkala,  direvisi atau dimutakhirkan serta didokumentasikan dalam rekam medis oleh setiap PPA.', '1.2', '', '', 10, 1424, 83, 0, 2025, 1, NULL, '1)	Bukti dalam rekam medis tentang rencana asuhan dievaluasi   secara   berkala, direvisi atau dimutakhirkan oleh setiap PPA.  \r\n2)	Sesuai di maksud dan tujuan: DPJP sebagai ketua tim PPA melakukan evaluasi / reviu berkala dan verifikasi harian. Lihat EP 5.', NULL, 'PPA', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5528, 'PAP 1.2 EP.3', 3, 'Instruksi berdasarkan rencana asuhan dibuat oleh PPA yang kompeten dan berwenang, dengan cara yang seragam, dan didokumentasikan di CPPT.', '1.2', '', '', 10, 1424, 83, 0, 2025, 1, NULL, 'Bukti dalam rekam medis tentang instruksi dibuat oleh PPA yang kompeten dan berwenang, dengan cara yang seragam, dan didokumentasikan di CPPT, di kolom Instruksi sesuai Std PAP 1.1. EP 2.', NULL, 'PPA', NULL, '2025-07-02 13:30:15', 0, 'A'),
(5529, 'PAP 1.2 EP.4', 4, 'Rencana asuhan pasien dibuat dengan membuat sasaran yang terukur dan di dokumentasikan.', '1.2', '', '', 10, 1424, 83, 0, 2025, 1, NULL, 'Bukti dalam rekam medis tentang rencana asuhan pasien dengan sasaran sesuai kebutuhan dan kondisi pasien.', NULL, 'PPA', NULL, '2025-07-02 13:30:35', 0, 'A'),
(5530, 'PAP 1.2 EP.5', 5, 'DPJP telah melakukan evaluasi/review berkala dan verifikasi harian untuk memantau terlaksananya  asuhan secara terintegrasi dan membuat notasi sesuai dengan kebutuhan.', '1.2', '', '', 10, 1424, 83, 0, 2025, 1, NULL, 'Bukti dalam rekam medis DPJP telah melakukan evaluasi/review berkala dan verifikasi harian untuk memantau terlaksananya asuhan secara terintegrasi dan membuat notasi sesuai dengan kebutuhan. Dan memberi tandatangan di CPPT kolom reviu dan verifikasi.', NULL, '-	DPJP \r\n-	PPJA\r\n-	Staf Klinis', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5531, 'PAP 2 EP.1', 1, 'Pimpinan rumah sakit telah melaksanakan tanggung jawabnya untuk memberikan pelayanan pada pasien berisiko tinggi dan pelayanan berisiko tinggi meliputi a)-c) dalam maksud dan tujuan.', '2', '', '', 10, 1425, 83, 0, 2025, 1, NULL, 'Bukti Pimpinan rumah sakit telah melaksanakan tanggung jawabnya untuk pasien berisiko tinggi dan pelayanan berisiko tinggi yang meliputi:\r\na)	Identifikasi pasien risiko tinggi dan pelayanan risiko tinggi sesuai dengan populasi pasiennya meliputi a) - n) , disertai penetapan risiko tambahan yang mungkin berpengaruh pada pasien risiko tinggi dan pelayanan risiko tinggi \r\nb)	Menetapkan prosedur, panduan praktik klinis (PPK), clinical pathway dan rencana perawatan secara kolaboratif\r\nc)	Melatih staf untuk menerapkan prosedur, panduan praktik klinis (PPK), clinical pathway dan rencana perawatan.', NULL, '-	DPJP \r\n-	PPJA\r\n-	Kepala Unit Pelayanan', NULL, '2025-07-02 13:31:29', 0, 'A'),
(5532, 'PAP 2 EP.2', 2, 'Rumah sakit telah memberikan pelayanan pada pasien risiko tinggi dan pelayanan risiko tinggi yang telah diidentifikasi berdasarkan populasi yaitu pasien anak, pasien dewasa dan pasien geriatri sesuai  dalam  maksud dan tujuan.', '2', '', '', 10, 1425, 83, 0, 2025, 1, NULL, 'Bukti dalam rekam medis tentang pelaksanaan  pemberian  pelayanan  pada  pasien  risiko  tinggi  dan pelayanan risiko tinggi pada populasi pasien anak, pasien dewasa dan pasien geriatri, meliputi : \r\na)	Rencana asuhan perawatan pasien; \r\nb)	Perawatan terintegrasi dan mekanisme komunikasi antar PPA secara efektif; \r\nc)	Pemberian informed consent, jika diperlukan; \r\nd)	Pemantauan/observasi pasien selama memberikan pelayanan; \r\ne)	Kualifikasi atau kompetensi staf yang memberikan pelayanan; dan \r\nf)	Ketersediaan dan penggunaan peralatan medis khusus untuk pemberian pelayanan.', NULL, '-	DPJP\r\n-	PPA lainnya\r\n-	Staf klinis', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5533, 'PAP 2 EP.3', 3, 'Pimpinan rumah sakit telah mengidentifikasi risiko tambahan yang dapat mempengaruhi pasien dan pelayanan risiko tinggi', '2', '', '', 10, 1425, 83, 0, 2025, 1, 'Regulasi tentang identifikasi risiko tambahan yang dapat mempengaruhi pasien dan pelayanan risiko tinggi, sesuai penjelasan di maksud dan tujuan.', NULL, NULL, NULL, NULL, '2025-07-02 13:32:06', 0, 'A'),
(5534, 'PAP 2.1 EP.1', 1, 'Rumah sakit telah menetapkan regulasi tentang penyelenggaraan pelayanan geriatri di rumah sakit sesuai dengan kemampuan, sumber daya dan sarana prasarana nya.', '2.1', '', '', 10, 1426, 83, 0, 2025, 1, 'Regulasi tentang tingkat jenis pelayanan geriatri yang sesuai dengan kemampuan, sumber daya dan sarana prasarana rumah sakit, mengacu pada poin a) – d) di maksud – tujuan.', NULL, NULL, NULL, NULL, '2025-07-02 13:32:31', 0, 'A'),
(5535, 'PAP 2.1 EP.2', 2, 'Rumah sakit telah menetapkan tim terpadu  geriatri  dan telah menyelenggarakan pelayanan sesuai tingkat jenis layanan', '2.1', '', '', 10, 1426, 83, 0, 2025, 1, 'Regulasi yang meliputi: \r\n1)	Penetapan Tim Terpadu Geriatri \r\n2)	Pedoman Kerja Tim Terpadu Geriatri \r\n3)	Program Kerja Tim Terpadu Geriatri.', NULL, NULL, NULL, NULL, '2025-07-02 13:32:42', 0, 'A'),
(5536, 'PAP 2.1 EP.3', 3, 'Rumah sakit telah melaksanakan proses pemantauan dan evaluasi kegiatan pelayanan geriatri', '2.1', '', '', 10, 1426, 83, 0, 2025, 1, NULL, 'Bukti pelaksanaan pemantauan dan evaluasi kegiatan pelayanan geriatri.', NULL, '-	Ketua/anggota Tim Terpadu Geriatri\r\n-	Kepala Bidang/divisi/bagian\r\n-	Kepala Unit Pelayanan', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5537, 'PAP 2.1 EP.4', 4, 'Ada pelaporan penyelenggaraan pelayanan geriatri di rumah sakit.', '2.1', '', '', 10, 1426, 83, 0, 2025, 1, NULL, 'Bukti pelaporan kegiatan pelayanan geriatri di rumah sakit', NULL, '-	Ketua/anggota Tim Terpadu Geriatri\r\n-	Kepala Unit Pelayanan', NULL, '2025-07-02 13:33:24', 0, 'A'),
(5538, 'PAP 2.2 EP.1', 1, 'Ada program PKRS terkait Pelayanan Kesehatan Warga Lanjut usia di Masyarakat Berbasis Rumah  Sakit (Hospital Based Community Geriatric Service).', '2.2', '', '', 10, 1427, 83, 0, 2025, 1, 'Ada program PKRS terkait Pelayanan Kesehatan Warga Lanjut Usia di Masyarakat Berbasis Rumah Sakit (Hospital Based Community Geriatric Service).', NULL, NULL, NULL, NULL, '2025-07-02 13:33:36', 0, 'A'),
