(5548, 'PAP 2.4 EP.4', 4, 'Rumah sakit melatih sumber daya manusia yang mampu melakukan\r\nskrining, pengkajian, dan tata laksana pasien risiko bunuh diri', '2.4', '', '', 10, 1429, 83, 0, 2025, 1, NULL, 'Bukti pelaksanaan pelatihan bagi staf tentang pelayanan resusitasi berupa: TOR, undangan, daftar hadir, materi, laporan, evaluasi, sertifikat.', NULL, '-	Staf klinis\r\n-	Staf RS\r\n-	Diklat', NULL, '2025-07-02 13:38:03', 0, 'A'),
