(5559, 'PAP 2.7 EP.2', 2, 'Panduan klinis dan prosedur disusun dan diterapkan untuk pelayanan darah serta produk darah.', '2.7', '', '', 10, 1432, 83, 0, 2025, 1, NULL, NULL, NULL, NULL, NULL, '2024-10-25 14:13:34', 0, 'A'),
(5560, 'PAP 2.7 EP.3', 3, 'Staf yang kompeten bertanggungjawab terhadap pelayanan darah di rumah sakit.', '2.7', '', '', 10, 1432, 83, 0, 2025, 1, NULL, NULL, NULL, NULL, NULL, '2024-10-25 14:13:34', 0, 'A'),
(5561, 'PAP 3 EP.1', 1, 'Berbagai pilihan makanan atau terapi nutrisi yang sesuai untuk kondisi, perawatan, dan  kebutuhan  pasien tersedia dan disediakan tepat waktu.', '3', '', '', 10, 1433, 83, 0, 2025, 1, NULL, 'Bukti tersedia dan disediakan tepat waktu berbagai pilihan makanan atau terapi nutrisi yang sesuai untuk kondisi, perawatan, dan kebutuhan pasien.', NULL, '-	PPA \r\n-	Kepala instalasi/unit Gizi\r\n-	Pasien/Keluarga', NULL, '2025-07-02 13:39:48', 0, 'A'),
(5562, 'PAP 3 EP.2', 2, 'Sebelum pasien rawat inap diberi makanan, terdapat instruksi pemberian makanan dalam rekam medis pasien yang didasarkan pada status  gizi  dan  kebutuhan pasien.', '3', '', '', 10, 1433, 83, 0, 2025, 1, NULL, 'Bukti dalam rekam medis tentang instruksi pemberian makanan  pasien  sesuai  dengan  status  gizi  dan kebutuhan pasien.', NULL, '-	PPA\r\n-	Nutrisionis/dietisien', NULL, '2025-07-02 13:40:17', 0, 'A'),
(5563, 'PAP 3 EP.3', 3, 'Untuk makanan yang disediakan keluarga, edukasi diberikan mengenai batasan-batasan diet pasien dan penyimpanan yang baik untuk mencegah kontaminasi.', '3', '', '', 10, 1433, 83, 0, 2025, 1, NULL, '1)	Makanan dari luar rumah sakit dapat diadakan sesuai ketentuan RS\r\n2)	Bukti pemberian edukasi tentang batasan-batasan diet pasien dan penyimpanan yang baik untuk mencegah kontaminasi bila makanan disediakan oleh keluarga,', NULL, '-	Staf klinis\r\n-	Nutrisionis/dietisien \r\n-	Pasien/keluarga', NULL, '2025-07-02 13:40:36', 0, 'A'),
(5564, 'PAP 3 EP.4', 4, 'Memiliki bukti pemberian terapi gizi terintegrasi (rencana, pemberian dan evaluasi) pada pasien risiko gizi.', '3', '', '', 10, 1433, 83, 0, 2025, 1, NULL, '1)	Bukti dalam rekam medis tentang pemberian terapi gizi terintegrasi pada pasien risiko gizi mencakup rencana, pemberian dan evaluasi terapi gizi \r\n2)	Bukti terapi gizi terintegrasi berupa pendokumentasian IAR oleh Dietisien direviu-verifikasi oleh DPJP\r\n(Lihat juga Std AKP 3 pada maksud dan tujuan poin e)).', NULL, '-	PPA\r\n-	Staf klinis\r\n-	Nutrisionis/dietisien', NULL, '2025-07-02 13:41:07', 0, 'A'),
(5565, 'PAP 3 EP.5', 5, 'Pemantauan dan evaluasi terapi gizi dicatat di rekam medis pasien.', '3', '', '', 10, 1433, 83, 0, 2025, 1, NULL, 'Bukti dalam rekam medis tentang hasil evaluasi dan monitoring terapi gizi.', NULL, '-	PPA\r\n-	Staf klinis\r\n-	Nutrisionisampai denganietisien \r\n-	Pasien/keluarga', NULL, '2025-07-02 13:41:25', 0, 'A'),
(5566, 'PAP 4 EP.1', 1, 'Rumah sakit memiliki proses untuk melakukan skrining, pengkajian, dan tata laksana nyeri meliputi poin - pada maksud dan tujuan.', '4', '', '', 10, 1434, 83, 0, 2025, 1, '1)	Regulasi tentang proses untuk melakukan skrining, pengkajian, dan tata laksana nyeri meliputi : \r\na)	Identifikasi pasien dengan rasa nyeri pada pengkajian awal dan pengkajian ulang\r\nb)	Pemberian informasi kepada pasien bahwa rasa nyeri dapat merupakan akibat dari terapi, prosedur, atau pemeriksaan. \r\nc)	Tata laksana untuk mengatasi rasa nyeri, terlepas dari mana nyeri berasal \r\nd)	Komunikasi dan edukasi kepada pasien dan keluarga mengenai pengelolaan nyeri sesuai dengan latar belakang agama, budaya, nilai-nilai yang dianut. \r\ne)	Edukasi kepada seluruh PPA mengenai pengkajian dan pengelolaan nyeri.\r\n2)	Regulasi termasuk Pengkajian awal pada pasien nyeri hebat/membutuhkan penanganan segera, terdiri dari skrining (rapid assessment) dan pengkajian lanjutan. (Lihat Std PP 1 EP 1).', NULL, NULL, NULL, NULL, '2025-07-02 13:41:48', 0, 'A'),
(5567, 'PAP 4 EP.2', 2, 'Informasi mengenai kemungkinan adanya nyeri dan pilihan tata laksananya diberikan kepada pasien yang menerima terapi/prosedur/pemeriksaan terencana  yang sudah dapat diprediksi menimbulkan rasa nyeri.', '4', '', '', 10, 1434, 83, 0, 2025, 1, NULL, 'Bukti pelaksanaan tentang pemberian informasi kemungkinan timbulnya nyeri dan pilihan tata laksananya diberikan kepada pasien yang menerima terapi/prosedur/pemeriksaan terencana yang sudah dapat diprediksi menimbulkan rasa nyeri.', NULL, '-	DPJP\r\n-	PPJA\r\n-	Staf klinis\r\n-	Pasien/keluarga', NULL, '2025-07-02 13:42:10', 0, 'A'),
(5568, 'PAP 4 EP.3', 3, 'Pasien dan keluarga mendapatkan edukasi mengenai pengelolaan nyeri sesuai dengan latar belakang agama, budaya, nilai-nilai yang dianut.', '4', '', '', 10, 1434, 83, 0, 2025, 1, NULL, 'Bukti pasien dan keluarga mendapatkan edukasi mengenai pengelolaan nyeri sesuai dengan latar belakang agama, budaya, nilai-nilai yang dianut. Lihat juga Std KE 4 EP b) dan Std KE 5, HPK 1.2 EP 1 dan 2.', NULL, '-	DPJP\r\n-	PPJA\r\n-	Staf klinis\r\n-	Pasien/Keluarga.', NULL, '2025-07-02 13:42:27', 0, 'A'),
(5569, 'PAP 4 EP.4', 4, 'Staf rumah sakit mendapatkan pelatihan mengenai  cara melakukan edukasi bagi pengelolaan nyeri.', '4', '', '', 10, 1434, 83, 0, 2025, 1, NULL, 'Bukti pelaksanaan pelatihan staf mengenai cara melakukan edukasi bagi pengelolaan nyeri, berupa: TOR, Undangan, daftar hadir, materi, laporan, evaluasi, sertifikat. Lihat juga Std KE 7.', NULL, '-	PPA\r\n-	Staf klinis', NULL, '2025-07-02 13:42:48', 0, 'A'),
(5570, 'PAP 5 EP.1', 1, 'Rumah sakit menerapkan pengkajian pasien menjelang akhir kehidupan  dan  dapat  dilakukan   pengkajian   ulang sampai pasien yang memasuki fase akhir kehidupannya, dengan memperhatikan poin   1) sampai 9) pada maksud dan tujuan.', '5', '', '', 10, 1435, 83, 0, 2025, 1, NULL, '1)	Bukti dalam rekam medis tentang penerapan pengkajian pasien menjelang akhir kehidupan, didahului skrining.\r\n2)	Selanjutnya dilakukan pengkajian awal yg khusus pada fase menjelang akhir kehidupan. Kemudian akan dilakukan dengan pengkajian ulang). \r\n3)	Bukti pengkajian ulang sampai pasien yang memasuki fase akhir kehidupannya, meliputi:\r\na)	Gejala dan respons pasien, termasuk mual, kesulitan bernapas, dan nyeri. \r\nb)	Faktor yang memperparah gejala fisik.\r\nc)	Orientasi spiritual pasien dan keluarganya, termasuk keterlibatan dalam kelompok agama tertentu.\r\nd)	Keprihatinan spiritual pasien dan keluarganya, seperti putus asa, penderitaan, rasa bersalah.\r\ne)	Status psikososial pasien dan keluarganya, seperti kekerabatan, kelayakan perumahan, pemeliharaan lingkungan, cara mengatasi, reaksi pasien dan keluarganya menghadapi penyakit.\r\nf)	Kebutuhan bantuan atau penundaan layanan untuk pasien dan keluarganya. \r\ng)	Kebutuhan alternatif layanan atau tingkat layanan. \r\nh)	Faktor risiko bagi yang ditinggalkan dalam hal cara mengatasi dan potensi reaksi patologis.\r\ni)	Pasien dan keluarga dilibatkan dalam pengambilan keputusan asuhan, termasuk keputusan do not resuscitate/DNR.\r\nLihat juga HPK 2.2.', NULL, '-	PPA\r\n-	Staf klinis\r\n-	Pasien/keluarga.', NULL, '0000-00-00 00:00:00', 0, 'A');
INSERT INTO `accreditation_instrument` (`instrument_id`, `instrument_reference_code`, `instrument_order_id`, `instrument_name`, `instrument_objective`, `instrument_material`, `instrument_document`, `instrument_maximum_score`, `instrument_standard_id`, `instrument_chapter_id`, `instrument_class_id`, `instrument_version`, `instrument_institution_group_id`, `instrument_r`, `instrument_d`, `instrument_o`, `instrument_w`, `instrument_s`, `instrument_update`, `instrument_user_id`, `instrument_record_status`) VALUES
(5571, 'PAP 5 EP.2', 2, 'Asuhan menjelang akhir kehidupan  ditujukan  terhadap kebutuhan psikososial, emosional, kultural dan spiritual pasien dan keluarganya.', '5', '', '', 10, 1435, 83, 0, 2025, 1, NULL, 'Bukti dalam rekam medis asuhan menjelang akhir kehidupan ditujukan terhadap kebutuhan biopsiko-sosial, emosional, budaya, dan spiritual pasien dan keluarga.', NULL, '-	PPA\r\n-	Staf klinis\r\n-	Pasien/keluarga', NULL, '2025-07-02 14:14:33', 0, 'A'),
(5572, 'PAB 1 EP.1', 1, 'Rumah sakit telah menetapkan regulasi pelayanan anestesi dan sedasi dan pembedahan meliputi poin a-c pada gambaran umum.', '1', '', '', 10, 1436, 84, 0, 2025, 1, '1)	Regulasi/penetapan pelayanan anestesi dan sedasi meliputi:\r\na)	Pengorganisasian pengelolaan pelayanan sedasi dan anaestesi terintegrasi. \r\nb)	Pelayanan sedasi \r\nc)	Pelayanan anestesi. \r\n2)	Regulasi tentang mendatangkan dokter anestesi dari luar rumah sakit untuk keadaan darurat dan pengganti sementara. (Lihat Std PAB 2 EP 3). \r\n3)	Regulasi tentang PPK untuk pelayanan sedasi dan anestesi.', NULL, NULL, NULL, NULL, '2025-07-02 14:42:01', 0, 'A'),
(5573, 'PAB 1 EP.2', 2, 'Pelayanan anestesi dan sedasi yang telah diberikan dapat memenuhi kebutuhan pasien.', '1', '', '', 10, 1436, 84, 0, 2025, 1, NULL, 'Bukti  dari laporan kegiatan bulanan,  pelaksanaan pelayanan anestesi-sedasi  yang telah diberikan sesuai kebutuhan pasien.', NULL, '-	Penanggung jawab pelayanan anestesi, \r\n-	Staf anestesi, termasuk penata/perawat \r\nAnestesi.', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5574, 'PAB 1 EP.3', 3, 'Pelayanan anestesi dan sedasi tersedia selama 24 (dua puluh empat) jam 7 (tujuh) hari sesuai dengan kebutuhan pasien.', '1', '', '', 10, 1436, 84, 0, 2025, 1, NULL, 'Bukti tentang  pelayanan anestesi dan sedasi tersedia 24 jam 7 (tujuh) hari sesuai dengan kebutuhan pasien.', 'Lihat daftar jaga dokter spesialis anestesi dan penata /perawat anestesi', 'Staf anestesi.', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5575, 'PAB 2 EP.1', 1, 'Rumah sakit telah  menerapkan  pelayanan  anestesi dan sedasi secara seragam di seluruh area seusai regulasi yang ditetapkan.', '2', '', '', 10, 1437, 84, 0, 2025, 1, NULL, '1)	Bukti tentang penerapan  pelayanan anestesi dan sedasi yang seragam di seluruh area sesuai regulasi yang ditetapkan.\r\n2)	Kriteria pelayanan anestesi yang seragam adalah kegiatan dibawah kendali dokter anestesi.\r\n3)	Kriteria pelayanan sedasi  yang seragam\r\ndapat dilakukan diluar kamar bedah dengan: \r\na)	Area-area di dalam rumah sakit tempat sedasi moderat dan dalam dapat dilakukan; \r\nb)	Kualifikasi staf yang memberikan sedasi; \r\nc)	Persetujuan medis (informed consent) untuk prosedur maupun sedasinya; \r\nd)	Perbedaan populasi anak, dewasa, dan geriatri ataupun pertimbangan khusus lainnya;  \r\ne)	Peralatan medis dan bahan yang digunakan sesuai dengan populasi yang diberikan sedasi moderat atau dalam; dan\r\nf)	Cara memantau.', NULL, '-	Penanggung jawab  pelayanan anestesi\r\n-	Staf anestesi.', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5576, 'PAB 2 EP.2', 2, 'Rumah sakit telah menetapkan penanggung jawab pelayanan anestesi dan sedasi adalah seorang dokter anastesi yang kompeten yang melaksanakan tanggung jawabnya meliputi poin a)sampai d)  pada  maksud  dan  tujuan.', '2', '', '', 10, 1437, 84, 0, 2025, 1, 'Regulasi tentang penetapan  penanggung jawab pelayanan anestesi dan sedasi adalah seorang dokter anastesi yang kompeten yang melaksanakan tanggung jawabnya meliputi:\r\na)	Mengembangkan, menerapkan, dan menjaga regulasi; \r\nb)	Melakukan pengawasan administratif; \r\nc)	Melaksanakan program pengendalian mutu yang dibutuhkan; dan \r\nd)	Memantau dan mengevaluasi pelayanan sedasi dan anestesi', NULL, NULL, NULL, NULL, '0000-00-00 00:00:00', 0, 'A'),
(5577, 'PAB 2 EP.3', 3, 'Bila memerlukan profesional pemberi asuhan terdapat PPA dari luar rumah sakit untuk memberikan pelayanan anestesi dan sedasi, maka ada bukti rekomendasi dan evaluasi pelayanan dari penanggung jawab pelayanan anastesi dan sedasi terhadap PPA tersebut.', '2', '', '', 10, 1437, 84, 0, 2025, 1, NULL, '1)	Bukti tentang rekomendasi dan evaluasi pelayanan dari penanggung jawab pelayanan anastesi dan sedasi terhadap pelayanan anestesi dan sedasi oleh PPA dari luar rumah sakit, untuk kondisi kedaruratan.\r\n2)	Untuk pengganti sementara, ada bukti proses kredensial melalui Komite Medis dan SIP di rumah sakit asal ybs.', NULL, 'Penanggung jawab  pelayanan anestesi.', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5578, 'PAB 3 EP.1', 1, 'Rumah sakit telah melaksanakan pemberian sedasi moderat dan dalam yang seragam di semua tempat di rumah sakit sesuai dengan poin a)-f)  pada  maksud dan tujuan.', '3', '', '', 10, 1438, 84, 0, 2025, 1, NULL, 'Bukti pelaksanakan pemberian sedasi moderat dan dalam yang seragam di semua tempat di rumah sakit sesuai: \r\na)	Area-area di dalam rumah sakit tempat sedasi moderat dan dalam dapat dilakukan; \r\nb)	Kualifikasi staf yang memberikan sedasi; \r\nc)	Persetujuan medis (informed consent) untuk prosedur maupun sedasinya; \r\nd)	Perbedaan populasi anak, dewasa, dan geriatri ataupun pertimbangan khusus lainnya;  \r\ne)	Peralatan medis dan bahan yang digunakan sesuai dengan populasi yang diberikan sedasi moderat atau dalam; dan\r\nf)	Cara memantau.', NULL, '-	Penanggung jawab pelayanan anestesi\r\n-	Staf anestesi.', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5579, 'PAB 3 EP.2', 2, 'Peralatan dan perbekalan gawat darurat tersedia di tempat dilakukan sedasi moderat dan dalam serta dipergunakan sesuai jenis sedasi, usia, dan kondisi pasien.', '3', '', '', 10, 1438, 84, 0, 2025, 1, NULL, NULL, 'Lihat ketersediaan peralatan dan perbekalan gawat darurat tersedia di tempat dilakukan sedasi moderat dan dalam serta dipergunakan sesuai jenis sedasi, usia, dan kondisi pasien.', '-	Penanggung jawab  pelayanan anestesi\r\n-	Staf anestesi\r\n-	Staf farmasi.', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5580, 'PAB 3 EP.3', 3, 'PPA yang terlatih dan berpengalaman dalam memberikan bantuan hidup lanjut (advance) harus selalu mendampingi dan siaga selama tindakan sedasi dikerjakan.', '3', '', '', 10, 1438, 84, 0, 2025, 1, NULL, 'Daftar jaga PPA yang kompeten dan  berwenang untuk memberikan bantuan  hidup lanjut (advance) selama tindakan  sedasi dilakukan.', NULL, '-	Penanggung jawab pelayanan anestesi\r\n-	Staf anestesi.', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5581, 'PAB 3.1 EP.1', 1, 'Tenaga medis yang diberikan kewenangan klinis memberikan sedasi  moderat  dan  dalam  harus  kompeten dalam poin a)–d) pada maksud dan tujuan.', '3.1', '', '', 10, 1439, 84, 0, 2025, 1, '1)	Regulasi tentang penetapan tenaga medis (dokter spesialis anestesi) yang memberikan sedasi moderat dan dalam sesuai :\r\na)	Teknik dan berbagai cara sedasi;  \r\nb)	Farmakologi obat sedasi dan penggunaaan zat reversal (antidot);  \r\nc)	Persyaratan pemantauan pasien; dan \r\nd)	Bertindak jika ada komplikasi. \r\n2)	SPK-RKK dokter spesialis anestesi.', NULL, NULL, NULL, NULL, '0000-00-00 00:00:00', 0, 'A'),
(5582, 'PAB 3.1 EP.2', 2, 'Profesional pemberi asuhan (PPA) yang bertanggung jawab melakukan   pemantauan   selama   pelayanan sedasi moderat dan dalam  harus  kompeten  meliputi poin – pada maksud dan tujuan.', '3.1', '', '', 10, 1439, 84, 0, 2025, 1, 'Regulasi tentang SPK RKK  Profesional pemberi asuhan (PPA) yang bertanggung jawab melakukan pemantauan selama pelayanan sedasi moderat dan dalam meliputi:\r\na)	Pemantauan yang diperlukan;  \r\nb)	Bertindak jika ada komplikasi;  \r\nc)	Penggunaan zat reversal (antidot); dan \r\nd)	d) Kriteria pemulihan.', NULL, NULL, NULL, NULL, '2025-07-02 14:02:26', 0, 'A'),
(5583, 'PAB 3.1 EP.3', 3, 'Kompetensi semua PPA yang terlibat dalam sedasi moderat dan dalam tercatat di file kepegawaian.', '3.1', '', '', 10, 1439, 84, 0, 2025, 1, NULL, 'Bukti SPK-RKK dalam file kepegawaian semua PPA  yang terlibat dalam sedasi moderat dan dalam', NULL, '-	Penanggung jawab pelayanan  anestesi\r\n-	Staf anestesi\r\n-	Kepala/staf SDM.', NULL, '2025-07-02 14:02:46', 0, 'A'),
(5584, 'PAB 3.2 EP.1', 1, 'Rumah sakit telah  menerapkan  pengkajian  prasedasi dan dicatat dalam rekam medis meliputi poin a)-e) pada maksud dan tujuan.', '3.2', '', '', 10, 1440, 84, 0, 2025, 1, NULL, 'Bukti penerapan pengkajian pra sedasi (form pengkajian prasedasi) dan dicatat dalam rekam medis meliputi :\r\na)	Mengidentifikasi masalah saluran pernapasan yang dapat memengaruhi jenis sedasi yang digunakan; \r\nb)	Mengevaluasi pasien terhadap risiko tindakan sedasi;  \r\nc)	Merencanakan jenis sedasi dan tingkat kedalaman sedasi yang diperlukan pasien berdasarkan prosedur/tindakan yang akan dilakukan;  \r\nd)	Pemberian sedasi secara aman; dan  \r\ne)	Menyimpulkan temuan hasil pemantauan pasien selama prosedur.', NULL, '-	Penanggung jawab pelayanan  anestesi\r\n-	Staf anestesi.', NULL, '2025-07-02 14:03:29', 0, 'A'),
(5585, 'PAB 3.2 EP.2', 2, 'Rumah sakit telah menerapkan pemantauan pasien selama dilakukan pelayanan sedasi moderat dan dalam oleh PPA yang kompeten dan di catat di rekam medik.', '3.2', '', '', 10, 1440, 84, 0, 2025, 1, NULL, 'Bukti  penerapan pemantauan pasien selama sedasi moderat dan dalam  oleh staf anestesi  yang kompeten dicatat di rekam medis.', NULL, '-	Penanggung jawab pelayanan Anestesi\r\n-	Staf anestesi.', NULL, '2025-07-02 14:04:00', 0, 'A'),
(5586, 'PAB 3.2 EP.3', 3, 'Kriteria pemulihan telah digunakan dan didokumentasikan untuk mengidentifikasi pasien yang      sudah pulih kembali dan atau siap untuk ditransfer/dipulangkan.', '3.2', '', '', 10, 1440, 84, 0, 2025, 1, NULL, 'Bukti dalam rekam medis tentang   kriteria pemulihan telah digunakan untuk mengidentifikasi pasien yang sudah pulih kembali dan atau siap untuk ditransfer/ dipulangkan.', NULL, '-	Penanggung jawab pelayanan anestesi\r\n-	Staf anestesi.', NULL, '2025-07-02 14:04:20', 0, 'A'),
(5587, 'PAB 4 EP.1', 1, 'Pengkajian pra-anestesi telah dilakukan untuk setiap pasien yang akan dilakukan anestesi.', '4', '', '', 10, 1441, 84, 0, 2025, 1, NULL, 'Bukti dalam rekam medis tentang  pelaksanaan pengkajian pra anestesi  dengan konsep IAR oleh dokter anestesi sesuai PPK.', NULL, '-	DPJP\r\n-	Pasien/keluarga', NULL, '2025-07-02 14:04:40', 0, 'A'),
(5588, 'PAB 4 EP.2', 2, 'Pengkajian prainduksi telah dilakukan secara terpisah untuk mengevaluasi ulang pasien segera sebelum induksi anestesi.', '4', '', '', 10, 1441, 84, 0, 2025, 1, NULL, 'Bukti dalam rekam medis tentang  pelaksanaan pengkajian  pra induksi  dengan konsep IAR oleh dokter anestesi sesuai PPK.', NULL, 'DPJP.', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5589, 'PAB 4 EP.3', 3, 'Kedua pengkajian tersebut telah dilakukan oleh PPA yang kompeten dan telah diberikan kewenangan klinis didokumentasikan dalam rekam medis pasien.', '4', '', '', 10, 1441, 84, 0, 2025, 1, NULL, 'Bukti pengkajian pra anestesi dan pra induksi terisi lengkap dan ditanda tangani oleh PPA yang kompeten.', NULL, 'Dokter Anestesi.', NULL, '2025-07-02 14:05:20', 0, 'A'),
(5590, 'PAB 5 EP.1', 1, 'Rumah sakit telah menerapkan pemberian informasi kepada pasien dan atau keluarga  atau  pihak  yang  akan memberikan keputusan tentang jenis, risiko, manfaat, alternatif dan analagsia  pasca  tindakan  sedasi atau anastesi.', '5', '', '', 10, 1442, 84, 0, 2025, 1, NULL, 'Bukti penerapan pemberian informasi kepada pasien dan atau keluarga atau pihak yang akan memberikan keputusan tentang jenis, risiko, manfaat, alternatif dan analgesia pasca tindakan sedasi atau anestesi.', NULL, '-	DPJP\r\n-	Pasien/keluarga.', NULL, '2025-07-02 14:05:44', 0, 'A'),
(5591, 'PAB 5 EP.2', 2, 'Pemberian informasi dilakukan oleh dokter spesialis anastesi dan didokumentasikan dalam formulir persetujuan tindakan anastesi/sedasi.', '5', '', '', 10, 1442, 84, 0, 2025, 1, NULL, 'Bukti dalam rekam medis pemberian informasi dilakukan oleh dokter spesialis anestesi dan didokumentasikan di formulir persetujuan atau penolakan tindakan  anastesi/sedasi.', NULL, '-	Dokter Anestesi\r\n-	Dokter Bedah.', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5592, 'PAB 6 EP.1', 1, 'Frekuensi dan jenis pemantauan selama tindakan anestesi dan pembedahan didasarkan pada status praanestesi pasien, anestesi yang digunakan, serta prosedur pembedahan yang dilakukan.', '6', '', '', 10, 1443, 84, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan jenis pemantauan selama tindakan sedasi dan anestesi dan pembedahan didasarkan pada status praanestesi pasien, anestesi yang digunakan, serta prosedur pembedahan yang dilakukan pencatatan dengan frekuensi  sesuai regulasi.\r\nTermasuk bukti pemantauan anestesi lokal.', NULL, '-	Dokter Anestesi\r\n-	Dokter Bedah.', NULL, '2025-07-02 14:06:15', 0, 'A'),
(5593, 'PAB 6 EP.2', 2, 'Pemantauan status fisiologis pasien sesuai dengan panduan praktik klinis (PPK) dan didokumentasikan dalam rekam medis pasien.', '6', '', '', 10, 1443, 84, 0, 2025, 1, NULL, 'Bukti dalam rekam medis tentang pemantauan status fisiologis pasien yang menjalani anestesi.', NULL, '-	Dokter Anestesi\r\n-	Staf Anestesi.', NULL, '2025-07-02 14:06:35', 0, 'A'),
(5594, 'PAB 6.1 EP.1', 1, 'Rumah sakit telah menerapkan pemantauan pasien pascaanestesi baik di ruang intensif maupun di ruang pemulihan dan didokumentasikan dalam rekam medis pasien.', '6.1', '', '', 10, 1444, 84, 0, 2025, 1, NULL, 'Bukti dalam rekam medis tentang  pemantauan pasien pascaanestesi baik di ruang intensif maupun di ruang pemulihan.', NULL, '-	Dokter Anestesi\r\n-	Staf Anestesi.', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5595, 'PAB 6.1 EP.2', 2, 'Pasien dipindahkan dari unit pascaanestesi (atau pemantauan pemulihan dihentikan) sesuai dengan kriteria baku yang ditetapkan dengan alternatif a) sampai c)  pada maksud dan tujuan.', '6.1', '', '', 10, 1444, 84, 0, 2025, 1, NULL, 'Bukti dalam rekam medis tentang pelaksanaan pemindahan pasien dari unit pascaanestesi (atau pemantauan pemulihan dihentikan) sesuai dengan kriteria dengan alternatif :\r\na)	Pasien dipindahkan (atau pemantauan pemulihan dihentikan) oleh seorang dokter spesialis anestesi yang kompeten  berdasarkan kriteria pascaanestesi yang ditetapkan oleh rumah sakit\r\nb)	pasien dipindahkan (atau pemantauan pemulihan dihentikan) oleh seorang perawat atau penata anastesi yang kompeten  berdasarkan kriteria pascaanestesi yang ditetapkan oleh rumah sakit, tercatat dalam rekam medis bahwa kriteria tersebut terpenuhi. \r\nc)	Pasien dipindahkan ke unit yang mampu menyediakan perawatan pascaanestesi misalnya di unit perawatan intensif.', NULL, 'Staf anestesi.', NULL, '2025-07-02 14:07:32', 0, 'A'),
(5596, 'PAB 6.1 EP.3', 3, 'Waktu dimulai dan dihentikannya proses pemulihan dicatat di dalam rekam medis pasien.', '6.1', '', '', 10, 1444, 84, 0, 2025, 1, NULL, 'Bukti dalam rekam medis  tentang waktu dimulai dan dihentikannya proses pemulihan.', NULL, 'Staf Anestesi.', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5597, 'PAB 7 EP.1', 1, 'Rumah sakit telah menerapkan pengkajian prabedah pada pasien yang akan dioperasi oleh dokter penanggung jawab pelayanan (DPJP) sebelum operasi dimulai.', '7', '', '', 10, 1445, 84, 0, 2025, 1, 'Regulasi Pelayanan Pembedahan yang mengatur tatakelola pembedahan mulai dari penjadwalan, pengkajian, informed consent, rencana asuhan pascabedah.', '1)	Bukti dalam rekam medis tentang penerapan pengkajian   prabedah pada pasien yang akan dioperasi oleh dokter penanggung jawab pelayanan (DPJP) sebelum operasi dimulai, sesuai regulasi rumah sakit.\r\n2)	Bukti sesuai Std PP 1.1', NULL, 'DPJP.', NULL, '2025-07-02 14:08:21', 0, 'A'),
(5598, 'PAB 7 EP.2', 2, 'Diagnosis praoperasi dan rencana prosedur/tindakan operasi berdasarkan hasil pengkajian prabedah dan didokumentasikan di rekam medik.', '7', '', '', 10, 1445, 84, 0, 2025, 1, NULL, 'Bukti dalam rekam medis tentang diagnosis praoperasi dan rencana prosedur/tindakan operasi berdasarkan hasil pengkajian prabedah.', NULL, 'DPJP.', NULL, '2025-07-02 14:08:45', 0, 'A'),
(5599, 'PAB 7.1 EP.1', 1, 'Rumah sakit telah menerapkan pemberian informasi kepada pasien dan atau keluarga  atau  pihak  yang  akan memberikan keputusan tentang jenis, risiko, manfaat, komplikasi dan dampak serta alternatif prosedur/teknik terkait dengan rencana operasi (termasuk pemakaian produk darah bila diperlukan) kepada pasien dan atau keluarga atau mereka yang berwenang memberi keputusan.', '7.1', '', '', 10, 1446, 84, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan  pemberian informasi kepada pasien dan atau keluarga atau pihak yang akan memberikan keputusan tentang jenis, risiko, manfaat, komplikasi dan dampak serta alternatif prosedur/teknik terkait dengan rencana operasi (termasuk pemakaian produk darah bila diperlukan) kepada pasien dan atau keluarga atau mereka yang berwenang memberi keputusan, meliputi:\r\na)	Risiko dari rencana tindakan operasi; \r\nb)	Manfaat dari rencana tindakan operasi; \r\nc)	Memungkinan komplikasi dan dampak; \r\nd)	Pilihan operasi atau nonoperasi (alternatif) yang tersedia untuk menangani pasien; \r\ne)	Sebagai tambahan jika dibutuhkan darah atau produk darah, sedangkan risiko dan alternatifnya didiskusikan.', NULL, '-	DPJP\r\n-	Pasien/keluarga.', NULL, '2025-07-02 14:09:14', 0, 'A'),
(5600, 'PAB 7.1 EP.2', 2, 'Pemberian informasi dilakukan oleh dokter  penanggung jawab pelayanan (DPJP)      didokumentasikan dalam formulir persetujuan tindakan kedokteran.', '7.1', '', '', 10, 1446, 84, 0, 2025, 1, NULL, 'Bukti tentang  pemberian informasi dilakukan oleh dokter penanggung jawab pelayanan (DPJP) didokumentasikan dalam formulir persetujuan atau penolakan tindakan kedokteran.', NULL, 'DPJP.', NULL, '2025-07-02 14:10:10', 0, 'A'),
(5601, 'PAB 7.2 EP.1', 1, 'Laporan operasi memuat poin a) sampai h) pada maksud dan tujuan serta dicatat pada formular/template yang ditetapkan rumah sakit.', '7.2', '', '', 10, 1447, 84, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan laporan operasi dalam formulir laporan operasi yang memuat :\r\na)	Diagnosis pascaoperasi; \r\nb)	Nama dokter bedah dan asistennya; \r\nc)	Prosedur operasi yang dilakukan dan rincian temuan; \r\nd)	Ada dan tidak ada komplikasi; \r\ne)	Spesimen operasi yang dikirim untuk diperiksa; \r\nf)	Jumlah darah yang hilang dan jumlah yang masuk lewat transfusi; \r\ng)	Nomor pendaftaran alat yang dipasang (implan), (bila mempergunakan) \r\nh)	Tanggal, waktu, dan tanda tangan dokter   yang bertanggung jawab.', NULL, 'DPJP.', NULL, '2025-07-02 14:10:46', 0, 'A'),
(5602, 'PAB 7.2 EP.2', 2, 'Laporan operasi telah tersedia segera setelah operasi selesai dan sebelum pasien dipindah ke ruang lain untuk perawatan selanjutnya', '7.2', '', '', 10, 1447, 84, 0, 2025, 1, NULL, '1)	Bukti laporan operasi terisi lengkap sebelum pasien  dipindah ke ruang lain untuk perawatan selanjutnya. \r\n2)	Bukti laporan operasi bila dilakukan di ruang intensif.', NULL, 'DPJP.', NULL, '2025-07-02 14:11:07', 0, 'A'),
(5603, 'PAB 7.3 EP.1', 1, 'Rencana asuhan pascaoperasi dicatat di rekam medis pasien dalam waktu 24 jam oleh dokter penanggung jawab pelayanan (DPJP).', '7.3', '', '', 10, 1448, 84, 0, 2025, 1, NULL, 'Bukti rencana asuhan pascaoperasi dicatat di rekam medis dalam waktu 24 jam oleh dokter penanggung jawab pelayanan (DPJP).', NULL, 'DPJP.', NULL, '2025-07-02 14:11:25', 0, 'A'),
(5604, 'PAB 7.3 EP.2', 2, 'Rencana asuhan pascaoperasi termasuk rencana  asuhan medis, keperawatan, oleh PPA lainnya berdasar atas kebutuhan pasien.', '7.3', '', '', 10, 1448, 84, 0, 2025, 1, NULL, '1)	Bukti dalam rekam medis rencana asuhan pascaoperasi   termasuk rencana asuhan medis, keperawatan, oleh PPA lainnya berdasar atas kebutuhan pasien  \r\n2)	Rencana pascaoperasi dapat dibuat sebelum operasi.', NULL, '-	DPJP\r\n-	Dokter yang menerima delegasi\r\n-	Perawat\r\n-	PPA lain.', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5605, 'PAB 7.3 EP.3', 3, 'Rencana asuhan pascaoperasi diubah berdasarkan pengkajian ulang pasien.', '7.3', '', '', 10, 1448, 84, 0, 2025, 1, NULL, 'Bukti  dalam rekam medis  rencana asuhan pascaoperasi diubah /dikembangkan  berdasarkan pengkajian ulang pasien.', NULL, '-	DPJP\r\n-	Dokter yang menerima delegasi\r\n-	Perawat\r\n-	PPA lain.', NULL, '2025-07-02 14:12:17', 0, 'A'),
(5606, 'PAB 7.4 EP.1', 1, 'Rumah sakit telah mengidentifikasi jenis alat implan yang termasuk dalam cakupan layanannya.', '7.4', '', '', 10, 1449, 84, 0, 2025, 1, 'Regulasi tentang  penetapan jenis alat implan yang termasuk dalam pelayanan rumah sakit.', NULL, NULL, NULL, NULL, '2025-07-02 14:12:29', 0, 'A'),
(5607, 'PAB 7.4 EP.2', 2, 'Kebijakan dan praktik mencakup poin a)sampai h) pada maksud dan tujuan.', '7.4', '', '', 10, 1449, 84, 0, 2025, 1, 'Regulasi tentang penggunaan implan  bedah berupa hal hal yang meliputi:\r\na)	Pemilihan implan berdasarkan peraturan perundangan. \r\nb)	Modifikasi surgical safety checklist untuk memastikan ketersediaan implan di kamar operasi dan pertimbangan khusus untuk penandaan lokasi operasi. \r\nc)	Kualifikasi dan pelatihan setiap staf dari luar yang dibutuhkan untuk pemasangan implan (staf dari pabrik/perusahaan  implan untuk mengkalibrasi). \r\nd)	Proses pelaporan jika ada kejadian yang tidak diharapkan terkait implant. \r\ne)	Proses pelaporan malfungsi implan sesuai dgn standar/aturan pabrik. \r\nf)	Pertimbangan pengendalian infeksi yang khusus. \r\ng)	Instruksi khusus kepada pasien setelah operasi. \r\nh)	kemampuan penelusuran (traceability) alat jika terjadi penarikan kembali (recall) alat medis misalnya dengan menempelkan barcode alat di rekam medis.', NULL, NULL, NULL, NULL, '0000-00-00 00:00:00', 0, 'A'),
(5608, 'PAB 7.4 EP.3', 3, 'Rumah sakit mempunyai proses untuk melacak implan medis yang telah digunakan pasien.', '7.4', '', '', 10, 1449, 84, 0, 2025, 1, NULL, 'Bukti  proses untuk melacak implan medis yang telah digunakan pasien, Rumah Sakit (kamar Operasi) mempunyai format pelaporan penggunaan implan yang dapat ditelusur bila diperlukan.', NULL, '-	Kepala/staf unit kamar operasi\r\n-	Kepala/staf unit farmasi', NULL, '2025-07-02 14:13:19', 0, 'A'),
(5609, 'PAB 7.4 EP.4', 4, 'Rumah sakit menerapkan proses untuk menghubungi dan memantau pasien dalam jangka waktu yang ditentukan setelah menerima pemberitahuan adanya penarikan/recall suatu implan medis.', '7.4', '', '', 10, 1449, 84, 0, 2025, 1, NULL, 'Bukti pelaksanaan proses untuk melacak pasien dalam jangka waktu yang ditentukan setelah menerima pemberitahuan adanya recall implan medis. Untuk penerapan traceability, saran agar rumah sakit meminta pasien melapor bila ada perubahan alamat/no kontak.', NULL, '-	Kepala/staf unit kamar operasi\r\n-	Kepala/staf unit farmasi.', NULL, '2025-07-02 14:14:09', 0, 'A'),
(5610, 'PKPO 1 EP.1', 1, 'Rumah sakit telah menetapkan regulasi tentang sistem pelayanan kefarmasian dan penggunaan  obat,  termasuk pengorganisasiannya sesuai dengan peraturan perundang-undangan', '1', '', '', 10, 1450, 85, 0, 2025, 1, 'Regulasi tentang : \r\na)	Pedoman pelayanaan unit farmasi\r\nb)	Pedoman pengorganisasian unit farmasi\r\nc)	Pemilihan, perencanaan, pengadaan, penyimpanan, peresepan, dispensing, pemberian, pemantauan', NULL, NULL, NULL, NULL, '2025-07-02 14:20:07', 0, 'A'),
(5611, 'PKPO 1 EP.2', 2, 'Rumah sakit memiliki bukti seluruh apoteker memiliki izin dan kompeten, serta telah melakukan supervisi pelayanan kefarmasian dan memastikan kepatuhan terhadap peraturan perundang- undangan.', '1', '', '', 10, 1450, 85, 0, 2025, 1, NULL, '1)	Bukti ijin  (STRA dan SIPA) semua apoteker dan \r\n2)	Bukti hasil supervisi pelayanan kefarmasian', NULL, '-	Kepala Instalasi Farmasi\r\n-	Apoteker', NULL, '2025-07-02 14:20:34', 0, 'A'),
(5612, 'PKPO 1 EP.3', 3, 'Rumah sakit memiliki bukti kajian sistem pelayanan kefarmasian dan penggunaan obat yang dilakukan setiap tahun.', '1', '', '', 10, 1450, 85, 0, 2025, 1, NULL, 'Bukti kajian sistem pelayanan kefarmasian dan penggunaan obat yang dilakukan setiap tahun.', NULL, '-	Kepala Instalasi Farmasi\r\n-	Apoteker', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5613, 'PKPO 1 EP.4', 4, 'Rumah sakit memiliki sumber informasi obat untuk semua staf yang terlibat dalam penggunaan obat.', '1', '', '', 10, 1450, 85, 0, 2025, 1, NULL, 'Bukti  sumber informasi obat untuk semua staf yang terlibat dalam penggunaan obat', 'Lihat Instalasi Farmasi, unit-unit kerja terkait', '-	Kepala Instalasi Farmasi\r\n-	Kepala unit kerja', NULL, '2025-07-02 14:21:38', 0, 'A'),
(5614, 'PKPO 2 EP.1', 1, 'Rumah sakit telah memiliki proses penyusunan formularium rumah sakit secara kolaboratif.', '2', '', '', 10, 1451, 85, 0, 2025, 1, NULL, 'Bukti  pelaksanaan proses penyusunan formularium rumah sakit (undangan, materi rapat, daftar hadir, notulen rapat)', NULL, '-	Komite Farmasi Terapi\r\n-	Kepala Instalasi Farmasi', NULL, '2025-07-02 14:29:13', 0, 'A'),
(5615, 'PKPO 2 EP.2', 2, 'Rumah sakit melakukan pemantauan kepatuhan terhadap formularium baik dari persediaan maupun penggunaannya.', '2', '', '', 10, 1451, 85, 0, 2025, 1, NULL, 'Bukti pelaksanaan monitoring kepatuhan terhadap formularium baik dari persediaan maupun penggunaannya', NULL, '-	Komite Farmasi Terapi\r\n-	Kepala Instalasi Farmasi\r\n-	Staf Instalasi Farmasi', NULL, '2025-07-02 14:30:10', 0, 'A'),
(5616, 'PKPO 2 EP.3', 3, 'Rumah sakit melakukan evaluasi  terhadap formularium sekurang-kurangnya setahun sekali berdasarkan informasi tentang efektivitas, keamanan dan biaya.', '2', '', '', 10, 1451, 85, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan  evaluasi terhadap formularium oleh  Komite/Tim Farmasi dan Terapi sekurang-kurangnya setahun sekali', NULL, '-	Komite Farmasi terapi\r\n-	Kepala Instalasi Farmasi', NULL, '2025-07-02 14:30:36', 0, 'A'),
(5617, 'PKPO 2 EP.4', 4, 'Rumah sakit melakukan pelaksanaan dan evaluasi terhadap perencanaan dan pengadaan sediaan farmasi, dan BMHP.', '2', '', '', 10, 1451, 85, 0, 2025, 1, NULL, 'Bukti pelaksanaan dan evaluasi terhadap perencanaan dan pengadaan sediaan farmasi, dan BMHP.', NULL, '-	Kepala Instalasi Farmasi \r\n-	Staf Instalasi Farmasi', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5618, 'PKPO 2 EP.5', 5, 'Rumah sakit melakukan pengadaan sediaan farmasi, dan BMHP melibatkan apoteker untuk memastikan proses berjalan sesuai peraturan  perundang- undangan.', '2', '', '', 10, 1451, 85, 0, 2025, 1, NULL, 'Bukti  pengadaan sediaan farmasi, dan BMHP melibatkan apoteker', NULL, '-	Kepala Instalasi Farmasi \r\n-	Staf Instalasi Farmasi', NULL, '2025-07-02 14:31:20', 0, 'A'),
(5619, 'PKPO 3 EP.1', 1, 'Sediaan farmasi dan BMHP disimpan dengan benar  dan aman dalam kondisi yang sesuai untuk stabilitas produk, termasuk yang disimpan di luar Instalasi Farmasi.', '3', '', '', 10, 1452, 85, 0, 2025, 1, NULL, NULL, 'Lihat penyimpanan  sediaan farmasi dan BMHP sudah benar dan aman', '-	Kepala Instalasi Farmasi\r\n-	Staf instalasi / depo farmasi\r\n-	Staf gudang farmasi\r\n-	Perawat', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5620, 'PKPO 3 EP.2', 2, 'Narkotika dan psikotropika disimpan dan dilaporkan penggunaannya sesuai peraturan perundang- undangan.', '3', '', '', 10, 1452, 85, 0, 2025, 1, NULL, 'Laporan mutasi narkotika dan psikotropika', 'Narkotika psikotropika disimpan dan  dilaporkan penggunaannya sesuai peraturan perundang-undangan', '-	Kepala Instalasi Farmasi\r\n-	Staf instalasi / depo farmasi\r\n-	Staf gudang farmasi', NULL, '2025-07-02 14:32:40', 0, 'A'),
