(5622, 'PKPO 3 EP.4', 4, 'Obat dan zat kimia yang digunakan untuk peracikan obat diberi label secara akurat yang terdiri atas nama zat dan kadarnya, tanggal  kedaluwarsa,  dan  peringatan khusus.', '3', '', '', 10, 1452, 85, 0, 2025, 1, NULL, NULL, 'Pastikan semua obat  dan zat kimia yang digunakan untuk peracikan obat diberi label obat yang terdiri atas   nama zat dan kadarnya, tanggal kedaluwarsa, dan peringatan khusus', '-	Kepala instalasi farmasi \r\n-	Apoteker\r\n-	Staf Instalasi farmasi', NULL, '2025-07-02 14:33:28', 0, 'A'),
(5623, 'PKPO 3.1 EP.1', 1, 'Obat yang memerlukan penanganan  khusus  dan  bahan berbahaya dikelola sesuai sifat  dan  risiko  bahan.', '3.1', '', '', 10, 1453, 85, 0, 2025, 1, NULL, NULL, 'Penyimpanan obat yang memerlukan penanganan khusus dan  bahan berbahaya dilaksanakan sesuai sifat dan risiko bahan', '-	Kepala Instalasi Farmasi\r\n-	Staf instalasi / depo farmasi\r\n-	Staf gudang farmasi', NULL, '2025-07-02 14:34:01', 0, 'A'),
(5624, 'PKPO 3.1 EP.2', 2, 'Radioaktif dikelola sesuai sifat dan risiko bahan radioaktif.', '3.1', '', '', 10, 1453, 85, 0, 2025, 1, NULL, NULL, 'Penyimpanan obat dan bahan radio aktif sesuai  sifat dan risiko bahan radioaktif', '-	Kepala Instalasi Farmasi\r\n-	Staf instalasi / depo farmasi\r\n-	Staf gudang farmasi\r\n-	Apoteker', NULL, '2025-07-02 14:34:26', 0, 'A'),
(5625, 'PKPO 3.1 EP.3', 3, 'Obat penelitian dikelola sesuai protokol penelitian.', '3.1', '', '', 10, 1453, 85, 0, 2025, 1, NULL, NULL, 'Obat penelitian dikelola sesuai protokol penelitian. Pengelolaan termasuk pengaturan pemberiannya kepada subjek.', '-	Kepala Instalasi Farmasi\r\n-	Apoteker \r\n-	Staf Farmasi', NULL, '0000-00-00 00:00:00', 0, 'A'),
