(5627, 'PKPO 3.1 EP.5', 5, 'Obat/BMHP dari program/donasi dikelola sesuai peraturan perundang-undangan dan pedoman terkait.', '3.1', '', '', 10, 1453, 85, 0, 2025, 1, NULL, NULL, 'Obat/BMHP dari program/donasi dikelola sesuai peraturan perundang-undangan dan pedoman terkait', '-	Kepala Instalasi Farmasi\r\n-	Apoteker \r\n-	Staf Farmasi', NULL, '2025-07-02 14:35:48', 0, 'A'),
