(5629, 'PKPO 3.2 EP.2', 2, 'Rumah sakit menerapkan tata laksana obat emergensi untuk meningkatkan ketepatan dan kecepatan pemberian obat.', '3.2', '', '', 10, 1454, 85, 0, 2025, 1, NULL, 'Bukti tata laksana obat emergensi untuk meningkatkan ketepatan dan kecepatan pemberian obat', NULL, '-	Kepala Instalasi Farmasi\r\n-	Perawat\r\n-	Apoteker \r\n-	Staf Farmasi', NULL, '2025-07-02 14:37:03', 0, 'A'),
(5630, 'PKPO 3.3 EP.1', 1, 'Batas waktu obat dapat digunakan (beyond use dattercantum pada label obat.', '3.3', '', '', 10, 1455, 85, 0, 2025, 1, NULL, 'Daftar BUD yang mengacu pada referensi terpercaya dan terkini', 'Lihat label obat tercantum  Batas waktu obat dapat digunakan (BUD= beyond use date)', '-	Kepala Instalasi Farmasi\r\n-	Apoteker \r\n-	Staf Farmasi', NULL, '2025-07-02 14:39:07', 0, 'A'),
