(5632, 'PKPO 3.3 EP.3', 3, 'Rumah sakit menerapkan proses recall obat, BMHP dan implan yang meliputi identifikasi, penarikan, dan pengembalian produk yang di-recall.', '3.3', '', '', 10, 1455, 85, 0, 2025, 1, NULL, 'Bukti  pelaksanaan proses recall obat, BMHP dan implant yang meliputi identifikasi, penarikan, dan pengembalian produk yang di-recall.', NULL, '-	Kepala Instalasi Farmasi\r\n-	Apoteker \r\n-	Staf gudang farmasi', NULL, '2025-07-02 14:40:41', 0, 'A'),
