(5634, 'PKPO 4 EP.1', 1, 'Rumah sakit menerapkan rekonsiliasi obat saat pasien masuk rumah sakit, pindah antar unit pelayanan di dalam rumah sakit dan sebelum pasien pulang.', '4', '', '', 10, 1456, 85, 0, 2025, 1, NULL, 'Bukti  pelaksanaan rekonsiliasi obat saat pasien masuk rumah sakit, pindah antar unit pelayanan di dalam rumah sakit dan sebelum pasien pulang.', NULL, '-	Kepala Instalasi Farmasi\r\n-	Apoteker \r\n-	Dokter\r\n-	Perawat', NULL, '2025-07-02 14:41:32', 0, 'A'),
(5635, 'PKPO 4 EP.2', 2, 'Hasil rekonsiliasi obat didokumentasikan di rekam medis.', '4', '', '', 10, 1456, 85, 0, 2025, 1, NULL, 'Bukti pelaksanaan rekonsiliasi obat pada EP 1  didokumentasikan dalam rekam medis', NULL, '-	Kepala Instalasi Farmasi\r\n-	Apoteker \r\n-	Staf Farmasi\r\n-	Perawat', NULL, '0000-00-00 00:00:00', 0, 'A'),
