(5638, 'PKPO 4.1 EP.3', 3, 'Telah dilaksanaan proses untuk mengelola resep  khusus seperti emergensi, automatic  stop  order, tapering,', '4.1', '', '', 10, 1457, 85, 0, 2025, 1, NULL, 'Bukti  pelaksanaan resep khusus seperti\r\nemergensi, automatic stop order, dan tapering', NULL, '-	Kepala Instalasi Farmasi\r\n-	Apoteker \r\n-	Staf Farmasi', NULL, '2025-07-02 14:43:06', 0, 'A'),
(5639, 'PKPO 4.1 EP.4', 4, 'Daftar obat yang diresepkan tercatat dalam rekam medis pasien dan menyertai pasien ketika dipindahkan/transfer.', '4.1', '', '', 10, 1457, 85, 0, 2025, 1, NULL, 'Bukti  daftar obat yang diresepkan tercatat dalam rekam medis pasien  dan menyertai pasien ketika dipindahkan/transfer', NULL, '-	Kepala Instalasi Farmasi\r\n-	Apoteker \r\n-	Staf Farmasi', NULL, '2025-07-02 14:43:28', 0, 'A'),
(5640, 'PKPO 4.1 EP.5', 5, 'Daftar obat pulang diserahkan kepada pasien disertai edukasi penggunaannya.', '4.1', '', '', 10, 1457, 85, 0, 2025, 1, NULL, 'Bukti  edukasi penggunaan\r\nsemua obat pulang yang diserahkan kepada pasien', NULL, '-	Kepala Instalasi Farmasi\r\n-	Apoteker \r\n-	Staf Farmasi\r\n-	Pasien/keluarga', NULL, '2025-07-02 14:43:48', 0, 'A'),
(5641, 'PKPO 5 EP.1', 1, 'Telah memiliki sistem distribusi dan dispensing yang sama/seragam diterapkan di rumah sakit sesuai peraturan perundang-undangan.', '5', '', '', 10, 1458, 85, 0, 2025, 1, NULL, 'Bukti  pelaksanaan sistem distribusi dan dispensing yang sama/seragam diterapkan di rumah sakit sesuai peraturan perundang-undangan', NULL, '-	Kepala Instalasi Farmasi\r\n-	Apoteker \r\n-	Staf Farmasi', NULL, '2025-07-02 14:44:13', 0, 'A'),
(5642, 'PKPO 5 EP.2', 2, 'Staf yang melakukan dispensing sediaan  obat  non steril kompeten.', '5', '', '', 10, 1458, 85, 0, 2025, 1, NULL, NULL, 'Lihat pelaksanaan dispensing sediaan obat non steril', '-	Kepala Instalasi Farmasi\r\n-	Apoteker \r\n-	Staf Farmasi', NULL, '2025-07-02 14:44:28', 0, 'A'),
(5643, 'PKPO 5 EP.3', 3, 'Staf yang melakukan dispensing sediaan obat  steril  non sitostatika terlatih dan kompeten.', '5', '', '', 10, 1458, 85, 0, 2025, 1, NULL, 'Bukti sertifikat pelatihan  dispensing sediaan obat steril non sitostatika dari staf yang melakukan dispensing sediaan obat steril non sitostatika', NULL, '-	Kepala Instalasi Farmasi\r\n-	Apoteker \r\n-	Staf Farmasi', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5644, 'PKPO 5 EP.4', 4, 'Staf yang melakukan pencampuran sitostatika terlatih dan kompeten', '5', '', '', 10, 1458, 85, 0, 2025, 1, NULL, 'Bukti sertifikat pelatihan  pencampuran sitostatika dari staf yang melakukan pencampuran sitostatika', NULL, '-	Kepala Instalasi Farmasi\r\n-	Apoteker \r\n-	Staf Farmasi', NULL, '2025-07-02 14:45:05', 0, 'A'),
(5645, 'PKPO 5 EP.5', 5, 'Tersedia fasilitas dispensing sesuai standar praktik kefarmasian.', '5', '', '', 10, 1458, 85, 0, 2025, 1, NULL, 'Bukti hasil pemantauan  suhu, kelembaban, tekanan ruang, pemeliharaan LAF (Laminar Air Flow) cabinet, BSC (Bio Safety Cabinet)', '1)	Lihat kebersihan ruangan dispensing sediaan obat non steril  dan obat steril (sitostatika, non sitostatika, nutrisi parenteral)\r\n2)	Lihat pelaksanaan dispensing sediaan obat steril sitostatika\r\n3)	Lihat pelaksanaan dispensing sediaan obat steril non sitostatika', '-	Kepala Instalasi Farmasi\r\n-	Apoteker \r\n-	Tenaga teknis kefarmasian', NULL, '2025-07-02 14:45:42', 0, 'A'),
(5646, 'PKPO 5 EP.6', 6, 'Telah melaksanakan penyerahan obat dalam bentuk yang siap diberikan untuk pasien rawat inap.', '5', '', '', 10, 1458, 85, 0, 2025, 1, NULL, NULL, 'Obat untuk pasien rawat inap dikemas dalam bentuk unit dose (untuk satu kali waktu pemberian)', '-	Kepala Instalasi Farmasi\r\n-	Apoteker \r\n-	Staf Farmasi', NULL, '2025-07-02 14:46:14', 0, 'A'),
(5647, 'PKPO 5 EP.7', 7, 'Obat yang sudah disiapkan diberi etiket yang meliputi identitas pasien, nama obat, dosis atau konsentrasi,  cara pemakaian, waktu pemberian, tanggal dispensing dan tanggal kedaluwarsa/beyond use date (BUD).', '5', '', '', 10, 1458, 85, 0, 2025, 1, NULL, NULL, 'Lihat obat yang sudah disiapkan diberi etiket yang meliputi identitas pasien, nama obat, dosis atau konsentrasi, cara pemakaian, waktu pemberian, tanggal dispensing dan tanggal kedaluwarsa/beyond use date (BUD).', '-	Kepala Instalasi Farmasi\r\n-	Apoteker \r\n-	Staf Farmasi', NULL, '2025-07-02 14:46:46', 0, 'A'),
(5648, 'PKPO 5.1 EP.1', 1, 'Telah melaksanakan pengkajian resep yang dilakukan oleh staf yang kompeten dan berwenang  serta  didukung tersedianya informasi klinis pasien yang memadai.', '5.1', '', '', 10, 1459, 85, 0, 2025, 1, NULL, 'Bukti pelaksanaan pengkajian resep oleh staf yang kompeten  dan berwenang', 'Tersedia data klinis yang dapat diakses oleh apoteker pada saat melakukan pengkajian resep', '-	Kepala Instalasi Farmasi\r\n-	Apoteker \r\n-	Tenaga teknis kefarmasian', 'Pengkajian resep oleh apoteker', '2025-07-02 14:47:27', 0, 'A'),
(5649, 'PKPO 5.1 EP.2', 2, 'Telah memiliki proses telaah obat sebelum diserahkan.', '5.1', '', '', 10, 1459, 85, 0, 2025, 1, NULL, 'Bukti proses telaah obat sebelum diserahkan oleh farmasi', NULL, '-	Kepala Instalasi Farmasi\r\n-	Apoteker \r\n-	Tenaga teknis kefarmasian', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5650, 'PKPO 6 EP.1', 1, 'Staf yang melakukan pemberian obat kompeten dan berwenang dengan pembatasan yang ditetapkan.', '6', '', '', 10, 1460, 85, 0, 2025, 1, NULL, 'Bukti pelaksanaan pemberian obat dilaksanakan oleh staf klinis yang kompeten dan  berwenang dengan pembatasan  yang ditetapkan (lihat SPK dan RKKnya)', NULL, 'Perawat', NULL, '2025-07-02 14:48:14', 0, 'A'),
(5651, 'PKPO 6 EP.2', 2, 'Telah dilaksanaan verifikasi sebelum obat diberikan kepada pasien minimal meliputi: identitas pasien,  nama obat, dosis, rute, dan waktu pemberian.', '6', '', '', 10, 1460, 85, 0, 2025, 1, NULL, '', NULL, 'Perawat', 'Pelaksanaan verifikasi sebelum obat diberikan kepada pasien', '2025-07-02 14:48:33', 0, 'A'),
(5652, 'PKPO 6 EP.3', 3, 'Telah melaksanakan double checking untuk obat high alert.', '6', '', '', 10, 1460, 85, 0, 2025, 1, NULL, NULL, NULL, 'Perawat', 'Pelaksanaan double check untuk pemberian obat high alert  kepada pasien', '0000-00-00 00:00:00', 0, 'A'),
(5653, 'PKPO 6 EP.4', 4, 'Pasien diberi informasi tentang obat yang akan diberikan.', '6', '', '', 10, 1460, 85, 0, 2025, 1, NULL, 'Bukti  pemberian informasi tentang obat yang akan diberikan kepada pasien', NULL, '-	Apoteker \r\n-	Perawat', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5654, 'PKPO 6.1 EP.1', 1, 'Telah melakukan penilaian obat yang dibawa pasien dari luar rumah sakit  untuk  kelayakan  penggunaannya di rumah sakit.', '6.1', '', '', 10, 1461, 85, 0, 2025, 1, NULL, 'Bukti  pelaksanaan penilaian obat yang dibawa pasien dari luar rumah sakit untuk kelayakan penggunaannya di rumah sakit', NULL, '-	Kepala Instalasi Farmasi\r\n-	Apoteker', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5655, 'PKPO 6.1 EP.2', 2, 'Telah melaksanakan edukasi kepada pasien/keluarga jika obat akan digunakan secara mandiri.', '6.1', '', '', 10, 1461, 85, 0, 2025, 1, NULL, 'Bukti materi edukasi kepada pasien/keluarga jika obat akan digunakan secara mandiri.', NULL, '-	Apoteker \r\n-	Perawat', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5656, 'PKPO 6.1 EP.3', 3, 'Telah memantau pelaksanaan penggunaan obat secara mandiri sesuai edukasi.', '6.1', '', '', 10, 1461, 85, 0, 2025, 1, NULL, 'Bukti pemantauan  pelaksanaan penggunaan obat secara mandiri\r\nsesuai edukasi.', NULL, '-	Apoteker \r\n-	Perawat', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5657, 'PKPO 7 EP.1', 1, 'Telah melaksanakan pemantauan terapi obat secara kolaboratif.', '7', '', '', 10, 1462, 85, 0, 2025, 1, NULL, 'Bukti  pelaksanaan pemantauan terapi obat', NULL, 'Apoteker', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5658, 'PKPO 7 EP.2', 2, 'Telah melaksanakan pemantauan dan pelaporan efek samping obat serta analisis laporan untuk meningkatkan keamanan penggunaan obat.', '7', '', '', 10, 1462, 85, 0, 2025, 1, NULL, '1)	Bukti pelaksanaan pemantauan dan pelaporan efek samping obat\r\n2)	Bukti  analisis laporan untuk meningkatkan keamanan penggunaan obat', NULL, '-	Komite/Tim Farmasi dan Terapi\r\n-	Kepala Instalasi Farmasi\r\n-	Apoteker \r\n-	Staf Farmasi', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5659, 'PKPO 7.1 EP.1', 1, 'Rumah sakit telah memiliki regulasi tentang medication safety yang bertujuan mengarahkan penggunaan obat yang aman dan meminimalkan risiko kesalahan penggunaan obat sesuai dengan peraturan perundang- undangan.', '7.1', '', '', 10, 1463, 85, 0, 2025, 1, 'Regulasi tentang medication safety', NULL, NULL, NULL, NULL, '0000-00-00 00:00:00', 0, 'A'),
(5660, 'PKPO 7.1 EP.2', 2, 'Rumah sakit menerapkan sistem pelaporan kesalahan obat yang menjamin laporan akurat dan tepat waktu yang merupakan bagian program peningkatan mutu dan keselamatan pasien.', '7.1', '', '', 10, 1463, 85, 0, 2025, 1, NULL, 'Bukti  pelaksanaan pelaporan kesalahan obat dilaksanakan dengan akurat dan tepat waktu', NULL, '-	Komite Mutu\r\n-	Komite/Tim Farmasi dan Terapi\r\n-	Kepala Instalasi Farmasi\r\n-	Apoteker \r\n-	Staf Farmasi', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5661, 'PKPO 7.1 EP.3', 3, 'Rumah sakit memiliki upaya untuk mendeteksi, mencegah dan menurunkan kesalahan obat dalam meningkatkan mutu proses penggunaan obat.', '7.1', '', '', 10, 1463, 85, 0, 2025, 1, NULL, 'Bukti pelaksanaan   upaya untuk mendeteksi, mencegah dan menurunkan kesalahan obat dalam meningkatkan mutu proses penggunaan obat, berupa FMEA (Failure Mode and Effect Analysis)', NULL, '-	Komite Mutu\r\n-	Komite/Tim Farmasi dan Terapi\r\n-	Kepala Instalasi Farmasi\r\n-	Apoteker', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5662, 'PKPO 7.1 EP.4', 4, 'Seluruh staf rumah sakit dilatih terkait kesalahan obat (medication error).', '7.1', '', '', 10, 1463, 85, 0, 2025, 1, NULL, 'Bukti pelatihan tentang kesalahan obat (medication error)  meliputi TOR, undangan, daftar hadir, materi, laporan, evaluasi, sertifikat', NULL, '-	Komite Mutu\r\n-	Kepala Instalasi Farmasi\r\n-	Apoteker \r\n-	Staf Farmasi\r\n-	Staf Klinis', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5663, 'KE 1 EP.1', 1, 'Rumah sakit  menetapkan  regulasi   tentang  pelaksanaan PKRS di rumah sakit sesuai poin a) sampai b) pada gambaran umum.', '1', '', '', 10, 1466, 86, 0, 2025, 1, 'Regulasi tentang pelaksanaan PKRS sesuai pon a)-b)', NULL, NULL, NULL, NULL, '2025-07-02 14:42:01', 0, 'A'),
(5664, 'KE 1 EP.2', 2, 'Terdapat penetapan tim atau unit Promosi Kesehatan Rumah Sakit (PKRS) yang mengkoordinasikan      pemberian edukasi kepada pasien sesuai dengan peraturan perundang-undangan.', '1', '', '', 10, 1466, 86, 0, 2025, 1, 'Regulasi tentang penetapan Tim atau unit PKRS, disertai dengan Pedoman Kerja', NULL, NULL, NULL, NULL, '0000-00-00 00:00:00', 0, 'A'),
(5665, 'KE 1 EP.3', 3, 'Tim atau unit PKRS menyusun program kegiatan promosi kesehatan rumah sakit setiap tahunnya, termasuk kegiatan edukasi rutin sesuai dengan misi rumah sakit, layanan, dan populasi pasiennya.', '1', '', '', 10, 1466, 86, 0, 2025, 1, 'Bukti tentang Program PKRS setiap tahun', NULL, NULL, NULL, NULL, '0000-00-00 00:00:00', 0, 'A'),
(5666, 'KE 1 EP.4', 4, 'Rumah sakit telah menerapkan pemberian edukasi kepada pasien dan keluarga menggunakan media, format, dan metode yang yang telah ditetapkan.', '1', '', '', 10, 1466, 86, 0, 2025, 1, NULL, NULL, 'Lihat penerapan pemberian edukasi dengan menggunakan media, format, dan metode yang yang telah  ditetapkan.', 'Kepala/staf tim/unit PKRS', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5667, 'KE 2 EP.1', 1, 'Tersedia informasi untuk pasien dan keluarga mengenai asuhan dan pelayanan yang disediakan oleh rumah sakit serta akses untuk mendapatkan layanan tersebut. Informasi dapat disampaikan secara  langsung dan/atau tidak langsung.', '2', '', '', 10, 1467, 86, 0, 2025, 1, NULL, 'Bukti materi informasi tentang:\r\na)	Asuhan dan pelayanan yang disediakan oleh rumah sakit \r\nb)	Akses untuk mendapatkan layanan dalam bentuk brosur/leaflet/banner, buletin,  Web site,  call center/SMS center, seminar awam,  pameran, slide show di TV internal / LCD dll.', NULL, '-	Staf admisi/bagian Informasi\r\n-	Unit/Tim PKRS\r\n-	Pasien/keluarga', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5668, 'KE 2 EP.2', 2, 'Rumah sakit menyampaikan informasi kepada pasien dan keluarga terkait alternatif asuhan  dan pelayanan  di tempat lain, apabila rumah sakit tidak dapat      memberikan asuhan dan pelayanan yang dibutuhkan pasien.', '2', '', '', 10, 1467, 86, 0, 2025, 1, NULL, 'Bukti tentang penyampaian informasi kepada pasien dan keluarga terkait alternatif asuhan dan pelayanan di tempat lain, apabila rumah sakit tidak dapat memberikan asuhan dan pelayanan yang dibutuhkan pasien.', NULL, '-	Staf admisi\r\n-	Staf klinis\r\n-	Pasien/keluarga', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5669, 'KE 2 EP.3', 3, 'Akses mendapatkan informasi kesehatan diberikan secara tepat waktu, dan status sosial ekonomi perawatan pasien tidak menghalangi pasien dan keluarga untuk mendapatkan informasi yang dibutuhkan.', '2', '', '', 10, 1467, 86, 0, 2025, 1, NULL, NULL, NULL, '-	Staf admisi\r\n-	Pasien/keluarga', NULL, '2025-07-02 15:00:03', 0, 'A'),
(5670, 'KE 2 EP.4', 4, 'Terdapat bukti pemberian informasi untuk pasien dan keluarga mengenai asuhan dan pelayanan di rumah sakit.', '2', '', '', 10, 1467, 86, 0, 2025, 1, NULL, 'Bukti tentang pemberian informasi untuk pasien dan keluarga mengenai asuhan dan pelayanan', NULL, NULL, NULL, '2025-07-02 15:00:15', 0, 'A'),
(5671, 'KE 3 EP.1', 1, 'Kebutuhan edukasi pasien dan keluarga dinilai berdasarkan pengkajian terhadap kemampuan dan kemauan belajar pasien dan  keluarga  yang  meliputi poin a) sampai f) pada maksud dan tujuan, dan dicatat di rekam medis.', '3', '', '', 10, 1468, 86, 0, 2025, 1, NULL, 'Bukti tentang pengkajian terhadap kemampuan dan kemauan belajar pasien dan keluarga dicatat di rekam medis yang meliputi :\r\na)	Kemampuan membaca, tingkat Pendidikan; \r\nb)	Bahasa yang digunakan (apakah diperlukan penerjemah atau penggunaan bahasa isyarat); \r\nc)	Hambatan emosional dan motivasi; \r\nd)	Keterbatasan fisik dan kognitif; \r\ne)	Kesediaan pasien untuk menerima informasi; dan \r\nf)	Nilai-nilai dan pilihan pasien.', NULL, '-	Staf klinis\r\n-	Pasien/keluarga', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5672, 'KE 3 EP.2', 2, 'Hambatan dari pasien dan keluarga dalam menerima edukasi dinilai sebelum pemberian  edukasi  dan dicatat di rekam medis.', '3', '', '', 10, 1468, 86, 0, 2025, 1, NULL, 'Bukti dalam rekam medis tentang pengkajian terhadap hambatan dari pasien dan keluarga dalam menerima edukasi.', NULL, '-	Staf klinis\r\n-	Pasien/keluarga', NULL, '2025-07-02 15:01:08', 0, 'A'),
(5673, 'KE 3 EP.3', 3, 'Terdapat bukti dilakukan pengkajian kemampuan dan kemauan belajar pasien/keluarga, serta hasil pengkajian digunakan PPA untuk membuat perencanaan kebutuhan edukasi.', '3', '', '', 10, 1468, 86, 0, 2025, 1, NULL, 'Bukti dalam rekam medis tentang hasil pengkajian digunakan  untuk membuat perencanaan kebutuhan edukasi.', NULL, '-	Staf klinis', NULL, '2025-07-02 15:01:33', 0, 'A'),
(5674, 'KE 4 EP.1', 1, 'Terdapat bukti bahwa edukasi yang diberikan kepada pasien dan keluarga telah diberikan dengan cara dan bahasa yang mudah dipahami.', '4', '', '', 10, 1469, 86, 0, 2025, 1, NULL, 'Bukti tentang materi edukasi telah diberikan dalam cara dan bahasa yang mudah dipahami oleh pasien', NULL, 'Pasien/ keluarga\r\n\r\n(Lihat juga KE 5 EP 4)', NULL, '2025-07-02 15:02:14', 0, 'A');
INSERT INTO `accreditation_instrument` (`instrument_id`, `instrument_reference_code`, `instrument_order_id`, `instrument_name`, `instrument_objective`, `instrument_material`, `instrument_document`, `instrument_maximum_score`, `instrument_standard_id`, `instrument_chapter_id`, `instrument_class_id`, `instrument_version`, `instrument_institution_group_id`, `instrument_r`, `instrument_d`, `instrument_o`, `instrument_w`, `instrument_s`, `instrument_update`, `instrument_user_id`, `instrument_record_status`) VALUES
(5675, 'KE 4 EP.2', 2, 'Terdapat bukti bahwa  pasien/keluarga  telah dijelaskan mengenai hasil pengkajian, diagnosis, rencana asuhan, dan hasil pengobatan, termasuk hasil pengobatan yang tidak diharapkan.', '4', '', '', 10, 1469, 86, 0, 2025, 1, NULL, 'Bukti pemberian penjelasan  oleh DPJP dan PPJA tentang :\r\n-	hasil pengkajian, \r\n-	diagnosis, \r\n-	rencana asuhan, dan\r\n-	hasil pengobatan, \r\n-	termasuk hasil pengobatan yang tidak diharapkan', NULL, '-	PPA\r\n-	Pasien/ keluarga\r\n\r\n(Lihat juga HPK 2 EP 2 dan 3)', NULL, '2025-07-02 15:02:41', 0, 'A'),
(5676, 'KE 4 EP.3', 3, 'Terdapat bukti edukasi kepada pasien dan keluarga terkait dengan cara cuci tangan yang aman, penggunaan obat yang aman, penggunaan peralatan medis yang aman, potensi interaksi obat-obat dan obat-makanan, pedoman nutrisi, manajemen nyeri, dan teknik rehabilitasi serta edukasi asuhan lanjutan   di rumah.', '4', '', '', 10, 1469, 86, 0, 2025, 1, NULL, 'Bukti pelaksanaan pemberian edukasi tentang:\r\n1)	cara cuci tangan yang aman, \r\n2)	penggunaan obat yang aman, \r\n3)	penggunaan peralatan medis yang aman, \r\n4)	potensi interaksi obat obat dan obat-makanan, \r\n5)	pedoman nutrisi, \r\n6)	manajemen nyeri,  \r\n7)	teknik rehabilitasi \r\n8)	edukasi asuhan lanjutan di rumah.', NULL, '-	DPJP/PPJA/PPA lainnya/tim PPI\r\n-	Pasien/keluarga', NULL, '2025-07-02 15:03:14', 0, 'A'),
(5677, 'KE 5 EP.1', 1, 'Rumah sakit memiliki proses untuk memastikan  bahwa pasien dan keluarganya memahami edukasi yang diberikan.', '5', '', '', 10, 1470, 86, 0, 2025, 1, NULL, 'Bukti pelaksanaan verifikasi untuk memastikan bahwa pasien  dan keluarganya memahami edukasi yang diberikan.', NULL, '-	PPA\r\n-	Staf Klinis\r\n-	Pasien/keluarga', NULL, '2025-07-02 15:03:43', 0, 'A'),
(5678, 'KE 5 EP.2', 2, 'Proses pemberian edukasi di dokumentasikan dalam rekam medik sesuai dengan metode edukasi yang  dapat diterima pasien dan keluarganya.', '5', '', '', 10, 1470, 86, 0, 2025, 1, NULL, 'Bukti pemberian materi edukasi yang tertulis', NULL, '-	PPA\r\n-	Staf Klinis\r\n-	Pasien/keluarga', NULL, '2025-07-02 15:04:03', 0, 'A'),
(5679, 'KE 5 EP.3', 3, 'Materi edukasi untuk pasien dan keluarga selalu tersedia dan diperbaharui secara berkala.', '5', '', '', 10, 1470, 86, 0, 2025, 1, NULL, 'Bukti materi edukasi tertulis yang diperbaharui secara berkala', NULL, 'Unit/Tim PKRS', NULL, '2025-07-02 15:04:27', 0, 'A'),
(5680, 'KE 5 EP.4', 4, 'Informasi dan edukasi disampaikan kepada  pasien  dan keluarga dengan menggunakan format yang  praktis dan dengan bahasa yang dipahami pasien dan keluarga.', '5', '', '', 10, 1470, 86, 0, 2025, 1, NULL, 'Bukti materi edukasi tertulis dengan menggunakan format yang praktis dan dengan bahasa yang dipahami pasien dan keluarga.', NULL, 'Pasien/keluarga\r\n\r\n(Lihat juga KE 4 EP 1)', NULL, '2025-07-02 15:04:48', 0, 'A'),
(5681, 'KE 5 EP.5', 5, 'Rumah sakit menyediakan penerjemah (bahasa dan bahasa isyarat) sesuai dengan kebutuhan pasien dan keluarga.', '5', '', '', 10, 1470, 86, 0, 2025, 1, NULL, '1)	Bukti daftar penterjemah sesuai kebutuhan pasien\r\n2)	Bukti tentang MoU dengan pihak terkait', NULL, 'Pasien/keluarga', NULL, '2025-07-02 15:05:27', 0, 'A'),
(5682, 'KE 6 EP.1', 1, 'Rumah sakit mengidentifikasi sumber-sumber yang ada di komunitas untuk mendukung promosi kesehatan berkelanjutan dan edukasi untuk menunjang asuhan pasien yang berkelanjutan.', '6', '', '', 10, 1471, 86, 0, 2025, 1, NULL, 'Bukti tentang daftar faskes primer dan praktik mandiri untuk mendukung promosi kesehatan berkelanjutan dan edukasi untuk menunjang asuhan pasien yang berkelanjutan.', NULL, 'Unit/Tim PKRS', NULL, '2025-07-02 15:05:48', 0, 'A'),
(5683, 'KE 6 EP.2', 2, 'Rumah sakit telah memiliki jejaring di komunitas untuk mendukung asuhan pasien berkelanjutan.', '6', '', '', 10, 1471, 86, 0, 2025, 1, 'Regulasi tentang MOU/ kerjasama dengan jejaring dikomunitas untuk mendukung asuhan pasien berkelanjutan.', NULL, NULL, NULL, NULL, '2025-07-02 15:20:37', 0, 'A'),
(5684, 'KE 6 EP.3', 3, 'Memiliki bukti telah disampaikan kepada pasien dan keluarga tentang edukasi lanjutan dikomunitas. Rujukan edukasi tersebut dilaksanakan oleh jejaring utama yaitu Fasilitas Kesehatan Tingkat Pertama (FKTP).', '6', '', '', 10, 1471, 86, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan rujukan edukasi lanjutan di komunitas.', NULL, '-	PPA\r\n-	Staf klinis\r\n-	MPP', NULL, '2025-07-02 15:21:00', 0, 'A'),
(5685, 'KE 6 EP.4', 4, 'Terdapat bukti edukasi berkelanjutan tersebut diberikan kepada pasien sesuai dengan kebutuhan.', '6', '', '', 10, 1471, 86, 0, 2025, 1, NULL, 'Bukti materi edukasi diberikan sesuai dengan kebutuhan pasien', NULL, '-	PPA\r\n-	Staf klinis\r\n-	Pasien/keluarga', NULL, '2025-07-02 15:21:18', 0, 'A'),
(5686, 'KE 7 EP.1', 1, 'Profesional Pemberi Asuhan (PPA) telah diberikan pelatihan dan terampil melaksanakan komunikasi efektif.', '7', '', '', 10, 1472, 86, 0, 2025, 1, NULL, 'Bukti tentang pelaksanaan pelatihan komunikasi efektif, berupa: TOR, undangan, daftar hadir, materi, laporan, evaluasi, sertifikat', NULL, 'PPA', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5687, 'KE 7 EP.2', 2, 'PPA telah memberikan edukasi yang efektif kepada pasien dan keluarga secara kolaboratif.', '7', '', '', 10, 1472, 86, 0, 2025, 1, NULL, 'Bukti tentang materi edukasi kolaboratif yang disampaikan kepada pasien.', NULL, 'PPA terkait', NULL, '2025-07-02 15:22:17', 0, 'A'),
(5688, 'SKP 1 EP.1', 1, 'Rumah sakit telah menetapkan regulasi terkait Sasaran keselamatan pasien meliputi poin 1 sampai 6 pada gambaran umum.', '1', '', '', 10, 1473, 87, 0, 2025, 1, 'Regulasi tentang penetapan sasaran keselamatan pasien meliputi:\r\n1)	Mengidentifikasi pasien dengan benar; \r\n2)	Meningkatkan komunikasi yang efektif; \r\n3)	Meningkatkan keamanan obat-obatan yang harus diwaspadai; \r\n4)	Memastikan sisi yang benar, prosedur yang benar, pasien yang benar pada pembedahan/tindakan invasif; \r\n5)	Mengurangi risiko infeksi akibat perawatan kesehatan; dan \r\n6)	Mengurangi risiko cedera pasien akibat jatuh.', NULL, NULL, NULL, NULL, '0000-00-00 00:00:00', 0, 'A'),
(5689, 'SKP 1 EP.2', 2, 'Rumah sakit telah menerapkan proses identifikasi pasien menggunakan minimal 2 (dua) identitas, dapat memenuhi tujuan identifikasi pasien dan sesuai dengan ketentuan rumah sakit.', '1', '', '', 10, 1473, 87, 0, 2025, 1, NULL, 'Bukti pelaksanaan tentang identitas pasien dengan minimal menggunakan 2 (dua) dari 4 (empat)identitas : \r\n1)	Nama pasien sesuai KTP-el\r\n2)	Tanggal lahir\r\n3)	Nomor Rekam Medis\r\n4)	Nomor induk kependudukan', NULL, '-	Staf unit pelayanan\r\n-	Staf klinis\r\n-	Pasien/keluarga', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5690, 'SKP 1 EP.3', 3, 'Pasien telah diidentifikasi menggunakan minimal dua jenis identitas meliputi poin 1)-4) dalam maksud dan tujuan.', '1', '', '', 10, 1473, 87, 0, 2025, 1, NULL, NULL, 'Lihat pelaksanaan identifikasi pasien dengan minimal menggunakan 2 (dua) identitas; nama pasien sesuai KTP-el dan tanggal lahir pada saat;\r\n1)	melakukan tindakan intervensi/terapi (misalnya pemberian obat, pemberian darah atau produk darah, melakukan terapi radiasi); \r\n2)	melakukan tindakan (misalnya memasang jalur intravena atau hemodialisis); \r\n3)	sebelum tindakan diagnostik apa pun (misalnya mengambil darah dan spesimen lain untuk pemeriksaan laboratorium penunjang, atau sebelum melakukan kateterisasi jantung ataupun tindakan radiologi diagnostik); dan \r\n4)	menyajikan makanan pasien\r\n5)	Staf unit pelayanan', '-	Staf klinis\r\n-	Pasien/keluarga', 'Peragaan pelaksanaan identifikasi pasien', '2025-07-02 15:28:32', 0, 'A'),
(5691, 'SKP 1 EP.4', 4, 'Rumah sakit memastikan pasien  teridentifikasi  dengan tepat pada situasi khusus, dan penggunaan label seperti tercantum dalam maksud dan tujuan.', '1', '', '', 10, 1473, 87, 0, 2025, 1, NULL, '1)	Bukti pelaksanaan identifikasi pada pasien koma, bayi baru lahir dan pada saat terjadi darurat bencana\r\n2)	Bukti pengunaan label pada sampel darah dan sampel patologi, nampan makanan pasien, label ASI yang disimpan untuk bayi yang dirawat', NULL, '-	Staf unit pelayanan\r\n-	Staf klinis', NULL, '2025-07-02 15:30:16', 0, 'A'),
(5692, 'SKP 2 EP.1', 1, 'Rumah sakit telah menerapkan komunikasi saat menerima instruksi melalui telepon: menulis/menginput ke komputer\n-	membacakan - konfirmasi kembali\' (writedown, read back, confirmation dan SBAR saat melaporkan kondisi pasien kepada DPJP serta di dokumentasikan dalam rekam medik.', '2', '', '', 10, 1474, 87, 0, 2025, 1, NULL, 'Bukti dokumen the read-back process\r\n1)	Bukti pesan melalui lewat telpon ditulis lengkap, dibaca ulang oleh penerima pesan, dan dikonfirmasi oleh pemberi pesan. \r\n2)	Bukti dokumentasi pelaksanaan pelaporan dengan metode SBAR', NULL, '-	DPJP \r\n-	PPJA/Staf Perawat\r\n-	Staf klinis lainnya', 'Peragaan proses penerimaan pesan secara verbal atau verbal lewat telpon', '2025-07-02 15:31:03', 0, 'A'),
(5693, 'SKP 2 EP.2', 2, 'Rumah sakit telah menerapkan komunikasi saat pelaporan hasil kritis pemeriksaan penunjang diagnostic  melalui  telepon: menulis/menginput ke komputer, membacakan, konfirmasi kembali (writedown, read back, confirmation) dan di dokumentasikan dalam rekam medik.', '2', '', '', 10, 1474, 87, 0, 2025, 1, NULL, 'Bukti dokumen berupa;\r\n1)	Hasil nilai kritis yang dilaporkan\r\n2)	 Pencatatan pesan yang disampaikan pada penyampaian hasil pemeriksaaan diagnostik, dan bukti konfirmasi', NULL, '-	DPJP \r\n-	PPJA/Staf Perawat\r\n-	Staf klinis lainnya', 'Peragaan penyampaian hasil pemeriksaan diagnostik', '2025-07-02 15:31:30', 0, 'A'),
(5694, 'SKP 2 EP.3', 3, 'Rumah sakit telah menerapkan komunikasi saat  serah terima sesuai dengan jenis serah terima meliputi poin 1)-3) dalam maksud dan tujuan.', '2', '', '', 10, 1474, 87, 0, 2025, 1, NULL, 'Bukti formulir serah terima, memuat alat, metode serah terima pasien (operan/hand over);\r\n1)	antara PPA\r\n2)	antara unit perawatan yang berbeda di dalam rumah sakit\r\n3)	dari ruang perawatan pasien ke unit layanan diagnostik seperti radiologi atau fisioterapi.', NULL, '-	DPJP \r\n-	PPJA/Staf Perawat\r\n-	Staf klinis lainnya', NULL, '2025-07-02 15:32:21', 0, 'A'),
(5695, 'SKP 3 EP.1', 1, 'Rumah sakit menetapkan daftar obat kewaspadaan tinggi\n(High Alert) termasuk obat Look -Alike Sound Alike (LASA).', '3', '', '', 10, 1475, 87, 0, 2025, 1, 'Regulasi  tentang daftar obat yang perlu diwaspadai. Sesuai regulasi RS\r\nDaftar disusun berdasarkan kelompok \r\n-	Obat LASA/Norum\r\n-	Elektrolit konsentrasi tinggi \r\n-	Obat sitostatika; dan Obat lainnya (sesuai ISMP)', NULL, 'Lihat pelaksanaan penggunaan daftar obat di unit terkait', '-	PPA \r\n-	Staf unit pelayanan (Apoteker/TTK)\r\n-	Staf klinis', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5696, 'SKP 3 EP.2', 2, 'Rumah sakit menerapkan pengelolaan obat kewaspadaan tinggi (High Alert) termasuk obat Look -Alike Sound Alike (LASA) secara seragam di seluruh area rumah sakit untuk mengurangi risiko dan cedera', '3', '', '', 10, 1475, 87, 0, 2025, 1, NULL, 'Bukti pelaksanaan tentang penyediaan, penyimpanan, penataan, penyiapan dan penggunaan obat yang perlu diwaspadai\r\n(High Alert) termasuk obat Look-Alike Sound Alike (LASA) sesuai regulasi RS', NULL, '-	Apoteker/TTK\r\n-	PPJA dan staf perawat\r\n-	Staf klinis', NULL, '2025-07-02 15:33:22', 0, 'A'),
(5697, 'SKP 3 EP.3', 3, 'Rumah sakit mengevaluasi dan memperbaharui daftar obat High-Alert dan obat Look -Alike Sound Alike (LASA) yang sekurang-kurangnya 1 (satu) tahun sekali berdasarkan laporan insiden lokal, nasional dan internasional.', '3', '', '', 10, 1475, 87, 0, 2025, 1, NULL, 'Bukti pelaksanaan evaluasi dan daftar obat High-Alert dan obat Look-Alike Sound Alike (LASA) yang sekurang-kurangnya 1 (satu) tahun', NULL, '-	Apoteker/TTK\r\n-	PPJA dan staf perawat\r\n-	Staf klinis', NULL, '2025-07-02 15:33:45', 0, 'A'),
(5698, 'SKP 3.1 EP.1', 1, 'Rumah sakit menerapkan proses penyimpanan elektrolit konsentrat tertentu hanya di Instalasi Farmasi, kecuali di unit pelayanan dengan pertimbangan klinis untuk      mengurangi risiko dan cedera pada penggunaan elektrolit konsentrat.', '3.1', '', '', 10, 1476, 87, 0, 2025, 1, NULL, 'Bukti tentang daftar elektrolit konsentrat tertentu yang dapat disimpan diluar instalasi farmasi  sesuai regulasi RS', 'Lihat pelaksanaan tempat penyimpanan', '-	PPA \r\n-	Staf unit pelayanan (Apoteker/TTK)', NULL, '2025-07-02 15:34:14', 0, 'A'),
(5699, 'SKP 3.1 EP.2', 2, 'Penyimpanan elektrolit konsentrat di luar Instalasi Farmasi diperbolehkan hanya dalam untuk situasi yang ditentukan sesuai dalam maksud dan tujuan.', '3.1', '', '', 10, 1476, 87, 0, 2025, 1, NULL, 'Bukti tentang daftar sediaan elektrolit konsentrat yang dapat disimpan diluar instalasi farmasi  untuk situasi (kondisi pasien gawat/pasien kritis) sesuai regulasi RS', 'Lihat  tempat penyimpanan sediaan elektrolit konsentrat diluar farmasi untuk situasi tertentu', '-	PPA \r\n-	Staf unit pelayanan (Apoteker/TTK)', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5700, 'SKP 3.1 EP.3', 3, 'Rumah sakit menetapkan dan menerapkan protokol koreksi hipokalemia, hiponatremia, hipofosfatemia.', '3.1', '', '', 10, 1476, 87, 0, 2025, 1, NULL, 'Bukti ada protokol koreksi hipokalemia, hiponatremia, hipofosfatemia.', 'Bukti penerapan protocol koreksi hipokalemia, hiponatremia,hipofosfatemia sesuai regulasi RS', '-	Apoteker\r\n-	Staf klinis', NULL, '2025-07-02 15:35:26', 0, 'A'),
(5701, 'SKP 4 EP.1', 1, 'Rumah sakit telah melaksanakan proses verifikasi pra operasi dengan daftar tilik untuk memastikan benar pasien, benar tindakan dan benar sisi.', '4', '', '', 10, 1477, 87, 0, 2025, 1, NULL, 'Bukti adanya daftar tilik verifikasi pra operasi dan bukti pelaksanaannya yang memuat, benar pasien, benar tindakan dan benar sisi', 'Bukti verifikasi pra operasi telah dilaksanakan', 'Staf klinis', NULL, '2025-07-02 15:36:04', 0, 'A'),
(5702, 'SKP 4 EP.2', 2, 'Rumah sakit telah menetapkan dan  menerapkan  tanda  yang seragam, mudah dikenali dan tidak bermakna ganda untuk mengidentifikasi sisi operasi atau tindakan invasif.', '4', '', '', 10, 1477, 87, 0, 2025, 1, NULL, NULL, 'Bukti menerapkan tanda yang seragam sesuai regulasi', 'DPJP', NULL, '2025-07-02 15:36:24', 0, 'A'),
(5703, 'SKP 4 EP.3', 3, 'Rumah sakit telah menerapkan penandaan sisi operasi atau tindakan invasif (site  marking) dilakukan oleh dokter operator/dokter asisten yang melakukan operasi atau tindakan invasif dengan melibatkan pasien bila memungkinkan.', '4', '', '', 10, 1477, 87, 0, 2025, 1, NULL, NULL, 'Bukti pelaksanaan penandaan sisi operasi atau tindakan invasif (site marking) dilakukan oleh dokter operator/dokter asisten yang melakukan operasi atau tindakan invasif dengan melibatkan pasien bila memungkinkan.', '-	DPJP\r\n-	Pasien/keluarga', NULL, '2025-07-02 15:37:38', 0, 'A'),
(5704, 'SKP 4 EP.4', 4, 'Rumah sakit telah menerapkan proses Time-Out menggunakan surgical check list (Surgical Safety Checklist)      dari WHO terkini pada tindakan operasi termasuk tindakan medis invasif.', '4', '', '', 10, 1477, 87, 0, 2025, 1, NULL, 'Bukti penerapan  proses Time-Out menggunakan “surgical check list” (Surgical Safety Checklist) dari WHO terkini pada tindakan operasi termasuk tindakan medis invasif.', 'Lihat form surgical safety check list', '-	DPJP\r\n-	Tim operasi', NULL, '2025-07-02 15:38:28', 0, 'A'),
(5705, 'SKP 5 EP.1', 1, 'Rumah sakit telah menerapkan kebersihan tangan (hand hygiene) yang mengacu pada standar WHO terkini.', '5', '', '', 10, 1478, 87, 0, 2025, 1, NULL, NULL, 'Bukti penerapan  kebersihan tangan (hand hygiene) di seluruh rumah sakit termasuk:\r\n-	kelengkapan fasilitas hand hygiene \r\n-	Pelaksanaan hand hygiene secara konsisten oleh staf', 'Staf RS', 'Peragaan kebersihan tangan tangan', '2025-07-02 15:39:31', 0, 'A'),
(5706, 'SKP 5 EP.2', 2, 'Terdapat proses evaluasi terhadap pelaksanaan program kebersihan tangan di rumah sakit serta upaya perbaikan yang dilakukan untuk meningkatkan pelaksanaan program.', '5', '', '', 10, 1478, 87, 0, 2025, 1, NULL, 'Bukti pelaksanaan evaluasi terhadap program kebersihan tangan di rumah sakit serta upaya perbaikan yang dilakukan.', NULL, '-	Komite/Tim PMKP\r\n-	Komite/Tim PPI\r\n-	IPCN\r\n-	IPCLN', NULL, '0000-00-00 00:00:00', 0, 'A'),
(5707, 'SKP 6 EP.1', 1, 'Rumah sakit telah melaksanakan skrining pasien  rawat  jalan pada kondisi, diagnosis, situasi atau lokasi yang dapat menyebabkan pasien berisiko jatuh, dengan menggunakan alat bantu/metode skrining yang ditetapkan rumah sakit', '6', '', '', 10, 1479, 87, 0, 2025, 1, NULL, 'Bukti pelaksanaan skrining pasien rawat jalan pada kondisi, diagnosis, situasi atau lokasi yang dapat menyebabkan pasien berisiko jatuh, dengan menggunakan alat bantu/metode skrining yang ditetapkan rumah sakit', NULL, '-	PPJA\r\n-	Staf klinis', NULL, '2025-07-02 15:40:16', 0, 'A'),
(5708, 'SKP 6 EP.2', 2, 'Tindakan dan/atau intervensi dilakukan untuk mengurangi risiko jatuh pada pasien jika hasil skrining menunjukkan adanya risiko jatuh dan hasil skrining serta intervensi didokumentasikan.', '6', '', '', 10, 1479, 87, 0, 2025, 1, NULL, 'Bukti pelaksanaan tindakan dan/atau intervensi untuk mengurangi  risiko jatuh', NULL, '-	PPJA\r\n-	Staf klinis\r\n-	Pasien/keluarga', NULL, '2025-07-02 15:40:47', 0, 'A'),
(5709, 'SKP 6.1 EP.1', 1, 'Rumah sakit telah melakukan pengkajian  risiko  jatuh  untuk semua pasien rawat inap baik dewasa maupun anak menggunakan metode pengkajian yang baku sesuai dengan ketentuan rumah sakit.', '6.1', '', '', 10, 1480, 87, 0, 2025, 1, NULL, 'Bukti pelaksanaan pengkajian awal risiko jatuh untuk semua pasien rawat inap baik dewasa maupun anak menggunakan metode pengkajian yang baku sesuai dengan ketentuan rumah sakit.', NULL, '-	PPJA\r\n-	Staf klinis\r\n-	Pasien/keluarga', NULL, '2025-07-02 15:41:06', 0, 'A'),
(5710, 'SKP 6.1 EP.2', 2, 'Rumah sakit telah melaksanakan pengkajian ulang risiko jatuh pada pasien rawat inap karena adanya perubahan kondisi, atau memang sudah mempunyai risiko jatuh dari hasil pengkajian.', '6.1', '', '', 10, 1480, 87, 0, 2025, 1, NULL, 'Bukti pengkajian ulang risiko jatuh pada pasien rawat inap karena adanya perubahan kondisi, atau memang sudah mempunyai risiko jatuh dari hasil pengkajian.', NULL, '-	PPJA\r\n-	Staf klinis\r\n-	Pasien/keluarga', NULL, '2025-07-02 15:42:07', 0, 'A'),
